const WebsocketAuthMode = enum {
    capability_token,
    signed_bearer_token,
};

const WebsocketAuthArgs = struct {
    ws_auth: ?WebsocketAuthMode = null,
    ws_token_file: ?[]const u8 = null,
    ws_token_sha256: ?[]const u8 = null,
    ws_shared_secret_file: ?[]const u8 = null,
    ws_issuer: ?[]const u8 = null,
    ws_audience: ?[]const u8 = null,
    ws_max_clock_skew_seconds: ?u64 = null,
};

const AppServerOptions = struct {
    listen_url: []const u8 = DEFAULT_LISTEN_URL,
    websocket_auth: WebsocketAuthArgs = .{},
};

const AppServerState = struct {
    runtime_feature_enablement: features_cmd.FeatureOverrides = .{},
    loaded_threads: std.ArrayList(LoadedThread) = .empty,
    fs_watches: std.ArrayList(FsWatchEntry) = .empty,
    fuzzy_search_sessions: std.ArrayList(FuzzySearchSessionEntry) = .empty,
    skill_watch_roots: std.ArrayList([]const u8) = .empty,
    skills_list_cache: std.ArrayList(SkillsListCacheEntry) = .empty,
    subscribed_thread_ids: std.ArrayList([]const u8) = .empty,
    opt_out_notification_methods: std.ArrayList([]const u8) = .empty,
    pre_response_notifications: std.ArrayList([]const u8) = .empty,
    pending_notifications: std.ArrayList([]const u8) = .empty,

    fn deinit(self: *AppServerState, allocator: std.mem.Allocator) void {
        self.runtime_feature_enablement.deinit(allocator);
        for (self.loaded_threads.items) |*thread| thread.deinit(allocator);
        self.loaded_threads.deinit(allocator);
        for (self.fs_watches.items) |*watch| watch.deinit(allocator);
        self.fs_watches.deinit(allocator);
        for (self.fuzzy_search_sessions.items) |*session| session.deinit(allocator);
        self.fuzzy_search_sessions.deinit(allocator);
        for (self.skill_watch_roots.items) |root| allocator.free(root);
        self.skill_watch_roots.deinit(allocator);
        clearSkillsListCache(allocator, self);
        self.skills_list_cache.deinit(allocator);
        for (self.subscribed_thread_ids.items) |thread_id| allocator.free(thread_id);
        self.subscribed_thread_ids.deinit(allocator);
        clearOptOutNotificationMethods(allocator, self);
        self.opt_out_notification_methods.deinit(allocator);
        for (self.pre_response_notifications.items) |payload| allocator.free(payload);
        self.pre_response_notifications.deinit(allocator);
        for (self.pending_notifications.items) |payload| allocator.free(payload);
        self.pending_notifications.deinit(allocator);
    }
};

const LoadedThread = struct {
    id: []const u8,
    session_id: []const u8,
    forked_from_id: ?[]const u8,
    preview: []const u8,
    model: []const u8,
    model_provider: []const u8,
    service_tier: ?[]const u8,
    cwd: []const u8,
    approval_policy: []const u8,
    approvals_reviewer: []const u8,
    sandbox_mode: []const u8,
    reasoning_effort: ?[]const u8,
    runtime_overrides: LoadedThreadRuntimeOverrides,
    ephemeral: bool,
    path: ?[]const u8,
    source: []const u8,
    thread_source: ?[]const u8,
    agent_nickname: ?[]const u8,
    agent_role: ?[]const u8,
    cli_version: []const u8,
    token_usage: ?session_mod.TokenUsageInfo,
    token_usage_turn_id: ?[]const u8,
    name: ?[]const u8,
    elicitation_count: u64,
    git_sha: ?[]const u8,
    git_branch: ?[]const u8,
    git_origin_url: ?[]const u8,
    goal: ?LoadedThreadGoal,
    transcript: session_mod.Transcript,
    turns_json: []const u8,
    created_at: i64,
    updated_at: i64,
    status: ThreadRuntimeStatus = .idle,

    fn deinit(self: *LoadedThread, allocator: std.mem.Allocator) void {
        allocator.free(self.id);
        allocator.free(self.session_id);
        if (self.forked_from_id) |value| allocator.free(value);
        allocator.free(self.preview);
        allocator.free(self.model);
        allocator.free(self.model_provider);
        if (self.service_tier) |value| allocator.free(value);
        allocator.free(self.cwd);
        allocator.free(self.approval_policy);
        allocator.free(self.approvals_reviewer);
        allocator.free(self.sandbox_mode);
        if (self.reasoning_effort) |value| allocator.free(value);
        if (self.path) |value| allocator.free(value);
        allocator.free(self.source);
        if (self.thread_source) |value| allocator.free(value);
        if (self.agent_nickname) |value| allocator.free(value);
        if (self.agent_role) |value| allocator.free(value);
        allocator.free(self.cli_version);
        if (self.token_usage_turn_id) |value| allocator.free(value);
        if (self.name) |value| allocator.free(value);
        if (self.git_sha) |value| allocator.free(value);
        if (self.git_branch) |value| allocator.free(value);
        if (self.git_origin_url) |value| allocator.free(value);
        if (self.goal) |*goal| goal.deinit(allocator);
        self.transcript.deinit(allocator);
        allocator.free(self.turns_json);
    }
};

