const SchemaFile = struct {
    name: []const u8,
    contents: []const u8,
};

const GENERATED_TS_HEADER = "// GENERATED CODE! DO NOT MODIFY BY HAND!\n\n";

const REQUEST_ID_TS =
    GENERATED_TS_HEADER ++
    \\export type RequestId = string | number;
    \\
    ;

const JSONRPC_REQUEST_TS =
    GENERATED_TS_HEADER ++
    \\import type { RequestId } from "./RequestId";
    \\
    \\export interface JSONRPCRequest {
    \\  id: RequestId;
    \\  method: string;
    \\  params?: unknown;
    \\  trace?: Record<string, unknown>;
    \\}
    \\
    ;

const JSONRPC_NOTIFICATION_TS =
    GENERATED_TS_HEADER ++
    \\export interface JSONRPCNotification {
    \\  method: string;
    \\  params?: unknown;
    \\}
    \\
    ;

const CLIENT_NOTIFICATION_TS =
    GENERATED_TS_HEADER ++
    \\export type ClientNotification = { method: "initialized" };
    \\
    ;

const JSONRPC_RESPONSE_TS =
    GENERATED_TS_HEADER ++
    \\import type { RequestId } from "./RequestId";
    \\
    \\export interface JSONRPCResponse {
    \\  id: RequestId;
    \\  result: unknown;
    \\}
    \\
    ;

const JSONRPC_ERROR_ERROR_TS =
    GENERATED_TS_HEADER ++
    \\export interface JSONRPCErrorError {
    \\  code: number;
    \\  message: string;
    \\  data?: unknown;
    \\}
    \\
    ;

const JSONRPC_ERROR_TS =
    GENERATED_TS_HEADER ++
    \\import type { JSONRPCErrorError } from "./JSONRPCErrorError";
    \\import type { RequestId } from "./RequestId";
    \\
    \\export interface JSONRPCError {
