fn writeAppServerTs(allocator: std.mem.Allocator, out_dir: []const u8, prettier: ?[]const u8, experimental: bool) !void {
    _ = prettier;
    _ = experimental;
    const io = std.Io.Threaded.global_single_threaded.io();
    const v2_out_dir = try std.fs.path.join(allocator, &.{ out_dir, "v2" });
    defer allocator.free(v2_out_dir);
    try std.Io.Dir.cwd().createDirPath(io, v2_out_dir);
    try writeSchemaFiles(allocator, out_dir, &APP_SERVER_TS_FILES);
}

fn writeAppServerJsonSchemas(allocator: std.mem.Allocator, out_dir: []const u8, experimental: bool) !void {
    _ = experimental;
    try writeSchemaFiles(allocator, out_dir, &APP_SERVER_JSON_SCHEMA_FILES);
}

fn writeRolloutLineJsonSchema(allocator: std.mem.Allocator, out_dir: []const u8) !void {
    const files = [_]SchemaFile{.{ .name = "RolloutLine.json", .contents = ROLLOUT_LINE_JSON_SCHEMA }};
    try writeSchemaFiles(allocator, out_dir, &files);
}

fn writeSchemaFiles(allocator: std.mem.Allocator, out_dir: []const u8, files: []const SchemaFile) !void {
    const io = std.Io.Threaded.global_single_threaded.io();
    try std.Io.Dir.cwd().createDirPath(io, out_dir);
    for (files) |file| {
        const schema_path = try std.fs.path.join(allocator, &.{ out_dir, file.name });
        defer allocator.free(schema_path);
        try std.Io.Dir.cwd().writeFile(io, .{ .sub_path = schema_path, .data = file.contents });
    }
}

fn runProxy(allocator: std.mem.Allocator, args: []const []const u8) !void {
    var socket_path_arg: ?[]const u8 = null;
    var index: usize = 0;
    while (index < args.len) : (index += 1) {
        const arg = args[index];
        if (isHelpFlag(arg)) {
            printProxyHelp();
            return;
        }
        if (std.mem.eql(u8, arg, "--sock")) {
            if (index + 1 >= args.len) return error.MissingAppServerProxySocketPath;
            index += 1;
            socket_path_arg = args[index];
            continue;
        }
        if (std.mem.startsWith(u8, arg, "--sock=")) {
            socket_path_arg = arg["--sock=".len..];
            continue;
        }
        if (std.mem.startsWith(u8, arg, "-")) return error.UnknownAppServerProxyOption;
        return error.UnexpectedAppServerProxyArgument;
    }

    const owned_default_path = if (socket_path_arg == null) try defaultUnixSocketPath(allocator) else null;
    defer if (owned_default_path) |path| allocator.free(path);
    const socket_path = socket_path_arg orelse owned_default_path.?;
    try runStdioToUnixSocket(allocator, socket_path);
}

pub fn runStdioToUnixSocket(allocator: std.mem.Allocator, socket_path: []const u8) !void {
    _ = allocator;
    const io = std.Io.Threaded.global_single_threaded.io();
    var address = try net.UnixAddress.init(socket_path);
    var stream = try address.connect(io);
    defer stream.close(io);

    var socket_out_buffer: [64 * 1024]u8 = undefined;
    var socket_writer = stream.writer(io, &socket_out_buffer);

    var stdin_open = true;
    var buffer: [64 * 1024]u8 = undefined;
    var fds = [_]std.posix.pollfd{
        .{ .fd = std.posix.STDIN_FILENO, .events = @intCast(std.posix.POLL.IN), .revents = 0 },
        .{ .fd = stream.socket.handle, .events = @intCast(std.posix.POLL.IN), .revents = 0 },
    };

    while (true) {
        fds[0].fd = if (stdin_open) std.posix.STDIN_FILENO else -1;
        fds[0].events = if (stdin_open) @intCast(std.posix.POLL.IN) else 0;
        fds[0].revents = 0;
        fds[1].events = @intCast(std.posix.POLL.IN);
        fds[1].revents = 0;

        _ = try std.posix.poll(&fds, -1);

        if (stdin_open and pollReventsInclude(fds[0].revents, relay_poll_read_events)) {
            const read_len = try std.posix.read(std.posix.STDIN_FILENO, &buffer);
            if (read_len == 0) {
                stdin_open = false;
                stream.shutdown(io, .send) catch {};
            } else {
                try socket_writer.interface.writeAll(buffer[0..read_len]);
                try socket_writer.interface.flush();
            }
        }

        if (pollReventsInclude(fds[1].revents, relay_poll_read_events)) {
            const read_len = try std.posix.read(stream.socket.handle, &buffer);
            if (read_len == 0) break;
            try cli_utils.writeStdout(buffer[0..read_len]);
        }
    }
}

const relay_poll_read_events = std.posix.POLL.IN | std.posix.POLL.HUP | std.posix.POLL.ERR | std.posix.POLL.NVAL;

fn pollReventsInclude(revents: i16, mask: comptime_int) bool {
    return (@as(u16, @bitCast(revents)) & @as(u16, @intCast(mask))) != 0;
}

fn parseTransport(value: []const u8) !Transport {
    if (std.mem.eql(u8, value, "stdio://")) return .stdio;
    if (std.mem.eql(u8, value, "off")) return .off;
    if (std.mem.eql(u8, value, "unix://")) return .unix_default;
    if (std.mem.startsWith(u8, value, "unix://")) {
        const path = value["unix://".len..];
        if (path.len == 0) return error.UnsupportedAppServerListenUrl;
        return .{ .unix_path = path };
    }
    if (std.mem.startsWith(u8, value, "ws://")) {
        const address = value["ws://".len..];
        const colon = std.mem.lastIndexOfScalar(u8, address, ':') orelse return error.UnsupportedAppServerListenUrl;
        const host = address[0..colon];
        const port_text = address[colon + 1 ..];
        if (host.len == 0 or port_text.len == 0) return error.UnsupportedAppServerListenUrl;
        const port = std.fmt.parseUnsigned(u16, port_text, 10) catch return error.UnsupportedAppServerListenUrl;
        return .{ .websocket = .{ .host = host, .port = port } };
    }
    return error.UnsupportedAppServerListenUrl;
}

fn formatTransportLabel(allocator: std.mem.Allocator, transport: Transport) ![]const u8 {
    return switch (transport) {
        .stdio => allocator.dupe(u8, "stdio://"),
        .off => allocator.dupe(u8, "off"),
        .unix_default => allocator.dupe(u8, "unix://"),
        .unix_path => |path| std.fmt.allocPrint(allocator, "unix://{s}", .{path}),
        .websocket => |address| std.fmt.allocPrint(allocator, "ws://{s}:{d}", .{ address.host, address.port }),
    };
}

const StdioServer = struct {
    allocator: std.mem.Allocator,

    fn run(self: *StdioServer) !void {
        var state = AppServerState{};
        defer state.deinit(self.allocator);

        var input_buffer: [64 * 1024]u8 = undefined;
        var stdin_reader = std.Io.File.stdin().reader(std.Io.Threaded.global_single_threaded.io(), &input_buffer);

        while (true) {
            const line_opt = try stdin_reader.interface.takeDelimiter('\n');
            const line = line_opt orelse break;
            const trimmed = std.mem.trim(u8, line, " \t\r\n");
            if (trimmed.len == 0) continue;
            const response = handleJsonRpcLine(self.allocator, &state, trimmed) catch |err| {
                const message = try std.fmt.allocPrint(self.allocator, "[app-server] failed to handle message: {s}\n", .{@errorName(err)});
                defer self.allocator.free(message);
                try cli_utils.writeStderr(message);
                continue;
            };
            try writePreResponseNotificationsStdout(self.allocator, &state);
            if (response) |payload| {
                defer self.allocator.free(payload);
                try writeStdoutLine(payload);
            }
            try queueExternalFsWatchNotifications(self.allocator, &state);
            try writePendingNotificationsStdout(self.allocator, &state);
        }
    }
};

const UnixServer = struct {
    allocator: std.mem.Allocator,
    socket_path: []const u8,

    fn run(self: *UnixServer) !void {
        const io = std.Io.Threaded.global_single_threaded.io();
        try ensureParentDir(io, self.socket_path);
        try deleteSocketFileIfSocket(self.allocator, io, self.socket_path);

        var address = try net.UnixAddress.init(self.socket_path);
        var server = address.listen(io, .{}) catch |err| switch (err) {
            error.AddressInUse, error.NotDir => return error.AppServerUnixSocketPathExists,
            else => return err,
        };
        defer server.deinit(io);
        defer deleteSocketFileIfSocket(self.allocator, io, self.socket_path) catch {};

        var state = AppServerState{};
        defer state.deinit(self.allocator);

        var stream = try server.accept(io);
        defer stream.close(io);

        var input_buffer: [64 * 1024]u8 = undefined;
        var output_buffer: [64 * 1024]u8 = undefined;
        var reader = stream.reader(io, &input_buffer);
        var writer = stream.writer(io, &output_buffer);

        while (true) {
            const line_opt = try reader.interface.takeDelimiter('\n');
            const line = line_opt orelse break;
            const trimmed = std.mem.trim(u8, line, " \t\r\n");
            if (trimmed.len == 0) continue;
            const response = handleJsonRpcLine(self.allocator, &state, trimmed) catch |err| {
                const message = try std.fmt.allocPrint(self.allocator, "[app-server] failed to handle message: {s}\n", .{@errorName(err)});
                defer self.allocator.free(message);
                try cli_utils.writeStderr(message);
                continue;
            };
            try writePreResponseNotificationsStream(self.allocator, &state, &writer.interface);
            if (response) |payload| {
                defer self.allocator.free(payload);
                try writeStreamLine(&writer.interface, payload);
            }
            try queueExternalFsWatchNotifications(self.allocator, &state);
            try writePendingNotificationsStream(self.allocator, &state, &writer.interface);
        }
    }
};

fn handleJsonRpcLine(allocator: std.mem.Allocator, state: *AppServerState, line: []const u8) !?[]const u8 {
    var parsed = std.json.parseFromSlice(std.json.Value, allocator, line, .{}) catch {
        return try renderJsonRpcError(allocator, null, -32700, "Parse error");
    };
    defer parsed.deinit();

    if (parsed.value != .object) {
        return try renderJsonRpcError(allocator, null, -32600, "Invalid Request");
    }

    const object = parsed.value.object;
    const id_value = object.get("id");
    const method_value = object.get("method") orelse {
        return try renderJsonRpcError(allocator, id_value, -32600, "Invalid Request");
    };
    if (method_value != .string) {
        return try renderJsonRpcError(allocator, id_value, -32600, "Invalid Request");
    }
    if (id_value == null) return null;

    const method = method_value.string;
    if (std.mem.eql(u8, method, "initialize")) {
        try updateOptOutNotificationMethods(allocator, state, object.get("params"));
        const result = try renderInitializeResult(allocator);
        defer allocator.free(result);
        return try renderJsonRpcResult(allocator, id_value.?, result);
    }
    if (std.mem.eql(u8, method, "memory/reset")) {
        return try handleMemoryReset(allocator, id_value.?);
    }
    if (std.mem.eql(u8, method, "getConversationSummary")) {
        return try handleGetConversationSummary(allocator, state, id_value.?, object.get("params"));
    }
    if (std.mem.eql(u8, method, "gitDiffToRemote")) {
        return try handleGitDiffToRemote(allocator, id_value.?, object.get("params"));
    }
    if (std.mem.eql(u8, method, "fuzzyFileSearch")) {
        return try handleFuzzyFileSearch(allocator, id_value.?, object.get("params"));
    }
    if (std.mem.eql(u8, method, "app/list")) {
        return try handleAppsList(allocator, state, id_value.?, object.get("params"));
    }
    if (isTurnMethod(method)) {
        return try handleTurnMethod(allocator, state, id_value.?, method, object.get("params"));
    }
    if (isThreadMethod(method)) {
        return try handleThreadMethod(allocator, state, id_value.?, method, object.get("params"));
    }
    if (isFuzzyFileSearchSessionMethod(method)) {
        return try handleFuzzyFileSearchSessionMethod(allocator, state, id_value.?, method, object.get("params"));
    }
    if (isMarketplaceMethod(method)) {
        return try handleMarketplaceMethod(allocator, id_value.?, method, object.get("params"));
    }
    if (isPluginMethod(method)) {
        return try handlePluginMethod(allocator, state, id_value.?, method, object.get("params"));
    }
    if (std.mem.eql(u8, method, "hooks/list")) {
        return try handleHooksList(allocator, id_value.?, object.get("params"));
    }
    if (std.mem.eql(u8, method, "skills/list")) {
        return try handleSkillsList(allocator, state, id_value.?, object.get("params"));
    }
    if (std.mem.eql(u8, method, "skills/config/write")) {
        return try handleSkillsConfigWrite(allocator, state, id_value.?, object.get("params"));
    }
    if (isFsMethod(method)) {
        return try handleFsMethod(allocator, state, id_value.?, method, object.get("params"));
    }
    if (isCommandExecMethod(method)) {
        return try handleCommandExecMethod(allocator, state, id_value.?, method, object.get("params"));
    }
    if (isFeedbackMethod(method)) {
        return try handleFeedbackMethod(allocator, state, id_value.?, method, object.get("params"));
    }
    if (isConfigMethod(method)) {
        return try handleConfigMethod(allocator, state, id_value.?, method, object.get("params"));
    }
    if (isAccountMethod(method)) {
        return try handleAccountMethod(allocator, id_value.?, method, object.get("params"));
    }
    if (isModelMethod(method)) {
        return try handleModelMethod(allocator, id_value.?, method, object.get("params"));
    }
    if (isCollaborationModeMethod(method)) {
        return try handleCollaborationModeMethod(allocator, id_value.?, method, object.get("params"));
    }
    if (isExperimentalFeatureMethod(method)) {
        return try handleExperimentalFeatureMethod(allocator, state, id_value.?, method, object.get("params"));
    }
    if (isMcpServerMethod(method)) {
        return try handleMcpServerMethod(allocator, state, id_value.?, method, object.get("params"));
    }
    if (isWindowsSandboxMethod(method)) {
        return try handleWindowsSandboxMethod(allocator, state, id_value.?, method, object.get("params"));
    }

    const message = try std.fmt.allocPrint(allocator, "unsupported app-server method: {s}", .{method});
    defer allocator.free(message);
    return try renderJsonRpcError(allocator, id_value, -32601, message);
}

fn handleMemoryReset(allocator: std.mem.Allocator, id_value: std.json.Value) ![]const u8 {
    const codex_home = resolveCodexHome(allocator) catch |err| {
        return try renderJsonRpcErrorForFailure(allocator, id_value, "failed to resolve CODEX_HOME", err);
    };
    defer allocator.free(codex_home);

    const state_path = memory_reset.resolveStateDbPath(allocator, codex_home) catch |err| {
        return try renderJsonRpcErrorForFailure(allocator, id_value, "failed to resolve state db path", err);
    };
    defer allocator.free(state_path);

    const state_exists = memory_reset.stateDbExists(allocator, state_path) catch |err| {
        return try renderJsonRpcErrorForFailure(allocator, id_value, "failed to inspect state db", err);
    };
    if (state_exists) {
        memory_reset.clearMemoryStateDb(allocator, state_path) catch |err| {
            return try renderJsonRpcErrorForFailure(allocator, id_value, "failed to clear memory state db", err);
        };
    }

    memory_reset.clearMemoryRootsContents(allocator, codex_home) catch |err| {
        return try renderJsonRpcErrorForFailure(allocator, id_value, "failed to clear memory directories", err);
    };
    return try renderJsonRpcResult(allocator, id_value, "{}");
}

fn handleAppsList(
    allocator: std.mem.Allocator,
    state: *AppServerState,
    id_value: std.json.Value,
    params_value: ?std.json.Value,
) ![]const u8 {
    const params = switch (optionalAppsListParams(params_value)) {
        .object => |object| object,
        .empty => null,
        .message => |message| return renderJsonRpcError(allocator, id_value, -32602, message),
    };

    var scoped_thread: ?*const LoadedThread = null;
    if (params) |object| {
        if (object.get("threadId")) |value| {
            if (value != .null) {
                if (value != .string or value.string.len == 0) return renderJsonRpcError(allocator, id_value, -32602, "threadId must be a string or null");
                scoped_thread = findLoadedThread(state, value.string) orelse return renderThreadNotFound(allocator, id_value, value.string);
            }
        }
    }

    if (!(try appServerFeatureEnabled(allocator, state, "apps"))) {
        return renderJsonRpcResult(allocator, id_value, "{\"data\":[],\"nextCursor\":null}");
    }

    var cursor: ?[]const u8 = null;
    var limit: ?usize = null;
    if (params) |object| {
        if (object.get("cursor")) |value| {
            if (value != .null) {
                if (value != .string) return renderJsonRpcError(allocator, id_value, -32602, "cursor must be a string or null");
                cursor = value.string;
            }
        }
        if (object.get("limit")) |value| {
            limit = switch (value) {
                .null => null,
                .integer => |integer| blk: {
                    if (integer < 0) return renderJsonRpcError(allocator, id_value, -32602, "limit must be a non-negative integer or null");
                    break :blk @intCast(integer);
                },
                .number_string => |number| std.fmt.parseUnsigned(usize, number, 10) catch {
                    return renderJsonRpcError(allocator, id_value, -32602, "limit must be a non-negative integer or null");
                },
                else => return renderJsonRpcError(allocator, id_value, -32602, "limit must be a non-negative integer or null"),
            };
        }
    }

    const start = if (cursor) |value|
        std.fmt.parseUnsigned(usize, value, 10) catch {
            const message = try std.fmt.allocPrint(allocator, "invalid cursor: {s}", .{value});
            defer allocator.free(message);
            return renderJsonRpcError(allocator, id_value, -32600, message);
        }
    else
        0;

    const codex_home = resolveCodexHome(allocator) catch |err| {
        return renderJsonRpcErrorForFailure(allocator, id_value, "app/list failed", err);
    };
    defer allocator.free(codex_home);

    const config_path = config.configTomlPath(allocator, codex_home) catch |err| {
        return renderJsonRpcErrorForFailure(allocator, id_value, "app/list failed", err);
    };
    defer allocator.free(config_path);
    const config_bytes = config.readConfigTomlFile(allocator, config_path) catch |err| {
        return renderJsonRpcErrorForFailure(allocator, id_value, "app/list failed", err);
    };
    defer if (config_bytes) |bytes| allocator.free(bytes);

    var scoped_cwds_storage: [1][]const u8 = undefined;
    var scoped_cwds: []const []const u8 = &.{};
    if (scoped_thread) |thread| {
        scoped_cwds_storage[0] = thread.cwd;
        scoped_cwds = scoped_cwds_storage[0..];
    }

    var total: usize = 0;
    const result = plugin_list.renderAppsListResponse(allocator, codex_home, config_bytes orelse "", scoped_cwds, start, limit, &total) catch |err| {
        return renderJsonRpcErrorForFailure(allocator, id_value, "app/list failed", err);
    };
    const result_json = result orelse {
        const message = try std.fmt.allocPrint(allocator, "cursor {d} exceeds total apps {d}", .{ start, total });
        defer allocator.free(message);
        return renderJsonRpcError(allocator, id_value, -32600, message);
    };
    defer allocator.free(result_json);

    return renderJsonRpcResult(allocator, id_value, result_json);
}

fn handleGetConversationSummary(
    allocator: std.mem.Allocator,
    state: *AppServerState,
    id_value: std.json.Value,
    params_value: ?std.json.Value,
) ![]const u8 {
    const params = params_value orelse return renderJsonRpcError(allocator, id_value, -32602, "getConversationSummary params must be an object");
    if (params != .object) return renderJsonRpcError(allocator, id_value, -32602, "getConversationSummary params must be an object");

    if (params.object.get("rolloutPath")) |rollout_path_value| {
        if (rollout_path_value != .string or rollout_path_value.string.len == 0) {
            return renderJsonRpcError(allocator, id_value, -32602, "rolloutPath must be a string");
        }

        var cfg = config.load(allocator) catch |err| {
            return renderJsonRpcErrorForFailure(allocator, id_value, "getConversationSummary failed to load config", err);
        };
        defer cfg.deinit(allocator);

        const path_raw = if (std.fs.path.isAbsolute(rollout_path_value.string))
            try allocator.dupe(u8, rollout_path_value.string)
        else
            try std.fs.path.join(allocator, &.{ cfg.codex_home, rollout_path_value.string });
        defer allocator.free(path_raw);

        return renderConversationSummaryResponseFromPath(allocator, id_value, cfg, path_raw, "rollout path", rollout_path_value.string);
    }

    if (params.object.get("conversationId")) |conversation_id_value| {
        if (conversation_id_value != .string or conversation_id_value.string.len == 0) {
            return renderJsonRpcError(allocator, id_value, -32602, "conversationId must be a string");
        }
        const conversation_id = conversation_id_value.string;
        if (findLoadedThread(state, conversation_id)) |thread| {
            const result = try renderConversationSummaryResponseFromLoadedThread(allocator, thread);
            defer allocator.free(result);
            return renderJsonRpcResult(allocator, id_value, result);
        }

        var cfg = config.load(allocator) catch |err| {
            return renderJsonRpcErrorForFailure(allocator, id_value, "getConversationSummary failed to load config", err);
        };
        defer cfg.deinit(allocator);

        const path_raw = session_store.resolveResumePath(allocator, cfg.codex_home, conversation_id) catch |err| {
            return renderJsonRpcErrorForFailure(allocator, id_value, "getConversationSummary failed to resolve thread path", err);
        };
        defer allocator.free(path_raw);

        return renderConversationSummaryResponseFromPath(allocator, id_value, cfg, path_raw, "thread id", conversation_id);
    }

    return renderJsonRpcError(allocator, id_value, -32602, "getConversationSummary params must include conversationId or rolloutPath");
}

fn renderConversationSummaryResponseFromPath(
    allocator: std.mem.Allocator,
    id_value: std.json.Value,
    cfg: config.Config,
    path_raw: []const u8,
    target_kind: []const u8,
    target_value: []const u8,
) ![]const u8 {
    var transcript = session_store.loadTranscript(allocator, path_raw) catch |err| switch (err) {
        error.FileNotFound => {
            const message = try std.fmt.allocPrint(allocator, "no rollout found for {s} {s}", .{ target_kind, target_value });
            defer allocator.free(message);
            return renderJsonRpcError(allocator, id_value, -32600, message);
        },
        else => return renderJsonRpcErrorForFailure(allocator, id_value, "getConversationSummary failed to load transcript", err),
    };
    defer transcript.deinit(allocator);

    const real_path = std.Io.Dir.cwd().realPathFileAlloc(std.Io.Threaded.global_single_threaded.io(), path_raw, allocator) catch |err| switch (err) {
        error.FileNotFound => {
            const message = try std.fmt.allocPrint(allocator, "no rollout found for {s} {s}", .{ target_kind, target_value });
            defer allocator.free(message);
            return renderJsonRpcError(allocator, id_value, -32600, message);
        },
        else => return err,
    };
    defer allocator.free(real_path);

    const configured_model_provider = try config.loadModelProviderId(allocator, cfg.active_profile);
    defer if (configured_model_provider) |value| allocator.free(value);
    const fallback_model_provider = configured_model_provider orelse "openai";

    const result = try renderConversationSummaryResponseFromTranscript(allocator, real_path, &transcript, fallback_model_provider);
    defer allocator.free(result);
    return renderJsonRpcResult(allocator, id_value, result);
}

fn handleGitDiffToRemote(allocator: std.mem.Allocator, id_value: std.json.Value, params_value: ?std.json.Value) ![]const u8 {
    const params = params_value orelse return renderJsonRpcError(allocator, id_value, -32602, "gitDiffToRemote params must be an object");
    if (params != .object) return renderJsonRpcError(allocator, id_value, -32602, "gitDiffToRemote params must be an object");

    const cwd_value = params.object.get("cwd") orelse return renderJsonRpcError(allocator, id_value, -32602, "cwd must be a string");
    if (cwd_value != .string or cwd_value.string.len == 0) {
        return renderJsonRpcError(allocator, id_value, -32602, "cwd must be a string");
    }

    var diff = git_remote_diff.compute(allocator, cwd_value.string) catch |err| switch (err) {
        error.OutOfMemory => return err,
        else => {
            const message = try std.fmt.allocPrint(allocator, "failed to compute git diff to remote for cwd: {s}", .{cwd_value.string});
            defer allocator.free(message);
            return renderJsonRpcError(allocator, id_value, -32602, message);
        },
    };
    defer diff.deinit(allocator);

    const sha_json = try std.json.Stringify.valueAlloc(allocator, diff.sha, .{});
    defer allocator.free(sha_json);
    const diff_json = try std.json.Stringify.valueAlloc(allocator, diff.diff, .{});
    defer allocator.free(diff_json);
    const result = try std.fmt.allocPrint(allocator, "{{\"sha\":{s},\"diff\":{s}}}", .{ sha_json, diff_json });
    defer allocator.free(result);
    return renderJsonRpcResult(allocator, id_value, result);
}

fn handleFuzzyFileSearch(allocator: std.mem.Allocator, id_value: std.json.Value, params_value: ?std.json.Value) ![]const u8 {
    const params = params_value orelse return renderJsonRpcError(allocator, id_value, -32602, "fuzzyFileSearch params must be an object");
    if (params != .object) return renderJsonRpcError(allocator, id_value, -32602, "fuzzyFileSearch params must be an object");

    const query_value = params.object.get("query") orelse return renderJsonRpcError(allocator, id_value, -32602, "query must be a string");
    if (query_value != .string) return renderJsonRpcError(allocator, id_value, -32602, "query must be a string");

    const roots = parseFuzzyFileSearchRoots(allocator, params.object.get("roots")) catch |err| switch (err) {
        error.InvalidFuzzyFileSearchRoots => return renderJsonRpcError(allocator, id_value, -32602, "roots must be an array of strings"),
        else => return err,
    };
    defer allocator.free(roots);

    if (params.object.get("cancellationToken")) |value| {
        if (value != .null and value != .string) {
            return renderJsonRpcError(allocator, id_value, -32602, "cancellationToken must be a string or null");
        }
    }

    var results = try fuzzy_file_search.search(allocator, query_value.string, roots);
    defer results.deinit(allocator);

    const result = try renderFuzzyFileSearchResult(allocator, results);
    defer allocator.free(result);
    return renderJsonRpcResult(allocator, id_value, result);
}

fn parseFuzzyFileSearchRoots(allocator: std.mem.Allocator, roots_value: ?std.json.Value) ![]const []const u8 {
    const value = roots_value orelse return error.InvalidFuzzyFileSearchRoots;
    if (value != .array) return error.InvalidFuzzyFileSearchRoots;
    const roots = try allocator.alloc([]const u8, value.array.items.len);
    errdefer allocator.free(roots);
    for (value.array.items, 0..) |item, index| {
        if (item != .string) return error.InvalidFuzzyFileSearchRoots;
        roots[index] = item.string;
    }
    return roots;
}

fn renderFuzzyFileSearchResult(allocator: std.mem.Allocator, results: fuzzy_file_search.Results) ![]const u8 {
    var out = std.ArrayList(u8).empty;
    errdefer out.deinit(allocator);

    try out.appendSlice(allocator, "{\"files\":[");
    for (results.files, 0..) |file, index| {
        if (index > 0) try out.appendSlice(allocator, ",");
        try appendFuzzyFileSearchMatch(allocator, &out, file);
    }
    try out.appendSlice(allocator, "]}");
    return out.toOwnedSlice(allocator);
}

const THREAD_REALTIME_LIST_VOICES_RESPONSE_JSON =
    "{\"voices\":{\"v1\":[\"juniper\",\"maple\",\"spruce\",\"ember\",\"vale\",\"breeze\",\"arbor\",\"sol\",\"cove\"],\"v2\":[\"alloy\",\"ash\",\"ballad\",\"coral\",\"echo\",\"sage\",\"shimmer\",\"verse\",\"marin\",\"cedar\"],\"defaultV1\":\"cove\",\"defaultV2\":\"marin\"}}";

const TurnStartInput = struct {
    prompt: []const u8,
    user_content_json: []const u8,
    image_urls: []const []const u8,
    local_image_paths: []const []const u8,
    skills: []const TurnNamedPathInput,

    fn deinit(self: *TurnStartInput, allocator: std.mem.Allocator) void {
        allocator.free(self.prompt);
        allocator.free(self.user_content_json);
        for (self.image_urls) |image_url| allocator.free(image_url);
        allocator.free(self.image_urls);
        for (self.local_image_paths) |path| allocator.free(path);
        allocator.free(self.local_image_paths);
        for (self.skills) |item| item.deinit(allocator);
        allocator.free(self.skills);
    }
};

const TurnNamedPathInput = struct {
    name: []const u8,
    path: []const u8,

    fn init(allocator: std.mem.Allocator, name: []const u8, path: []const u8) !TurnNamedPathInput {
        const owned_name = try allocator.dupe(u8, name);
        errdefer allocator.free(owned_name);
        const owned_path = try allocator.dupe(u8, path);
        errdefer allocator.free(owned_path);
        return .{ .name = owned_name, .path = owned_path };
    }

    fn deinit(self: TurnNamedPathInput, allocator: std.mem.Allocator) void {
        allocator.free(self.name);
        allocator.free(self.path);
    }
};

const TurnLocalImages = struct {
    data_urls: []const []const u8 = &.{},
    missing_placeholders: []const []const u8 = &.{},

    fn deinit(self: *TurnLocalImages, allocator: std.mem.Allocator) void {
        for (self.data_urls) |data_url| allocator.free(data_url);
        if (self.data_urls.len > 0) allocator.free(self.data_urls);
        for (self.missing_placeholders) |placeholder| allocator.free(placeholder);
        if (self.missing_placeholders.len > 0) allocator.free(self.missing_placeholders);
    }
};

fn isTurnMethod(method: []const u8) bool {
    return std.mem.eql(u8, method, "turn/start") or
        std.mem.eql(u8, method, "turn/steer") or
        std.mem.eql(u8, method, "turn/interrupt");
}

fn handleTurnMethod(
    allocator: std.mem.Allocator,
    state: *AppServerState,
    id_value: std.json.Value,
    method: []const u8,
    params_value: ?std.json.Value,
) ![]const u8 {
    if (std.mem.eql(u8, method, "turn/start")) {
        return handleTurnStart(allocator, state, id_value, params_value);
    }
    if (std.mem.eql(u8, method, "turn/steer")) {
        return handleTurnSteer(allocator, state, id_value, params_value);
    }
    if (std.mem.eql(u8, method, "turn/interrupt")) {
        return handleTurnInterrupt(allocator, state, id_value, params_value);
    }
    return renderParsedButNotImplemented(allocator, id_value, method);
}

fn handleTurnStart(
    allocator: std.mem.Allocator,
    state: *AppServerState,
    id_value: std.json.Value,
    params_value: ?std.json.Value,
) ![]const u8 {
    const params = params_value orelse return renderJsonRpcError(allocator, id_value, -32602, "turn/start params must be an object");
    if (params != .object) return renderJsonRpcError(allocator, id_value, -32602, "turn/start params must be an object");
    const object = params.object;

    const thread_id = requiredThreadIdParam(object) catch |err| switch (err) {
        error.MissingThreadId => return renderJsonRpcError(allocator, id_value, -32602, "threadId must be a string"),
    };
    if (!isUuidString(thread_id)) {
        return renderInvalidThreadId(allocator, id_value, thread_id);
    }
    const thread_index = findLoadedThreadIndex(state, thread_id) orelse {
        return renderThreadNotFound(allocator, id_value, thread_id);
    };

    var input = parseTurnStartInput(allocator, object) catch |err| switch (err) {
        error.InvalidTurnInput => return renderJsonRpcError(allocator, id_value, -32602, "input must be an array of supported user input items"),
        error.EmptyTurnInput => return renderJsonRpcError(allocator, id_value, -32600, "input must include text or image"),
        error.UnsupportedTurnInput => return renderJsonRpcError(allocator, id_value, -32600, "only text, image, localImage, skill, and mention turn/start input is implemented"),
        else => return err,
    };
    defer input.deinit(allocator);

    var cfg = config.load(allocator) catch |err| {
        return renderJsonRpcErrorForFailure(allocator, id_value, "turn/start failed to load config", err);
    };
    defer cfg.deinit(allocator);

    var credentials = auth_mod.loadForConfig(allocator, &cfg) catch |err| {
        return renderJsonRpcErrorForFailure(allocator, id_value, "turn/start failed to load auth", err);
    };
    defer credentials.deinit(allocator);

    const thread = &state.loaded_threads.items[thread_index];
    const turn_id = try nextTurnIdForTranscript(allocator, &thread.transcript);
    defer allocator.free(turn_id);

    applyTurnStartRuntimeOverrides(allocator, &cfg, thread, object) catch |err| switch (err) {
        error.InvalidTurnContextOverride => return renderJsonRpcError(allocator, id_value, -32602, "invalid turn context override"),
        else => return err,
    };

    var local_images = try loadTurnLocalImages(allocator, input.local_image_paths);
    defer local_images.deinit(allocator);
    const request_input_images = try combineTurnInputImages(allocator, input.image_urls, local_images.data_urls);
    defer if (request_input_images.len > 0) allocator.free(request_input_images);
    var skill_injections = try loadTurnSkillInjections(allocator, input.skills);
    defer skill_injections.deinit(allocator);
    const prompt_for_turn = try turnPromptWithContextBlocks(allocator, input.prompt, local_images.missing_placeholders, skill_injections.blocks);
    defer allocator.free(prompt_for_turn);

    const response = try renderTurnStartResponse(allocator, turn_id);
    defer allocator.free(response);
    const started_at_ms = currentUnixMilliseconds();
    const started_at = @divTrunc(started_at_ms, std.time.ms_per_s);
    const user_item_index = thread.transcript.history.items.len;
    const started_notification = try renderTurnNotification(allocator, "turn/started", thread.id, turn_id, "inProgress", started_at, null);
    var started_notification_moved = false;
    errdefer if (!started_notification_moved) allocator.free(started_notification);

    const answer = session_mod.runTurnWithOptions(allocator, cfg, &credentials, &thread.transcript, prompt_for_turn, .{
        .prompt_for_approval = false,
        .output_schema = optionalJsonParam(object, "outputSchema"),
        .input_images = request_input_images,
    }) catch |err| {
        const error_message = try std.fmt.allocPrint(allocator, "turn/start failed to run turn: {s}", .{@errorName(err)});
        defer allocator.free(error_message);
        thread.status = .system_error;
        try refreshLoadedThreadAfterTurn(allocator, thread, prompt_for_turn);
        if (thread.path) |path| {
            try session_store.saveTranscript(allocator, path, &thread.transcript);
        }
        try queueErrorNotification(allocator, state, thread.id, turn_id, error_message, false);
        try queueThreadStatusChangedNotification(allocator, state, thread.id, .system_error);
        return renderJsonRpcError(allocator, id_value, -32603, error_message);
    };
    defer allocator.free(answer);

    const completed_at_ms = currentUnixMilliseconds();
    const completed_at = @divTrunc(completed_at_ms, std.time.ms_per_s);
    const completed_notification = try renderTurnNotification(allocator, "turn/completed", thread.id, turn_id, "completed", started_at, completed_at);
    var completed_notification_moved = false;
    errdefer if (!completed_notification_moved) allocator.free(completed_notification);

    try refreshLoadedThreadAfterTurn(allocator, thread, prompt_for_turn);
    if (thread.path) |path| {
        try session_store.saveTranscript(allocator, path, &thread.transcript);
    }

    thread.status = .active;
    try queueThreadStatusChangedNotification(allocator, state, thread.id, .active);
    try queueTurnNotification(allocator, state, "turn/started", started_notification);
    started_notification_moved = true;
    if (user_item_index < thread.transcript.history.items.len) {
        const user_item = thread.transcript.history.items[user_item_index];
        if (user_item.kind == .message and isHistoryRole(user_item, "user")) {
            try queueUserMessageItemNotification(allocator, state, "item/started", thread.id, turn_id, user_item_index, input.user_content_json, "startedAtMs", started_at_ms);
            try queueUserMessageItemNotification(allocator, state, "item/completed", thread.id, turn_id, user_item_index, input.user_content_json, "completedAtMs", currentUnixMilliseconds());
        }
    }
    if (latestAssistantMessageIndex(&thread.transcript, user_item_index)) |assistant_item_index| {
        const assistant_item = thread.transcript.history.items[assistant_item_index];
        try queueItemNotificationFromHistory(allocator, state, "item/started", thread.id, turn_id, assistant_item, assistant_item_index, "startedAtMs", started_at_ms);
        if (assistant_item.text) |text| {
            if (text.len > 0) {
                try queueAgentMessageDeltaNotification(allocator, state, thread.id, turn_id, assistant_item_index, text);
            }
        }
        try queueItemNotificationFromHistory(allocator, state, "item/completed", thread.id, turn_id, assistant_item, assistant_item_index, "completedAtMs", completed_at_ms);
    }
    try queueTurnNotification(allocator, state, "turn/completed", completed_notification);
    completed_notification_moved = true;
    thread.status = .idle;
    try queueThreadStatusChangedNotification(allocator, state, thread.id, .idle);

    return renderJsonRpcResult(allocator, id_value, response);
}

fn handleTurnSteer(
    allocator: std.mem.Allocator,
    state: *AppServerState,
    id_value: std.json.Value,
    params_value: ?std.json.Value,
) ![]const u8 {
    const params = params_value orelse return renderJsonRpcError(allocator, id_value, -32602, "turn/steer params must be an object");
    if (params != .object) return renderJsonRpcError(allocator, id_value, -32602, "turn/steer params must be an object");
    const object = params.object;

    const thread_id = requiredThreadIdParam(object) catch |err| switch (err) {
        error.MissingThreadId => return renderJsonRpcError(allocator, id_value, -32602, "threadId must be a string"),
    };
    const expected_turn_id_value = object.get("expectedTurnId") orelse return renderJsonRpcError(allocator, id_value, -32602, "expectedTurnId must be a string");
    if (expected_turn_id_value != .string) return renderJsonRpcError(allocator, id_value, -32602, "expectedTurnId must be a string");
    if (expected_turn_id_value.string.len == 0) return renderJsonRpcError(allocator, id_value, -32600, "expectedTurnId must not be empty");
    if (!isUuidString(thread_id)) {
        return renderInvalidThreadId(allocator, id_value, thread_id);
    }
    if (findLoadedThreadIndex(state, thread_id) == null) {
        return renderThreadNotFound(allocator, id_value, thread_id);
    }

    var input = parseTurnStartInput(allocator, object) catch |err| switch (err) {
        error.InvalidTurnInput => return renderJsonRpcError(allocator, id_value, -32602, "input must be an array of supported user input items"),
        error.EmptyTurnInput => return renderJsonRpcError(allocator, id_value, -32600, "input must not be empty"),
        error.UnsupportedTurnInput => return renderJsonRpcError(allocator, id_value, -32600, "only text, image, localImage, skill, and mention turn/steer input is implemented"),
        else => return err,
    };
    defer input.deinit(allocator);

    return renderJsonRpcError(allocator, id_value, -32600, "no active turn to steer");
}

fn handleTurnInterrupt(
    allocator: std.mem.Allocator,
    state: *AppServerState,
    id_value: std.json.Value,
    params_value: ?std.json.Value,
) ![]const u8 {
    const params = params_value orelse return renderJsonRpcError(allocator, id_value, -32602, "turn/interrupt params must be an object");
    if (params != .object) return renderJsonRpcError(allocator, id_value, -32602, "turn/interrupt params must be an object");
    const object = params.object;

    const thread_id = requiredThreadIdParam(object) catch |err| switch (err) {
        error.MissingThreadId => return renderJsonRpcError(allocator, id_value, -32602, "threadId must be a string"),
    };
    const turn_id_value = object.get("turnId") orelse return renderJsonRpcError(allocator, id_value, -32602, "turnId must be a string");
    if (turn_id_value != .string) return renderJsonRpcError(allocator, id_value, -32602, "turnId must be a string");
    if (!isUuidString(thread_id)) {
        return renderInvalidThreadId(allocator, id_value, thread_id);
    }
    if (findLoadedThreadIndex(state, thread_id) == null) {
        return renderThreadNotFound(allocator, id_value, thread_id);
    }

    if (turn_id_value.string.len == 0) {
        return renderJsonRpcResult(allocator, id_value, "{}");
    }
    return renderJsonRpcError(allocator, id_value, -32600, "no active turn to interrupt");
}

fn parseTurnStartInput(allocator: std.mem.Allocator, params: std.json.ObjectMap) !TurnStartInput {
    const input = params.get("input") orelse return error.InvalidTurnInput;
    if (input != .array) return error.InvalidTurnInput;

    var prompt = std.ArrayList(u8).empty;
    errdefer prompt.deinit(allocator);
    var user_content = std.ArrayList(u8).empty;
    errdefer user_content.deinit(allocator);
    try user_content.append(allocator, '[');
    var image_urls = std.ArrayList([]const u8).empty;
    var image_urls_moved = false;
    errdefer if (!image_urls_moved) {
        for (image_urls.items) |image_url| allocator.free(image_url);
        image_urls.deinit(allocator);
    };
    var local_image_paths = std.ArrayList([]const u8).empty;
    var local_image_paths_moved = false;
    errdefer if (!local_image_paths_moved) {
        for (local_image_paths.items) |path| allocator.free(path);
        local_image_paths.deinit(allocator);
    };
    var skills = std.ArrayList(TurnNamedPathInput).empty;
    var skills_moved = false;
    errdefer if (!skills_moved) {
        for (skills.items) |item| item.deinit(allocator);
        skills.deinit(allocator);
    };
    var input_items: usize = 0;
    var text_items: usize = 0;
    for (input.array.items) |item| {
        if (item != .object) return error.InvalidTurnInput;
        const item_type = item.object.get("type") orelse return error.InvalidTurnInput;
        if (item_type != .string) return error.InvalidTurnInput;
        if (std.mem.eql(u8, item_type.string, "text")) {
            const text = item.object.get("text") orelse return error.InvalidTurnInput;
            if (text != .string) return error.InvalidTurnInput;
            if (text_items > 0) try prompt.append(allocator, '\n');
            try prompt.appendSlice(allocator, text.string);
            if (input_items > 0) try user_content.append(allocator, ',');
            try appendTurnStartTextInputJson(allocator, &user_content, item.object, text.string);
            text_items += 1;
            input_items += 1;
        } else if (std.mem.eql(u8, item_type.string, "image")) {
            const url = item.object.get("url") orelse return error.InvalidTurnInput;
            if (url != .string) return error.InvalidTurnInput;
            const image_url = try allocator.dupe(u8, url.string);
            image_urls.append(allocator, image_url) catch |err| {
                allocator.free(image_url);
                return err;
            };
            if (input_items > 0) try user_content.append(allocator, ',');
            try appendTurnStartImageInputJson(allocator, &user_content, url.string);
            input_items += 1;
        } else if (std.mem.eql(u8, item_type.string, "localImage")) {
            const path = item.object.get("path") orelse return error.InvalidTurnInput;
            if (path != .string) return error.InvalidTurnInput;
            const local_image_path = try allocator.dupe(u8, path.string);
            local_image_paths.append(allocator, local_image_path) catch |err| {
                allocator.free(local_image_path);
                return err;
            };
            if (input_items > 0) try user_content.append(allocator, ',');
            try appendTurnStartLocalImageInputJson(allocator, &user_content, path.string);
            input_items += 1;
        } else if (std.mem.eql(u8, item_type.string, "skill")) {
            const name = item.object.get("name") orelse return error.InvalidTurnInput;
            const path = item.object.get("path") orelse return error.InvalidTurnInput;
            if (name != .string or path != .string) return error.InvalidTurnInput;
            const skill = try TurnNamedPathInput.init(allocator, name.string, path.string);
            skills.append(allocator, skill) catch |err| {
                skill.deinit(allocator);
                return err;
            };
            if (input_items > 0) try user_content.append(allocator, ',');
            try appendTurnStartNamedPathInputJson(allocator, &user_content, "skill", name.string, path.string);
            input_items += 1;
        } else if (std.mem.eql(u8, item_type.string, "mention")) {
            const name = item.object.get("name") orelse return error.InvalidTurnInput;
            const path = item.object.get("path") orelse return error.InvalidTurnInput;
            if (name != .string or path != .string) return error.InvalidTurnInput;
            if (input_items > 0) try user_content.append(allocator, ',');
            try appendTurnStartNamedPathInputJson(allocator, &user_content, "mention", name.string, path.string);
            input_items += 1;
        } else {
            return error.UnsupportedTurnInput;
        }
    }
    if (input_items == 0) return error.EmptyTurnInput;
    try user_content.append(allocator, ']');
    const prompt_owned = try prompt.toOwnedSlice(allocator);
    errdefer allocator.free(prompt_owned);
    const user_content_owned = try user_content.toOwnedSlice(allocator);
    errdefer allocator.free(user_content_owned);
    const image_urls_owned = try image_urls.toOwnedSlice(allocator);
    image_urls_moved = true;
    errdefer {
        for (image_urls_owned) |image_url| allocator.free(image_url);
        allocator.free(image_urls_owned);
    }
    const local_image_paths_owned = try local_image_paths.toOwnedSlice(allocator);
    local_image_paths_moved = true;
    errdefer {
        for (local_image_paths_owned) |path| allocator.free(path);
        allocator.free(local_image_paths_owned);
    }
    const skills_owned = try skills.toOwnedSlice(allocator);
    skills_moved = true;
    errdefer {
        for (skills_owned) |item| item.deinit(allocator);
        allocator.free(skills_owned);
    }
    return .{
        .prompt = prompt_owned,
        .user_content_json = user_content_owned,
        .image_urls = image_urls_owned,
        .local_image_paths = local_image_paths_owned,
        .skills = skills_owned,
    };
}

fn appendTurnStartTextInputJson(
    allocator: std.mem.Allocator,
    out: *std.ArrayList(u8),
    item: std.json.ObjectMap,
    text: []const u8,
) !void {
    try out.appendSlice(allocator, "{\"type\":\"text\",\"text\":");
    try appendJsonString(allocator, out, text);
    try out.appendSlice(allocator, ",\"text_elements\":");
    if (item.get("text_elements")) |text_elements| {
        if (text_elements != .array) return error.InvalidTurnInput;
        const text_elements_json = try std.json.Stringify.valueAlloc(allocator, text_elements, .{});
        defer allocator.free(text_elements_json);
        try out.appendSlice(allocator, text_elements_json);
    } else {
        try out.appendSlice(allocator, "[]");
    }
    try out.append(allocator, '}');
}

fn appendTurnStartImageInputJson(
    allocator: std.mem.Allocator,
    out: *std.ArrayList(u8),
    url: []const u8,
) !void {
    try out.appendSlice(allocator, "{\"type\":\"image\",\"url\":");
    try appendJsonString(allocator, out, url);
    try out.append(allocator, '}');
}

fn appendTurnStartLocalImageInputJson(
    allocator: std.mem.Allocator,
    out: *std.ArrayList(u8),
    path: []const u8,
) !void {
    try out.appendSlice(allocator, "{\"type\":\"localImage\",\"path\":");
    try appendJsonString(allocator, out, path);
    try out.append(allocator, '}');
}

fn appendTurnStartNamedPathInputJson(
    allocator: std.mem.Allocator,
    out: *std.ArrayList(u8),
    item_type: []const u8,
    name: []const u8,
    path: []const u8,
) !void {
    try out.appendSlice(allocator, "{\"type\":");
    try appendJsonString(allocator, out, item_type);
    try out.appendSlice(allocator, ",\"name\":");
    try appendJsonString(allocator, out, name);
    try out.appendSlice(allocator, ",\"path\":");
    try appendJsonString(allocator, out, path);
    try out.append(allocator, '}');
}

fn combineTurnInputImages(
    allocator: std.mem.Allocator,
    image_urls: []const []const u8,
    local_image_urls: []const []const u8,
) ![]const []const u8 {
    const total_len = image_urls.len + local_image_urls.len;
    if (total_len == 0) return &.{};

    const combined = try allocator.alloc([]const u8, total_len);
    for (image_urls, 0..) |image_url, index| combined[index] = image_url;
    for (local_image_urls, 0..) |image_url, index| combined[image_urls.len + index] = image_url;
    return combined;
}

fn loadTurnLocalImages(allocator: std.mem.Allocator, paths: []const []const u8) !TurnLocalImages {
    if (paths.len == 0) return .{};

    var data_urls = std.ArrayList([]const u8).empty;
    var data_urls_moved = false;
    errdefer if (!data_urls_moved) {
        for (data_urls.items) |data_url| allocator.free(data_url);
        data_urls.deinit(allocator);
    };

    var missing_placeholders = std.ArrayList([]const u8).empty;
    var missing_placeholders_moved = false;
    errdefer if (!missing_placeholders_moved) {
        for (missing_placeholders.items) |placeholder| allocator.free(placeholder);
        missing_placeholders.deinit(allocator);
    };

    for (paths) |path| {
        const data_url = image_inputs.loadOne(allocator, path) catch |err| {
            const placeholder = try renderLocalImageErrorPlaceholder(allocator, path, err);
            missing_placeholders.append(allocator, placeholder) catch |append_err| {
                allocator.free(placeholder);
                return append_err;
            };
            continue;
        };
        data_urls.append(allocator, data_url) catch |err| {
            allocator.free(data_url);
            return err;
        };
    }

    const data_urls_owned = try data_urls.toOwnedSlice(allocator);
    data_urls_moved = true;
    errdefer {
        for (data_urls_owned) |data_url| allocator.free(data_url);
        if (data_urls_owned.len > 0) allocator.free(data_urls_owned);
    }
    const missing_placeholders_owned = try missing_placeholders.toOwnedSlice(allocator);
    missing_placeholders_moved = true;
    return .{
        .data_urls = data_urls_owned,
        .missing_placeholders = missing_placeholders_owned,
    };
}

fn renderLocalImageErrorPlaceholder(
    allocator: std.mem.Allocator,
    path: []const u8,
    err: anyerror,
) ![]const u8 {
    return std.fmt.allocPrint(allocator, "Codex could not read the local image at `{s}`: {s}", .{ path, @errorName(err) });
}

const TurnSkillInjections = struct {
    blocks: []const []const u8 = &.{},

    fn deinit(self: *TurnSkillInjections, allocator: std.mem.Allocator) void {
        for (self.blocks) |block| allocator.free(block);
        if (self.blocks.len > 0) allocator.free(self.blocks);
    }
};

fn loadTurnSkillInjections(allocator: std.mem.Allocator, skills: []const TurnNamedPathInput) !TurnSkillInjections {
    if (skills.len == 0) return .{};

    var blocks = std.ArrayList([]const u8).empty;
    var blocks_moved = false;
    errdefer if (!blocks_moved) {
        for (blocks.items) |block| allocator.free(block);
        blocks.deinit(allocator);
    };

    for (skills) |skill| {
        const contents = std.Io.Dir.cwd().readFileAlloc(
            std.Io.Threaded.global_single_threaded.io(),
            skill.path,
            allocator,
            .limited(512 * 1024),
        ) catch |err| blk: {
            break :blk try std.fmt.allocPrint(allocator, "Codex could not read the skill file: {s}", .{@errorName(err)});
        };
        defer allocator.free(contents);

        const block = try renderTurnSkillBlock(allocator, skill, contents);
        blocks.append(allocator, block) catch |err| {
            allocator.free(block);
            return err;
        };
    }

    const blocks_owned = try blocks.toOwnedSlice(allocator);
    blocks_moved = true;
    return .{ .blocks = blocks_owned };
}

fn renderTurnSkillBlock(
    allocator: std.mem.Allocator,
    skill: TurnNamedPathInput,
    contents: []const u8,
) ![]const u8 {
    return std.fmt.allocPrint(
        allocator,
        "<skill>\n<name>{s}</name>\n<path>{s}</path>\n{s}\n</skill>",
        .{ skill.name, skill.path, contents },
    );
}

fn turnPromptWithContextBlocks(
    allocator: std.mem.Allocator,
    prompt: []const u8,
    placeholders: []const []const u8,
    skill_blocks: []const []const u8,
) ![]const u8 {
    if (placeholders.len == 0 and skill_blocks.len == 0) return allocator.dupe(u8, prompt);

    var out = std.ArrayList(u8).empty;
    errdefer out.deinit(allocator);
    if (prompt.len > 0) try out.appendSlice(allocator, prompt);
    for (placeholders) |placeholder| {
        if (out.items.len > 0) try out.append(allocator, '\n');
        try out.appendSlice(allocator, placeholder);
    }
    for (skill_blocks) |skill_block| {
        if (out.items.len > 0) try out.append(allocator, '\n');
        try out.appendSlice(allocator, skill_block);
    }
    return out.toOwnedSlice(allocator);
}

fn nextTurnIdForTranscript(allocator: std.mem.Allocator, transcript: *const session_mod.Transcript) ![]const u8 {
    var count: usize = 0;
    for (transcript.history.items) |item| {
        if (item.kind == .message) count += 1;
    }
    return std.fmt.allocPrint(allocator, "turn-{d}", .{count});
}

fn applyTurnStartRuntimeOverrides(
    allocator: std.mem.Allocator,
    cfg: *config.Config,
    thread: *LoadedThread,
    params: std.json.ObjectMap,
) !void {
    const effective_model = optionalStringParam(params, "model") orelse thread.model;
    try replaceOwnedString(allocator, &cfg.model, effective_model);
    if (optionalStringParam(params, "model")) |model| {
        try replaceOwnedString(allocator, &thread.model, model);
        thread.runtime_overrides.model = true;
    }

    if (optionalStringParam(params, "cwd")) |cwd_raw| {
        const cwd = try std.Io.Dir.cwd().realPathFileAlloc(std.Io.Threaded.global_single_threaded.io(), cwd_raw, allocator);
        defer allocator.free(cwd);
        try replaceOwnedString(allocator, &thread.cwd, cwd);
        try thread.transcript.setCwd(allocator, cwd);
    }

    const approval_policy_label = optionalStringParam(params, "approvalPolicy") orelse thread.approval_policy;
    cfg.approval_policy = config.ApprovalPolicy.parse(approval_policy_label) catch return error.InvalidTurnContextOverride;
    if (optionalStringParam(params, "approvalPolicy")) |approval_policy| {
        try replaceOwnedString(allocator, &thread.approval_policy, approval_policy);
        thread.runtime_overrides.approval_policy = true;
    }

    const sandbox_label = optionalStringParam(params, "sandbox") orelse thread.sandbox_mode;
    cfg.sandbox_mode = config.SandboxMode.parse(sandbox_label) catch return error.InvalidTurnContextOverride;
    if (optionalStringParam(params, "sandbox")) |sandbox| {
        try replaceOwnedString(allocator, &thread.sandbox_mode, sandbox);
        thread.runtime_overrides.sandbox_mode = true;
    }

    if (optionalStringParam(params, "modelProvider")) |model_provider| {
        try replaceOwnedString(allocator, &thread.model_provider, model_provider);
        try thread.transcript.setModelProvider(allocator, model_provider);
        thread.runtime_overrides.model_provider = true;
    }

    if (params.get("serviceTier")) |service_tier_value| {
        if (service_tier_value != .null and service_tier_value != .string) return error.InvalidTurnContextOverride;
        if (thread.service_tier) |existing| allocator.free(existing);
        thread.service_tier = if (service_tier_value == .string)
            try allocator.dupe(u8, service_tier_value.string)
        else
            null;
        if (cfg.service_tier) |existing| allocator.free(existing);
        cfg.service_tier = if (thread.service_tier) |value| try allocator.dupe(u8, value) else null;
        thread.runtime_overrides.service_tier = true;
    } else {
        if (cfg.service_tier) |existing| allocator.free(existing);
        cfg.service_tier = if (thread.service_tier) |value| try allocator.dupe(u8, value) else null;
    }
}

fn refreshLoadedThreadAfterTurn(allocator: std.mem.Allocator, thread: *LoadedThread, prompt: []const u8) !void {
    if (thread.preview.len == 0) try replaceOwnedString(allocator, &thread.preview, prompt);
    const turns_json = try renderTranscriptTurnsJson(allocator, &thread.transcript, true);
    errdefer allocator.free(turns_json);
    allocator.free(thread.turns_json);
    thread.turns_json = turns_json;
    thread.updated_at = currentUnixSeconds();
}

fn rollbackLoadedThread(allocator: std.mem.Allocator, thread: *LoadedThread, num_turns: u32) !void {
    const path = thread.path orelse return error.RollbackRequiresPersistedHistory;
    if (rollbackCutIndex(&thread.transcript, num_turns)) |cut_index| {
        trimTranscriptHistoryFrom(allocator, &thread.transcript, cut_index);
    }
    try refreshLoadedThreadAfterRollback(allocator, thread);
    try session_store.appendThreadRollback(allocator, path, num_turns);
}

fn rollbackCutIndex(transcript: *const session_mod.Transcript, num_turns: u32) ?usize {
    var earliest_user_index: ?usize = null;
    var remaining = num_turns;
    var index = transcript.history.items.len;
    while (index > 0) {
        index -= 1;
        const item = transcript.history.items[index];
        if (item.kind == .message and isHistoryRole(item, "user")) {
            earliest_user_index = index;
            if (remaining == 1) return index;
            remaining -= 1;
        }
    }
    return earliest_user_index;
}

fn trimTranscriptHistoryFrom(allocator: std.mem.Allocator, transcript: *session_mod.Transcript, cut_index: usize) void {
    for (transcript.history.items[cut_index..]) |item| item.deinit(allocator);
    transcript.history.shrinkRetainingCapacity(cut_index);
}

fn refreshLoadedThreadAfterRollback(allocator: std.mem.Allocator, thread: *LoadedThread) !void {
    const preview = try resumePreview(allocator, &thread.transcript);
    defer allocator.free(preview);
    try replaceOwnedString(allocator, &thread.preview, preview);

    const turns_json = try renderTranscriptTurnsJson(allocator, &thread.transcript, true);
    errdefer allocator.free(turns_json);
    allocator.free(thread.turns_json);
    thread.turns_json = turns_json;

    thread.token_usage = thread.transcript.token_usage;
    if (thread.token_usage_turn_id) |turn_id| allocator.free(turn_id);
    thread.token_usage_turn_id = null;
    thread.token_usage_turn_id = try transcriptTokenUsageTurnId(allocator, &thread.transcript);
    thread.updated_at = currentUnixSeconds();
}

fn setLoadedThreadName(allocator: std.mem.Allocator, thread: *LoadedThread, name: []const u8) !void {
    const owned_name = try allocator.dupe(u8, name);
    var owned_name_moved = false;
    errdefer if (!owned_name_moved) allocator.free(owned_name);

    try thread.transcript.setTitle(allocator, name);
    if (thread.name) |existing| allocator.free(existing);
    thread.name = owned_name;
    owned_name_moved = true;
    thread.updated_at = currentUnixSeconds();
    if (thread.path) |path| try session_store.saveTranscript(allocator, path, &thread.transcript);
}

fn setLoadedThreadMemoryMode(allocator: std.mem.Allocator, thread: *LoadedThread, mode: []const u8) !void {
    try thread.transcript.setMemoryMode(allocator, mode);
    thread.updated_at = currentUnixSeconds();
    if (thread.path) |path| try session_store.saveTranscript(allocator, path, &thread.transcript);
}

fn setLoadedThreadPath(allocator: std.mem.Allocator, thread: *LoadedThread, path: []const u8) !void {
    const owned_path = try allocator.dupe(u8, path);
    errdefer allocator.free(owned_path);
    if (thread.path) |existing| allocator.free(existing);
    thread.path = owned_path;
    thread.updated_at = currentUnixSeconds();
}

fn setLoadedThreadGoal(
    allocator: std.mem.Allocator,
    thread: *LoadedThread,
    object: std.json.ObjectMap,
) !void {
    const now = currentUnixSeconds();
    const objective = loadedThreadGoalObjective(object);
    const status = loadedThreadGoalStatus(object);
    const token_budget = loadedThreadGoalTokenBudget(object);

    if (objective) |value| {
        if (thread.goal) |*existing| {
            if (std.mem.eql(u8, existing.objective, value) and !std.mem.eql(u8, existing.status, "complete")) {
                if (status) |next_status| {
                    const status_copy = try allocator.dupe(u8, next_status);
                    allocator.free(existing.status);
                    existing.status = status_copy;
                }
                if (token_budget.present) existing.token_budget = token_budget.value;
                existing.updated_at = now;
                thread.updated_at = now;
                return;
            }
            existing.deinit(allocator);
            thread.goal = null;
        }

        const objective_copy = try allocator.dupe(u8, value);
        errdefer allocator.free(objective_copy);
        const status_copy = try allocator.dupe(u8, status orelse "active");
        errdefer allocator.free(status_copy);

        thread.goal = .{
            .objective = objective_copy,
            .status = status_copy,
            .token_budget = if (token_budget.present) token_budget.value else null,
            .tokens_used = 0,
            .time_used_seconds = 0,
            .created_at = now,
            .updated_at = now,
        };
        thread.updated_at = now;
        return;
    }

    const existing = if (thread.goal) |*goal| goal else return error.MissingThreadGoal;
    if (status) |next_status| {
        const status_copy = try allocator.dupe(u8, next_status);
        allocator.free(existing.status);
        existing.status = status_copy;
    }
    if (token_budget.present) existing.token_budget = token_budget.value;
    existing.updated_at = now;
    thread.updated_at = now;
}

fn loadedThreadGoalObjective(object: std.json.ObjectMap) ?[]const u8 {
    const value = object.get("objective") orelse return null;
    if (value == .null) return null;
    return std.mem.trim(u8, value.string, " \t\r\n");
}

fn loadedThreadGoalStatus(object: std.json.ObjectMap) ?[]const u8 {
    const value = object.get("status") orelse return null;
    if (value == .null) return null;
    return value.string;
}

const LoadedThreadGoalTokenBudget = struct {
    present: bool,
    value: ?i64,
};

fn loadedThreadGoalTokenBudget(object: std.json.ObjectMap) LoadedThreadGoalTokenBudget {
    const value = object.get("tokenBudget") orelse return .{ .present = false, .value = null };
    if (value == .null) return .{ .present = true, .value = null };
    return .{ .present = true, .value = value.integer };
}

fn clearLoadedThreadGoal(allocator: std.mem.Allocator, thread: *LoadedThread) bool {
    if (thread.goal) |*goal| {
        goal.deinit(allocator);
    } else {
        return false;
    }
    thread.goal = null;
    thread.updated_at = currentUnixSeconds();
    return true;
}

fn updateLoadedThreadGitInfo(
    allocator: std.mem.Allocator,
    thread: *LoadedThread,
    git_info: std.json.ObjectMap,
) !void {
    try patchLoadedThreadGitInfoField(allocator, git_info, "sha", &thread.git_sha);
    try patchLoadedThreadGitInfoField(allocator, git_info, "branch", &thread.git_branch);
    try patchLoadedThreadGitInfoField(allocator, git_info, "originUrl", &thread.git_origin_url);
    try syncLoadedThreadGitInfoToTranscript(allocator, thread);
    thread.updated_at = currentUnixSeconds();
    if (thread.path) |path| try session_store.saveTranscript(allocator, path, &thread.transcript);
}

fn syncLoadedThreadGitInfoToTranscript(allocator: std.mem.Allocator, thread: *LoadedThread) !void {
    if (thread.git_sha) |value|
        try thread.transcript.setGitSha(allocator, value)
    else
        thread.transcript.clearGitSha(allocator);
    if (thread.git_branch) |value|
        try thread.transcript.setGitBranch(allocator, value)
    else
        thread.transcript.clearGitBranch(allocator);
    if (thread.git_origin_url) |value|
        try thread.transcript.setGitOriginUrl(allocator, value)
    else
        thread.transcript.clearGitOriginUrl(allocator);
}

fn patchLoadedThreadGitInfoField(
    allocator: std.mem.Allocator,
    git_info: std.json.ObjectMap,
    field_name: []const u8,
    slot: *?[]const u8,
) !void {
    const value = git_info.get(field_name) orelse return;
    if (value == .null) {
        clearOptionalOwnedString(allocator, slot);
        return;
    }
    if (value != .string) return error.InvalidThreadMetadataGitInfo;
    const normalized = std.mem.trim(u8, value.string, " \t\r\n");
    if (normalized.len == 0) return error.InvalidThreadMetadataGitInfo;
    try replaceOptionalOwnedString(allocator, slot, normalized);
}

fn replaceOptionalOwnedString(
    allocator: std.mem.Allocator,
    slot: *?[]const u8,
    value: []const u8,
) !void {
    const owned = try allocator.dupe(u8, value);
    clearOptionalOwnedString(allocator, slot);
    slot.* = owned;
}

fn clearOptionalOwnedString(allocator: std.mem.Allocator, slot: *?[]const u8) void {
    if (slot.*) |existing| allocator.free(existing);
    slot.* = null;
}

fn appendInjectedResponseItem(
    allocator: std.mem.Allocator,
    transcript: *session_mod.Transcript,
    item: std.json.Value,
) !void {
    const before_len = transcript.history.items.len;
    try session_mod.appendResponseHistoryItem(allocator, transcript, item);
    if (transcript.history.items.len == before_len) return error.UnsupportedInjectedItem;
}

fn parseInjectedResponseItems(
    allocator: std.mem.Allocator,
    items: []const std.json.Value,
) !session_mod.Transcript {
    var transcript = session_mod.Transcript{};
    errdefer transcript.deinit(allocator);
    for (items) |item| try appendInjectedResponseItem(allocator, &transcript, item);
    return transcript;
}

fn injectLoadedThreadItems(
    allocator: std.mem.Allocator,
    thread: *LoadedThread,
    items: []const std.json.Value,
) !void {
    if (items.len == 0) return;

    var injected = try parseInjectedResponseItems(allocator, items);
    defer injected.deinit(allocator);
    for (injected.history.items) |item| try thread.transcript.appendHistoryItem(allocator, item);

    const turns_json = try renderTranscriptTurnsJson(allocator, &thread.transcript, true);
    errdefer allocator.free(turns_json);
    allocator.free(thread.turns_json);
    thread.turns_json = turns_json;
    thread.updated_at = currentUnixSeconds();
    if (thread.path) |path| try session_store.saveTranscript(allocator, path, &thread.transcript);
}

fn renderTurnStartResponse(allocator: std.mem.Allocator, turn_id: []const u8) ![]const u8 {
    var response = std.ArrayList(u8).empty;
    errdefer response.deinit(allocator);
    try response.appendSlice(allocator, "{\"turn\":");
    try appendTurnJson(allocator, &response, turn_id, "inProgress", null, null);
    try response.appendSlice(allocator, "}");
    return response.toOwnedSlice(allocator);
}

fn queueItemNotificationFromHistory(
    allocator: std.mem.Allocator,
    state: *AppServerState,
    method: []const u8,
    thread_id: []const u8,
    turn_id: []const u8,
    item: api.HistoryItem,
    item_index: usize,
    timestamp_field: []const u8,
    timestamp_ms: i64,
) !void {
    const notification = try renderItemNotificationFromHistory(allocator, method, thread_id, turn_id, item, item_index, timestamp_field, timestamp_ms);
    var notification_moved = false;
    errdefer if (!notification_moved) allocator.free(notification);
    try queueTurnNotification(allocator, state, method, notification);
    notification_moved = true;
}

fn queueUserMessageItemNotification(
    allocator: std.mem.Allocator,
    state: *AppServerState,
    method: []const u8,
    thread_id: []const u8,
    turn_id: []const u8,
    item_index: usize,
    content_json: []const u8,
    timestamp_field: []const u8,
    timestamp_ms: i64,
) !void {
    const notification = try renderUserMessageItemNotification(allocator, method, thread_id, turn_id, item_index, content_json, timestamp_field, timestamp_ms);
    var notification_moved = false;
    errdefer if (!notification_moved) allocator.free(notification);
    try queueTurnNotification(allocator, state, method, notification);
    notification_moved = true;
}

fn renderUserMessageItemNotification(
    allocator: std.mem.Allocator,
    method: []const u8,
    thread_id: []const u8,
    turn_id: []const u8,
    item_index: usize,
    content_json: []const u8,
    timestamp_field: []const u8,
    timestamp_ms: i64,
) ![]const u8 {
    var notification = std.ArrayList(u8).empty;
    errdefer notification.deinit(allocator);
    try notification.appendSlice(allocator, "{\"jsonrpc\":\"2.0\",\"method\":");
    try appendJsonString(allocator, &notification, method);
    try notification.appendSlice(allocator, ",\"params\":{\"item\":{\"type\":\"userMessage\",\"id\":\"item-");
    try appendUsize(allocator, &notification, item_index);
    try notification.appendSlice(allocator, "\",\"content\":");
    try notification.appendSlice(allocator, content_json);
    try notification.appendSlice(allocator, "},\"threadId\":");
    try appendJsonString(allocator, &notification, thread_id);
    try notification.appendSlice(allocator, ",\"turnId\":");
    try appendJsonString(allocator, &notification, turn_id);
    try notification.append(allocator, ',');
    try appendJsonString(allocator, &notification, timestamp_field);
    try notification.append(allocator, ':');
    try appendInt(allocator, &notification, timestamp_ms);
    try notification.appendSlice(allocator, "}}");
    return notification.toOwnedSlice(allocator);
}

