fn latestAssistantMessageIndex(transcript: *const session_mod.Transcript, start_index: usize) ?usize {
    if (transcript.history.items.len <= start_index) return null;
    var index = transcript.history.items.len;
    while (index > start_index) {
        index -= 1;
        const item = transcript.history.items[index];
        if (item.kind == .message and isHistoryRole(item, "assistant")) return index;
    }
    return null;
}

fn isHistoryRole(item: api.HistoryItem, role: []const u8) bool {
    const item_role = item.role orelse return false;
    return std.mem.eql(u8, item_role, role);
}

fn renderTurnNotification(
    allocator: std.mem.Allocator,
    method: []const u8,
    thread_id: []const u8,
    turn_id: []const u8,
    status: []const u8,
    started_at: ?i64,
    completed_at: ?i64,
) ![]const u8 {
    var notification = std.ArrayList(u8).empty;
    errdefer notification.deinit(allocator);
    try notification.appendSlice(allocator, "{\"jsonrpc\":\"2.0\",\"method\":");
    try appendJsonString(allocator, &notification, method);
    try notification.appendSlice(allocator, ",\"params\":{\"threadId\":");
    try appendJsonString(allocator, &notification, thread_id);
    try notification.appendSlice(allocator, ",\"turn\":");
    try appendTurnJson(allocator, &notification, turn_id, status, started_at, completed_at);
    try notification.appendSlice(allocator, "}}");
    return notification.toOwnedSlice(allocator);
}

fn appendTurnJson(
    allocator: std.mem.Allocator,
    out: *std.ArrayList(u8),
    turn_id: []const u8,
    status: []const u8,
    started_at: ?i64,
    completed_at: ?i64,
) !void {
    try out.appendSlice(allocator, "{\"id\":");
    try appendJsonString(allocator, out, turn_id);
    try out.appendSlice(allocator, ",\"items\":[],\"itemsView\":\"notLoaded\",\"status\":");
    try appendJsonString(allocator, out, status);
    try out.appendSlice(allocator, ",\"error\":null,\"startedAt\":");
    try appendOptionalInt(allocator, out, started_at);
    try out.appendSlice(allocator, ",\"completedAt\":");
    try appendOptionalInt(allocator, out, completed_at);
    try out.appendSlice(allocator, ",\"durationMs\":");
    if (started_at != null and completed_at != null) {
        try appendInt(allocator, out, (completed_at.? - started_at.?) * 1000);
    } else {
        try out.appendSlice(allocator, "null");
    }
    try out.appendSlice(allocator, "}");
}

fn queueTurnNotification(allocator: std.mem.Allocator, state: *AppServerState, method: []const u8, notification: []const u8) !void {
    if (notificationMethodOptedOut(state, method)) {
        allocator.free(notification);
        return;
    }
    try state.pending_notifications.append(allocator, notification);
}

fn queueErrorNotification(
    allocator: std.mem.Allocator,
    state: *AppServerState,
    thread_id: []const u8,
    turn_id: []const u8,
    message: []const u8,
    will_retry: bool,
) !void {
    const notification = try renderErrorNotification(allocator, thread_id, turn_id, message, will_retry);
    var notification_moved = false;
    errdefer if (!notification_moved) allocator.free(notification);
    try queueTurnNotification(allocator, state, "error", notification);
    notification_moved = true;
}

fn renderErrorNotification(
    allocator: std.mem.Allocator,
    thread_id: []const u8,
    turn_id: []const u8,
    message: []const u8,
    will_retry: bool,
) ![]const u8 {
    var notification = std.ArrayList(u8).empty;
    errdefer notification.deinit(allocator);
    try notification.appendSlice(allocator, "{\"jsonrpc\":\"2.0\",\"method\":\"error\",\"params\":{\"error\":{\"message\":");
    try appendJsonString(allocator, &notification, message);
    try notification.appendSlice(allocator, ",\"codexErrorInfo\":null,\"additionalDetails\":null},\"willRetry\":");
    try notification.appendSlice(allocator, if (will_retry) "true" else "false");
    try notification.appendSlice(allocator, ",\"threadId\":");
    try appendJsonString(allocator, &notification, thread_id);
    try notification.appendSlice(allocator, ",\"turnId\":");
    try appendJsonString(allocator, &notification, turn_id);
    try notification.appendSlice(allocator, "}}");
    return notification.toOwnedSlice(allocator);
}

fn isThreadMethod(method: []const u8) bool {
    return std.mem.eql(u8, method, "thread/start") or
        std.mem.eql(u8, method, "thread/resume") or
        std.mem.eql(u8, method, "thread/fork") or
        std.mem.eql(u8, method, "thread/loaded/list") or
        std.mem.eql(u8, method, "thread/unsubscribe") or
        std.mem.eql(u8, method, "thread/archive") or
        std.mem.eql(u8, method, "thread/unarchive") or
        std.mem.eql(u8, method, "thread/compact/start") or
        std.mem.eql(u8, method, "thread/shellCommand") or
        std.mem.eql(u8, method, "thread/approveGuardianDeniedAction") or
        std.mem.eql(u8, method, "thread/backgroundTerminals/clean") or
        std.mem.eql(u8, method, "thread/increment_elicitation") or
        std.mem.eql(u8, method, "thread/decrement_elicitation") or
        std.mem.eql(u8, method, "thread/rollback") or
        std.mem.eql(u8, method, "thread/list") or
        std.mem.eql(u8, method, "thread/inject_items") or
        std.mem.eql(u8, method, "thread/name/set") or
        std.mem.eql(u8, method, "thread/goal/set") or
        std.mem.eql(u8, method, "thread/goal/get") or
        std.mem.eql(u8, method, "thread/goal/clear") or
        std.mem.eql(u8, method, "thread/memoryMode/set") or
        std.mem.eql(u8, method, "thread/metadata/update") or
        std.mem.eql(u8, method, "thread/read") or
        std.mem.eql(u8, method, "thread/turns/list") or
        std.mem.eql(u8, method, "thread/realtime/start") or
        std.mem.eql(u8, method, "thread/realtime/appendAudio") or
        std.mem.eql(u8, method, "thread/realtime/appendText") or
        std.mem.eql(u8, method, "thread/realtime/stop") or
        std.mem.eql(u8, method, "thread/realtime/listVoices");
}

fn handleThreadMethod(
    allocator: std.mem.Allocator,
    state: *AppServerState,
    id_value: std.json.Value,
    method: []const u8,
    params_value: ?std.json.Value,
) ![]const u8 {
    if (std.mem.eql(u8, method, "thread/start")) {
        return handleThreadStart(allocator, state, id_value, params_value);
    }
    if (std.mem.eql(u8, method, "thread/resume")) {
        return handleThreadResume(allocator, state, id_value, params_value);
    }
    if (std.mem.eql(u8, method, "thread/fork")) {
        return handleThreadFork(allocator, state, id_value, params_value);
    }
    if (std.mem.eql(u8, method, "thread/loaded/list")) {
        if (validateThreadLoadedListParams(params_value)) |message| {
            return renderJsonRpcError(allocator, id_value, -32602, message);
        }
        const result = renderThreadLoadedListResult(allocator, state, params_value) catch |err| switch (err) {
            error.InvalidThreadLoadedListCursor => {
                const cursor = threadLoadedListCursor(params_value) orelse "";
                const message = try std.fmt.allocPrint(allocator, "invalid cursor: {s}", .{cursor});
                defer allocator.free(message);
                return renderJsonRpcError(allocator, id_value, -32600, message);
            },
            else => return err,
        };
        defer allocator.free(result);
        return renderJsonRpcResult(allocator, id_value, result);
    }
    if (std.mem.eql(u8, method, "thread/unsubscribe")) {
        const object = parseThreadObjectParams(params_value) catch |err| switch (err) {
            error.InvalidThreadParams => return renderThreadObjectParamsError(allocator, id_value, method),
        };
        const thread_id = requiredThreadIdParam(object) catch |err| switch (err) {
            error.MissingThreadId => return renderJsonRpcError(allocator, id_value, -32602, "threadId must be a string"),
        };
        if (!isUuidString(thread_id)) {
            return renderInvalidThreadId(allocator, id_value, thread_id);
        }
        if (findLoadedThreadIndex(state, thread_id) == null) {
            _ = removeThreadSubscription(allocator, state, thread_id);
            return renderJsonRpcResult(allocator, id_value, "{\"status\":\"notLoaded\"}");
        }
        if (removeThreadSubscription(allocator, state, thread_id)) {
            return renderJsonRpcResult(allocator, id_value, "{\"status\":\"unsubscribed\"}");
        }
        return renderJsonRpcResult(allocator, id_value, "{\"status\":\"notSubscribed\"}");
    }
    if (std.mem.eql(u8, method, "thread/archive")) {
        const object = parseThreadObjectParams(params_value) catch |err| switch (err) {
            error.InvalidThreadParams => return renderThreadObjectParamsError(allocator, id_value, method),
        };
        const thread_id = requiredThreadIdParam(object) catch |err| switch (err) {
            error.MissingThreadId => return renderJsonRpcError(allocator, id_value, -32602, "threadId must be a string"),
        };
        if (!isUuidString(thread_id)) {
            return renderInvalidThreadId(allocator, id_value, thread_id);
        }
        var cfg = config.load(allocator) catch |err| {
            return renderJsonRpcErrorForFailure(allocator, id_value, "thread/archive failed to load config", err);
        };
        defer cfg.deinit(allocator);

        var archive_thread_ids = std.ArrayList([]const u8).empty;
        defer archive_thread_ids.deinit(allocator);
        try archive_thread_ids.append(allocator, thread_id);
        var owned_archive_thread_ids = std.ArrayList([]const u8).empty;
        defer {
            for (owned_archive_thread_ids.items) |owned_id| allocator.free(owned_id);
            owned_archive_thread_ids.deinit(allocator);
        }
        feedback_state.appendSpawnDescendantThreadIds(allocator, cfg.codex_home, thread_id, &archive_thread_ids, &owned_archive_thread_ids) catch |err| switch (err) {
            error.SqlitePrepareFailed => {},
            else => return renderJsonRpcErrorForFailure(allocator, id_value, "thread/archive failed to list spawned descendants", err),
        };

        const archived_path = session_store.archiveRollout(allocator, cfg.codex_home, thread_id) catch |err| switch (err) {
            error.FileNotFound => return renderNoRolloutFoundForThreadId(allocator, id_value, thread_id),
            else => return renderJsonRpcErrorForFailure(allocator, id_value, "thread/archive failed", err),
        };
        defer allocator.free(archived_path);
        _ = thread_state.markThreadArchived(allocator, cfg.codex_home, thread_id, archived_path) catch {};
        if (removeLoadedThread(allocator, state, thread_id)) {
            try queueThreadStatusChangedNotification(allocator, state, thread_id, .not_loaded);
        }
        _ = removeThreadSubscription(allocator, state, thread_id);
        try queueThreadIdNotification(allocator, state, "thread/archived", thread_id);
        var descendant_index = archive_thread_ids.items.len;
        while (descendant_index > 1) {
            descendant_index -= 1;
            const descendant_id = archive_thread_ids.items[descendant_index];
            const descendant_archived_path = session_store.archiveRollout(allocator, cfg.codex_home, descendant_id) catch continue;
            _ = thread_state.markThreadArchived(allocator, cfg.codex_home, descendant_id, descendant_archived_path) catch {};
            allocator.free(descendant_archived_path);
            if (removeLoadedThread(allocator, state, descendant_id)) {
                try queueThreadStatusChangedNotification(allocator, state, descendant_id, .not_loaded);
            }
            _ = removeThreadSubscription(allocator, state, descendant_id);
            try queueThreadIdNotification(allocator, state, "thread/archived", descendant_id);
        }
        return renderJsonRpcResult(allocator, id_value, "{}");
    }
    if (std.mem.eql(u8, method, "thread/unarchive")) {
        const object = parseThreadObjectParams(params_value) catch |err| switch (err) {
            error.InvalidThreadParams => return renderThreadObjectParamsError(allocator, id_value, method),
        };
        const thread_id = requiredThreadIdParam(object) catch |err| switch (err) {
            error.MissingThreadId => return renderJsonRpcError(allocator, id_value, -32602, "threadId must be a string"),
        };
        if (!isUuidString(thread_id)) {
            return renderInvalidThreadId(allocator, id_value, thread_id);
        }
        var cfg = config.load(allocator) catch |err| {
            return renderJsonRpcErrorForFailure(allocator, id_value, "thread/unarchive failed to load config", err);
        };
        defer cfg.deinit(allocator);
        const unarchived_path = session_store.unarchiveRollout(allocator, cfg.codex_home, thread_id) catch |err| switch (err) {
            error.FileNotFound => return renderNoArchivedRolloutFoundForThreadId(allocator, id_value, thread_id),
            else => return renderJsonRpcErrorForFailure(allocator, id_value, "thread/unarchive failed", err),
        };
        defer allocator.free(unarchived_path);
        _ = thread_state.markThreadUnarchived(allocator, cfg.codex_home, thread_id, unarchived_path) catch {};
        var unarchived_thread = createStoredThreadFromPath(allocator, cfg, object, unarchived_path) catch |err| {
            return renderJsonRpcErrorForFailure(allocator, id_value, "thread/unarchive failed to load thread", err);
        };
        defer unarchived_thread.deinit(allocator);
        const response_status: ThreadRuntimeStatus = if (findLoadedThreadIndex(state, thread_id)) |thread_index| status: {
            if (unarchived_thread.path) |path| {
                try setLoadedThreadPath(allocator, &state.loaded_threads.items[thread_index], path);
            }
            break :status .idle;
        } else .not_loaded;
        const result = try renderThreadReadResponseWithStatus(allocator, &unarchived_thread, false, response_status);
        defer allocator.free(result);
        try queueThreadIdNotification(allocator, state, "thread/unarchived", thread_id);
        return renderJsonRpcResult(allocator, id_value, result);
    }
    if (std.mem.eql(u8, method, "thread/compact/start")) {
        return renderThreadNotFoundForThreadIdParam(allocator, id_value, method, params_value);
    }
    if (std.mem.eql(u8, method, "thread/shellCommand")) {
        const object = parseThreadObjectParams(params_value) catch |err| switch (err) {
            error.InvalidThreadParams => return renderThreadObjectParamsError(allocator, id_value, method),
        };
        const thread_id = requiredThreadIdParam(object) catch |err| switch (err) {
            error.MissingThreadId => return renderJsonRpcError(allocator, id_value, -32602, "threadId must be a string"),
        };
        const command_value = object.get("command") orelse return renderJsonRpcError(allocator, id_value, -32602, "command must be a string");
        if (command_value != .string) return renderJsonRpcError(allocator, id_value, -32602, "command must be a string");
        if (std.mem.trim(u8, command_value.string, " \t\r\n").len == 0) {
            return renderJsonRpcError(allocator, id_value, -32600, "command must not be empty");
        }
        if (!isUuidString(thread_id)) {
            return renderInvalidThreadId(allocator, id_value, thread_id);
        }
        return renderThreadNotFound(allocator, id_value, thread_id);
    }
    if (std.mem.eql(u8, method, "thread/approveGuardianDeniedAction")) {
        const object = parseThreadObjectParams(params_value) catch |err| switch (err) {
            error.InvalidThreadParams => return renderThreadObjectParamsError(allocator, id_value, method),
        };
        const thread_id = requiredThreadIdParam(object) catch |err| switch (err) {
            error.MissingThreadId => return renderJsonRpcError(allocator, id_value, -32602, "threadId must be a string"),
        };
        const event_value = object.get("event") orelse return renderJsonRpcError(allocator, id_value, -32602, "event must be a Guardian denial event");
        if (!guardianAssessmentEventIsValid(event_value)) {
            return renderJsonRpcError(allocator, id_value, -32600, "invalid Guardian denial event");
        }
        if (!isUuidString(thread_id)) {
            return renderInvalidThreadId(allocator, id_value, thread_id);
        }
        if (findLoadedThread(state, thread_id) != null) {
            return renderJsonRpcResult(allocator, id_value, "{}");
        }
        return renderThreadNotFound(allocator, id_value, thread_id);
    }
    if (std.mem.eql(u8, method, "thread/backgroundTerminals/clean")) {
        return renderThreadNotFoundForThreadIdParam(allocator, id_value, method, params_value);
    }
    if (std.mem.eql(u8, method, "thread/increment_elicitation") or
        std.mem.eql(u8, method, "thread/decrement_elicitation"))
    {
        const object = parseThreadObjectParams(params_value) catch |err| switch (err) {
            error.InvalidThreadParams => return renderThreadObjectParamsError(allocator, id_value, method),
        };
        const thread_id = requiredThreadIdParam(object) catch |err| switch (err) {
            error.MissingThreadId => return renderJsonRpcError(allocator, id_value, -32602, "threadId must be a string"),
        };
        if (!isUuidString(thread_id)) {
            return renderInvalidThreadId(allocator, id_value, thread_id);
        }
        const thread_index = findLoadedThreadIndex(state, thread_id) orelse {
            return renderThreadNotFound(allocator, id_value, thread_id);
        };
        const thread = &state.loaded_threads.items[thread_index];
        if (std.mem.eql(u8, method, "thread/increment_elicitation")) {
            if (thread.elicitation_count == std.math.maxInt(u64)) {
                return renderJsonRpcError(allocator, id_value, -32603, "failed to increment out-of-band elicitation counter: out-of-band elicitation count overflowed");
            }
            thread.elicitation_count += 1;
        } else {
            if (thread.elicitation_count == 0) {
                return renderJsonRpcError(allocator, id_value, -32600, "out-of-band elicitation count is already zero");
            }
            thread.elicitation_count -= 1;
        }
        const result = try renderThreadElicitationResponse(allocator, thread.elicitation_count);
        defer allocator.free(result);
        return renderJsonRpcResult(allocator, id_value, result);
    }
    if (std.mem.eql(u8, method, "thread/rollback")) {
        const object = parseThreadObjectParams(params_value) catch |err| switch (err) {
            error.InvalidThreadParams => return renderThreadObjectParamsError(allocator, id_value, method),
        };
        const thread_id = requiredThreadIdParam(object) catch |err| switch (err) {
            error.MissingThreadId => return renderJsonRpcError(allocator, id_value, -32602, "threadId must be a string"),
        };
