            error.InvalidThreadParams => return renderThreadObjectParamsError(allocator, id_value, method),
        };
        const thread_id = requiredThreadIdParam(object) catch |err| switch (err) {
            error.MissingThreadId => return renderJsonRpcError(allocator, id_value, -32602, "threadId must be a string"),
        };
        if (validateThreadRealtimeStartParams(object)) |message| {
            return renderJsonRpcError(allocator, id_value, -32602, message);
        }
        if (!isUuidString(thread_id)) {
            return renderInvalidThreadId(allocator, id_value, thread_id);
        }
        return renderThreadNotFound(allocator, id_value, thread_id);
    }
    return renderParsedButNotImplemented(allocator, id_value, method);
}

fn handleThreadStart(
    allocator: std.mem.Allocator,
    state: *AppServerState,
    id_value: std.json.Value,
    params_value: ?std.json.Value,
) ![]const u8 {
    if (validateThreadStartParams(params_value)) |message| {
        return renderJsonRpcError(allocator, id_value, -32602, message);
    }
    const params = threadStartObjectParams(params_value);

    var cfg = config.load(allocator) catch |err| {
        return renderJsonRpcErrorForFailure(allocator, id_value, "thread/start failed to load config", err);
    };
    defer cfg.deinit(allocator);

    var thread = createLoadedThreadFromStartParams(allocator, cfg, params) catch |err| {
        return renderJsonRpcErrorForFailure(allocator, id_value, "thread/start failed to create thread", err);
    };
    var thread_moved = false;
    errdefer if (!thread_moved) thread.deinit(allocator);

    const result = try renderThreadLifecycleResponse(allocator, &thread, true);
    defer allocator.free(result);
    const started_notification = try renderThreadStartedNotification(allocator, &thread);
    var notification_moved = false;
    errdefer if (!notification_moved) allocator.free(started_notification);

    const subscription_added = try ensureThreadSubscribed(allocator, state, thread.id);
    var subscription_committed = false;
    errdefer {
        if (subscription_added and !subscription_committed) _ = removeThreadSubscription(allocator, state, thread.id);
    }
    try state.loaded_threads.append(allocator, thread);
    thread_moved = true;
    subscription_committed = true;
    try queueThreadStartedNotification(allocator, state, started_notification);
    notification_moved = true;

    return renderJsonRpcResult(allocator, id_value, result);
}

fn handleThreadResume(
    allocator: std.mem.Allocator,
    state: *AppServerState,
    id_value: std.json.Value,
    params_value: ?std.json.Value,
) ![]const u8 {
    if (validateThreadResumeParams(params_value)) |message| {
        return renderJsonRpcError(allocator, id_value, -32602, message);
    }
    const object = parseThreadObjectParams(params_value) catch |err| switch (err) {
        error.InvalidThreadParams => return renderThreadObjectParamsError(allocator, id_value, "thread/resume"),
    };
    var cfg = config.load(allocator) catch |err| {
        return renderJsonRpcErrorForFailure(allocator, id_value, "thread/resume failed to load config", err);
    };
    defer cfg.deinit(allocator);

    if (object.get("history")) |history| {
        if (history != .null) {
            var thread = createLoadedThreadFromHistoryParams(allocator, cfg, object, history.array.items) catch |err| switch (err) {
                error.EmptyHistory => return renderJsonRpcError(allocator, id_value, -32600, "history must not be empty"),
                error.InvalidHistory => return renderJsonRpcError(allocator, id_value, -32602, "history entries must be response items"),
                else => return renderJsonRpcErrorForFailure(allocator, id_value, "thread/resume failed to create thread from history", err),
            };
            var thread_moved = false;
            errdefer if (!thread_moved) thread.deinit(allocator);

            const include_turns = !(optionalBoolParam(object, "excludeTurns") orelse false);
            const result = try renderThreadLifecycleResponse(allocator, &thread, include_turns);
            defer allocator.free(result);

            const subscription_added = try ensureThreadSubscribed(allocator, state, thread.id);
            var subscription_committed = false;
            errdefer {
                if (subscription_added and !subscription_committed) _ = removeThreadSubscription(allocator, state, thread.id);
            }
            try upsertLoadedThread(allocator, state, thread);
            thread_moved = true;
            subscription_committed = true;
            if (include_turns) try queueThreadTokenUsageNotification(allocator, state, &thread);

            return renderJsonRpcResult(allocator, id_value, result);
        }
    }

    const resume_path_raw = try threadResumePathIncludingStateDb(allocator, cfg.codex_home, object);
    defer allocator.free(resume_path_raw);

    var transcript = session_store.loadTranscript(allocator, resume_path_raw) catch |err| switch (err) {
        error.FileNotFound => return renderNoRolloutFoundForThreadResume(allocator, id_value, object),
        else => return renderJsonRpcErrorForFailure(allocator, id_value, "thread/resume failed to load transcript", err),
    };
    defer transcript.deinit(allocator);

    const resume_path = std.Io.Dir.cwd().realPathFileAlloc(std.Io.Threaded.global_single_threaded.io(), resume_path_raw, allocator) catch |err| switch (err) {
        error.FileNotFound => return renderNoRolloutFoundForThreadResume(allocator, id_value, object),
        else => return err,
    };
    defer allocator.free(resume_path);

    var thread = createLoadedThreadFromResumeParams(allocator, cfg, object, resume_path, &transcript) catch |err| {
        return renderJsonRpcErrorForFailure(allocator, id_value, "thread/resume failed to create thread", err);
    };
    var thread_moved = false;
    errdefer if (!thread_moved) thread.deinit(allocator);
    applyStateResumeMetadata(allocator, cfg.codex_home, object, &thread) catch |err| {
        return renderJsonRpcErrorForFailure(allocator, id_value, "thread/resume failed to apply state metadata", err);
    };

    const include_turns = !(optionalBoolParam(object, "excludeTurns") orelse false);
    const result = try renderThreadLifecycleResponse(allocator, &thread, include_turns);
    defer allocator.free(result);

    const subscription_added = try ensureThreadSubscribed(allocator, state, thread.id);
    var subscription_committed = false;
    errdefer {
        if (subscription_added and !subscription_committed) _ = removeThreadSubscription(allocator, state, thread.id);
    }
    try upsertLoadedThread(allocator, state, thread);
    thread_moved = true;
    subscription_committed = true;
    if (include_turns) try queueThreadTokenUsageNotification(allocator, state, &thread);

    return renderJsonRpcResult(allocator, id_value, result);
}

fn handleThreadFork(
    allocator: std.mem.Allocator,
    state: *AppServerState,
    id_value: std.json.Value,
    params_value: ?std.json.Value,
) ![]const u8 {
    if (validateThreadForkParams(params_value)) |message| {
        return renderJsonRpcError(allocator, id_value, -32602, message);
    }
    const object = parseThreadObjectParams(params_value) catch |err| switch (err) {
        error.InvalidThreadParams => return renderThreadObjectParamsError(allocator, id_value, "thread/fork"),
    };

    var cfg = config.load(allocator) catch |err| {
        return renderJsonRpcErrorForFailure(allocator, id_value, "thread/fork failed to load config", err);
    };
    defer cfg.deinit(allocator);

    if (optionalStringParam(object, "path")) |path| {
        var source = createLoadedThreadFromForkPath(allocator, cfg, object, path) catch |err| switch (err) {
            error.FileNotFound => return renderNoRolloutFoundForThreadResume(allocator, id_value, object),
            else => return renderJsonRpcErrorForFailure(allocator, id_value, "thread/fork failed to load source transcript", err),
        };
        defer source.deinit(allocator);
        return handleThreadForkWithSource(allocator, state, id_value, object, cfg, &source);
    }

    const source_thread_id = requiredThreadIdParam(object) catch |err| switch (err) {
        error.MissingThreadId => return renderJsonRpcError(allocator, id_value, -32602, "threadId must be a string"),
    };
    if (!isUuidString(source_thread_id)) {
        return renderInvalidThreadId(allocator, id_value, source_thread_id);
    }
    if (findLoadedThread(state, source_thread_id)) |source| {
        return handleThreadForkWithSource(allocator, state, id_value, object, cfg, source);
    }

    var stored_source = createStoredThreadFromParamsIncludingArchived(allocator, cfg, object) catch |err| switch (err) {
        error.FileNotFound => return renderThreadNotFound(allocator, id_value, source_thread_id),
        error.InvalidThreadParams => return renderThreadObjectParamsError(allocator, id_value, "thread/fork"),
        else => return renderJsonRpcErrorForFailure(allocator, id_value, "thread/fork failed to load source transcript", err),
    };
    defer stored_source.deinit(allocator);
    return handleThreadForkWithSource(allocator, state, id_value, object, cfg, &stored_source);
}

fn handleThreadForkWithSource(
    allocator: std.mem.Allocator,
    state: *AppServerState,
    id_value: std.json.Value,
    params: std.json.ObjectMap,
    cfg: config.Config,
    source: *const LoadedThread,
) ![]const u8 {
    var thread = createLoadedThreadFromForkParams(allocator, cfg, params, source) catch |err| {
        return renderJsonRpcErrorForFailure(allocator, id_value, "thread/fork failed to create thread", err);
    };
    var thread_moved = false;
    errdefer if (!thread_moved) thread.deinit(allocator);

    const include_turns = !(optionalBoolParam(params, "excludeTurns") orelse false);
    const result = try renderThreadLifecycleResponse(allocator, &thread, include_turns);
    defer allocator.free(result);
    const started_notification = try renderThreadStartedNotification(allocator, &thread);
    var notification_moved = false;
    errdefer if (!notification_moved) allocator.free(started_notification);

    const subscription_added = try ensureThreadSubscribed(allocator, state, thread.id);
    var subscription_committed = false;
    errdefer {
        if (subscription_added and !subscription_committed) _ = removeThreadSubscription(allocator, state, thread.id);
    }
    try state.loaded_threads.append(allocator, thread);
    thread_moved = true;
    subscription_committed = true;
    if (include_turns) try queueThreadTokenUsageNotification(allocator, state, &thread);
    try queueThreadStartedNotification(allocator, state, started_notification);
    notification_moved = true;

    return renderJsonRpcResult(allocator, id_value, result);
}

fn threadStartObjectParams(params_value: ?std.json.Value) ?std.json.ObjectMap {
    const params = params_value orelse return null;
    if (params != .object) return null;
    return params.object;
}

fn threadResumePath(allocator: std.mem.Allocator, codex_home: []const u8, params: std.json.ObjectMap) ![]const u8 {
    if (optionalStringParam(params, "path")) |path| {
        return allocator.dupe(u8, path);
    }
    const thread_id = requiredThreadIdParam(params) catch return error.InvalidThreadParams;
    return session_store.resolveResumePath(allocator, codex_home, thread_id);
}

fn threadResumePathIncludingStateDb(allocator: std.mem.Allocator, codex_home: []const u8, params: std.json.ObjectMap) ![]const u8 {
    const path = try threadResumePath(allocator, codex_home, params);
    errdefer allocator.free(path);
    if (optionalStringParam(params, "path") != null) return path;

    const io = std.Io.Threaded.global_single_threaded.io();
    _ = std.Io.Dir.cwd().statFile(io, path, .{ .follow_symlinks = true }) catch |err| switch (err) {
        error.FileNotFound => {
            const thread_id = requiredThreadIdParam(params) catch return error.InvalidThreadParams;
            const state_path = (try thread_state.findRolloutPathByThreadId(allocator, codex_home, thread_id)) orelse return path;
            allocator.free(path);
            return state_path;
        },
        else => return path,
    };
    return path;
}

fn createStoredThreadFromParams(
    allocator: std.mem.Allocator,
    cfg: config.Config,
    params: std.json.ObjectMap,
) !LoadedThread {
    const resume_path_raw = try threadResumePath(allocator, cfg.codex_home, params);
    defer allocator.free(resume_path_raw);

    return createStoredThreadFromPath(allocator, cfg, params, resume_path_raw);
}

fn createStoredThreadFromParamsIncludingStateDb(
    allocator: std.mem.Allocator,
    cfg: config.Config,
    params: std.json.ObjectMap,
) !LoadedThread {
    return createStoredThreadFromParams(allocator, cfg, params) catch |err| switch (err) {
        error.FileNotFound => createStateDbStoredThreadFromParams(allocator, cfg, params),
        else => err,
    };
}

fn createStoredThreadFromParamsIncludingArchived(
    allocator: std.mem.Allocator,
    cfg: config.Config,
    params: std.json.ObjectMap,
) !LoadedThread {
    return createStoredThreadFromParams(allocator, cfg, params) catch |err| switch (err) {
        error.FileNotFound => createArchivedOrStateDbStoredThreadFromParams(allocator, cfg, params),
        else => err,
    };
}

fn createArchivedOrStateDbStoredThreadFromParams(
    allocator: std.mem.Allocator,
    cfg: config.Config,
    params: std.json.ObjectMap,
) !LoadedThread {
    return createArchivedStoredThreadFromParams(allocator, cfg, params) catch |err| switch (err) {
        error.FileNotFound => createStateDbStoredThreadFromParams(allocator, cfg, params),
        else => err,
    };
}

fn createArchivedStoredThreadFromParams(
    allocator: std.mem.Allocator,
    cfg: config.Config,
    params: std.json.ObjectMap,
) !LoadedThread {
    const thread_id = requiredThreadIdParam(params) catch return error.InvalidThreadParams;
    const archived_path = try session_store.resolveArchivedRolloutPath(allocator, cfg.codex_home, thread_id);
    defer allocator.free(archived_path);
    return createStoredThreadFromPath(allocator, cfg, params, archived_path);
}

fn createStateDbStoredThreadFromParams(
    allocator: std.mem.Allocator,
    cfg: config.Config,
    params: std.json.ObjectMap,
) !LoadedThread {
    const thread_id = requiredThreadIdParam(params) catch return error.InvalidThreadParams;
    const state_path = (try thread_state.findRolloutPathByThreadId(allocator, cfg.codex_home, thread_id)) orelse return error.FileNotFound;
    defer allocator.free(state_path);
    var thread = try createStoredThreadFromPath(allocator, cfg, params, state_path);
    errdefer thread.deinit(allocator);
    const metadata = try thread_state.findThreadMetadataByThreadId(allocator, cfg.codex_home, thread_id);
    defer if (metadata) |value| value.deinit(allocator);
    if (metadata) |value| try applyStateThreadMetadata(allocator, &thread, value);
    return thread;
}

fn createStoredThreadFromPath(
    allocator: std.mem.Allocator,
    cfg: config.Config,
    params: std.json.ObjectMap,
    path_raw: []const u8,
) !LoadedThread {
    var transcript = try session_store.loadTranscript(allocator, path_raw);
    defer transcript.deinit(allocator);

    const resume_path = try std.Io.Dir.cwd().realPathFileAlloc(std.Io.Threaded.global_single_threaded.io(), path_raw, allocator);
    defer allocator.free(resume_path);

    var thread = try createLoadedThreadFromResumeParams(allocator, cfg, params, resume_path, &transcript);
    errdefer thread.deinit(allocator);
    try applyIndexedThreadName(allocator, cfg.codex_home, &thread);
    return thread;
}

fn applyIndexedThreadName(allocator: std.mem.Allocator, codex_home: []const u8, thread: *LoadedThread) !void {
    const indexed_name = try session_store.findThreadName(allocator, codex_home, thread.id);
    defer if (indexed_name) |value| allocator.free(value);
    const name = indexed_name orelse return;
    const name_copy = try allocator.dupe(u8, name);
    if (thread.name) |value| allocator.free(value);
    thread.name = name_copy;
}

const StateThreadMetadataApplyOptions = struct {
    apply_model_runtime: bool = true,
    apply_cwd: bool = true,
};

fn applyStateThreadMetadata(allocator: std.mem.Allocator, thread: *LoadedThread, metadata: thread_state.ThreadMetadata) !void {
    try applyStateThreadMetadataWithOptions(allocator, thread, metadata, .{});
}

fn applyStateResumeMetadata(
    allocator: std.mem.Allocator,
    codex_home: []const u8,
    params: std.json.ObjectMap,
    thread: *LoadedThread,
) !void {
    const metadata = try thread_state.findThreadMetadataByThreadId(allocator, codex_home, thread.id);
    defer if (metadata) |value| value.deinit(allocator);
    if (metadata) |value| {
        try applyStateThreadMetadataWithOptions(allocator, thread, value, .{
            .apply_model_runtime = !threadResumeHasModelRuntimeOverride(params),
            .apply_cwd = optionalStringParam(params, "cwd") == null,
        });
    }
}

fn applyStateThreadMetadataWithOptions(
    allocator: std.mem.Allocator,
    thread: *LoadedThread,
    metadata: thread_state.ThreadMetadata,
    options: StateThreadMetadataApplyOptions,
) !void {
    if (stateThreadString(metadata.first_user_message)) |preview| {
        try replaceOwnedString(allocator, &thread.preview, preview);
    }
    if (stateThreadTitle(metadata.title, thread.preview)) |title| {
        try replaceOptionalOwnedString(allocator, &thread.name, title);
    }
    if (metadata.memory_mode) |memory_mode| {
        try thread.transcript.setMemoryMode(allocator, memory_mode);
    }
    if (options.apply_model_runtime) {
        if (stateThreadString(metadata.model)) |model| {
            try replaceOwnedString(allocator, &thread.model, model);
            thread.runtime_overrides.model = true;
        }
        if (stateThreadString(metadata.model_provider)) |model_provider| {
            try replaceOwnedString(allocator, &thread.model_provider, model_provider);
            try thread.transcript.setModelProvider(allocator, model_provider);
            thread.runtime_overrides.model_provider = true;
        }
        if (stateThreadReasoningEffort(metadata.reasoning_effort)) |reasoning_effort| {
            try replaceOptionalOwnedString(allocator, &thread.reasoning_effort, reasoning_effort);
            thread.runtime_overrides.reasoning_effort = true;
        }
    }
    if (options.apply_cwd) {
        if (stateThreadString(metadata.cwd)) |cwd| {
            try replaceOwnedString(allocator, &thread.cwd, cwd);
            try thread.transcript.setCwd(allocator, cwd);
        }
    }
    if (stateThreadString(metadata.cli_version)) |cli_version| {
        try replaceOwnedString(allocator, &thread.cli_version, cli_version);
        try thread.transcript.setCliVersion(allocator, cli_version);
    }
    if (metadata.lifecycle_loaded) {
        if (metadata.created_at_ms) |value| thread.created_at = @divFloor(value, 1000);
        if (metadata.updated_at_ms) |value| thread.updated_at = @divFloor(value, 1000);
        if (metadata.source) |source| {
            try replaceOwnedString(allocator, &thread.source, source);
            try thread.transcript.setSource(allocator, source);
        }
        if (metadata.thread_source) |thread_source| {
            try replaceOptionalOwnedString(allocator, &thread.thread_source, thread_source);
            try thread.transcript.setThreadSource(allocator, thread_source);
        } else {
            clearOptionalOwnedString(allocator, &thread.thread_source);
        }
        if (metadata.agent_nickname) |agent_nickname| {
            try replaceOptionalOwnedString(allocator, &thread.agent_nickname, agent_nickname);
        } else {
            clearOptionalOwnedString(allocator, &thread.agent_nickname);
        }
        if (metadata.agent_role) |agent_role| {
            try replaceOptionalOwnedString(allocator, &thread.agent_role, agent_role);
        } else {
            clearOptionalOwnedString(allocator, &thread.agent_role);
        }
    }
    try replaceStateMetadataGitInfo(allocator, &thread.git_sha, metadata.git_sha);
    try replaceStateMetadataGitInfo(allocator, &thread.git_branch, metadata.git_branch);
    try replaceStateMetadataGitInfo(allocator, &thread.git_origin_url, metadata.git_origin_url);
    try syncLoadedThreadGitInfoToTranscript(allocator, thread);
}

fn threadResumeHasModelRuntimeOverride(params: std.json.ObjectMap) bool {
    if (optionalStringParam(params, "model") != null) return true;
    if (optionalStringParam(params, "modelProvider") != null) return true;
    const config_value = params.get("config") orelse return false;
    if (config_value != .object) return false;
    return config_value.object.get("model") != null or
        config_value.object.get("model_provider") != null or
        config_value.object.get("model_reasoning_effort") != null;
}

fn replaceStateMetadataGitInfo(allocator: std.mem.Allocator, slot: *?[]const u8, value: ?[]const u8) !void {
    if (value) |text| {
        try replaceOptionalOwnedString(allocator, slot, text);
    } else {
        clearOptionalOwnedString(allocator, slot);
    }
}

fn createLoadedThreadFromStartParams(
    allocator: std.mem.Allocator,
    cfg: config.Config,
    params: ?std.json.ObjectMap,
) !LoadedThread {
    const thread_id = try generateUuidString(allocator);
    errdefer allocator.free(thread_id);
    const session_id = try allocator.dupe(u8, thread_id);
    errdefer allocator.free(session_id);
    const preview = try allocator.dupe(u8, "");
    errdefer allocator.free(preview);
    const source = try allocator.dupe(u8, "appServer");
    errdefer allocator.free(source);
    const cli_version = try allocator.dupe(u8, "0.0.1");
    errdefer allocator.free(cli_version);
    const turns_json = try allocator.dupe(u8, "[]");
    errdefer allocator.free(turns_json);

    const model = try allocator.dupe(u8, optionalStringParam(params, "model") orelse cfg.model);
    errdefer allocator.free(model);

    const configured_model_provider = try config.loadModelProviderId(allocator, cfg.active_profile);
    defer if (configured_model_provider) |value| allocator.free(value);
    const model_provider = try allocator.dupe(u8, optionalStringParam(params, "modelProvider") orelse configured_model_provider orelse "openai");
    errdefer allocator.free(model_provider);

    const service_tier = try threadStartServiceTier(allocator, cfg, params);
    errdefer if (service_tier) |value| allocator.free(value);

    const cwd = try threadStartCwd(allocator, params);
    errdefer allocator.free(cwd);

    const approval_policy = try allocator.dupe(u8, optionalStringParam(params, "approvalPolicy") orelse cfg.approval_policy.label());
    errdefer allocator.free(approval_policy);

    const approvals_reviewer = try allocator.dupe(u8, optionalStringParam(params, "approvalsReviewer") orelse "user");
    errdefer allocator.free(approvals_reviewer);

    const sandbox_mode = try allocator.dupe(u8, optionalStringParam(params, "sandbox") orelse cfg.sandbox_mode.label());
    errdefer allocator.free(sandbox_mode);

    const reasoning_effort = if (cfg.model_reasoning_effort) |effort|
        try allocator.dupe(u8, effort.label())
    else
        null;
    errdefer if (reasoning_effort) |value| allocator.free(value);

    const ephemeral = optionalBoolParam(params, "ephemeral") orelse false;
    const path = if (ephemeral)
        null
    else
        try session_store.createSessionPathForId(allocator, cfg.codex_home, thread_id);
    errdefer if (path) |value| allocator.free(value);

    const thread_source = if (optionalStringParam(params, "threadSource")) |value|
        try allocator.dupe(u8, value)
    else
        null;
    errdefer if (thread_source) |value| allocator.free(value);

    var transcript = session_mod.Transcript{};
    errdefer transcript.deinit(allocator);
    try transcript.setId(allocator, thread_id);
    try transcript.setSource(allocator, source);
    try transcript.setModelProvider(allocator, model_provider);
    try transcript.setCwd(allocator, cwd);
    try transcript.setCliVersion(allocator, cli_version);
    if (thread_source) |value| try transcript.setThreadSource(allocator, value);

    const now = currentUnixSeconds();
    return .{
        .id = thread_id,
        .session_id = session_id,
        .forked_from_id = null,
        .preview = preview,
        .model = model,
        .model_provider = model_provider,
        .service_tier = service_tier,
        .cwd = cwd,
        .approval_policy = approval_policy,
        .approvals_reviewer = approvals_reviewer,
        .sandbox_mode = sandbox_mode,
        .reasoning_effort = reasoning_effort,
        .runtime_overrides = .{
            .model = paramPresent(params, "model"),
            .model_provider = paramPresent(params, "modelProvider"),
            .service_tier = paramPresent(params, "serviceTier"),
            .approval_policy = paramPresent(params, "approvalPolicy"),
            .sandbox_mode = paramPresent(params, "sandbox"),
        },
        .ephemeral = ephemeral,
        .path = path,
        .source = source,
        .thread_source = thread_source,
        .agent_nickname = null,
        .agent_role = null,
        .cli_version = cli_version,
        .token_usage = null,
        .token_usage_turn_id = null,
        .name = null,
        .elicitation_count = 0,
        .git_sha = null,
        .git_branch = null,
        .git_origin_url = null,
        .goal = null,
        .transcript = transcript,
        .turns_json = turns_json,
        .created_at = now,
        .updated_at = now,
    };
}

fn createLoadedThreadFromHistoryParams(
    allocator: std.mem.Allocator,
    cfg: config.Config,
    params: std.json.ObjectMap,
    history: []const std.json.Value,
) !LoadedThread {
    var transcript = try transcriptFromResponseHistory(allocator, history);
    errdefer transcript.deinit(allocator);

    const thread_id = try generateUuidString(allocator);
    errdefer allocator.free(thread_id);
    const session_id = try allocator.dupe(u8, thread_id);
    errdefer allocator.free(session_id);
    const preview = try resumePreview(allocator, &transcript);
    errdefer allocator.free(preview);
    const source = try allocator.dupe(u8, "appServer");
    errdefer allocator.free(source);
    const cli_version = try allocator.dupe(u8, "0.0.1");
    errdefer allocator.free(cli_version);
    const turns_json = try renderTranscriptTurnsJson(allocator, &transcript, true);
    errdefer allocator.free(turns_json);

    const model = try allocator.dupe(u8, optionalStringParam(params, "model") orelse cfg.model);
    errdefer allocator.free(model);

    const configured_model_provider = try config.loadModelProviderId(allocator, cfg.active_profile);
    defer if (configured_model_provider) |value| allocator.free(value);
    const model_provider = try allocator.dupe(u8, optionalStringParam(params, "modelProvider") orelse configured_model_provider orelse "openai");
    errdefer allocator.free(model_provider);

    const service_tier = try threadStartServiceTier(allocator, cfg, params);
    errdefer if (service_tier) |value| allocator.free(value);

    const cwd = try threadStartCwd(allocator, params);
    errdefer allocator.free(cwd);

    const approval_policy = try allocator.dupe(u8, optionalStringParam(params, "approvalPolicy") orelse cfg.approval_policy.label());
    errdefer allocator.free(approval_policy);

    const approvals_reviewer = try allocator.dupe(u8, optionalStringParam(params, "approvalsReviewer") orelse "user");
    errdefer allocator.free(approvals_reviewer);

    const sandbox_mode = try allocator.dupe(u8, optionalStringParam(params, "sandbox") orelse cfg.sandbox_mode.label());
    errdefer allocator.free(sandbox_mode);

    const reasoning_effort = if (cfg.model_reasoning_effort) |effort|
        try allocator.dupe(u8, effort.label())
    else
        null;
    errdefer if (reasoning_effort) |value| allocator.free(value);

    const path = try session_store.createSessionPathForId(allocator, cfg.codex_home, thread_id);
    errdefer allocator.free(path);

    const now = currentUnixSeconds();
    try transcript.setId(allocator, thread_id);
    try transcript.setSource(allocator, source);
    try transcript.setModelProvider(allocator, model_provider);
    try transcript.setCwd(allocator, cwd);
    try transcript.setCliVersion(allocator, cli_version);

    return .{
        .id = thread_id,
        .session_id = session_id,
        .forked_from_id = null,
        .preview = preview,
        .model = model,
        .model_provider = model_provider,
        .service_tier = service_tier,
        .cwd = cwd,
        .approval_policy = approval_policy,
        .approvals_reviewer = approvals_reviewer,
        .sandbox_mode = sandbox_mode,
        .reasoning_effort = reasoning_effort,
        .runtime_overrides = .{
            .model = paramPresent(params, "model"),
            .model_provider = paramPresent(params, "modelProvider"),
            .service_tier = paramPresent(params, "serviceTier"),
            .approval_policy = paramPresent(params, "approvalPolicy"),
            .sandbox_mode = paramPresent(params, "sandbox"),
        },
        .ephemeral = false,
        .path = path,
        .source = source,
        .thread_source = null,
        .agent_nickname = null,
        .agent_role = null,
        .cli_version = cli_version,
        .token_usage = null,
        .token_usage_turn_id = null,
        .name = null,
        .elicitation_count = 0,
        .git_sha = null,
        .git_branch = null,
        .git_origin_url = null,
        .goal = null,
        .transcript = transcript,
        .turns_json = turns_json,
        .created_at = now,
        .updated_at = now,
    };
}

fn createLoadedThreadFromResumeParams(
    allocator: std.mem.Allocator,
    cfg: config.Config,
    params: std.json.ObjectMap,
    path: []const u8,
    transcript: *const session_mod.Transcript,
) !LoadedThread {
    const thread_id = if (transcript.id) |value|
        try allocator.dupe(u8, value)
    else
        try session_store.sessionIdFromPath(allocator, path);
    errdefer allocator.free(thread_id);
    const session_id = try allocator.dupe(u8, thread_id);
    errdefer allocator.free(session_id);
    const forked_from_id = if (transcript.forked_from_id) |value|
        try allocator.dupe(u8, value)
    else
        null;
    errdefer if (forked_from_id) |value| allocator.free(value);
    const preview = try resumePreview(allocator, transcript);
    errdefer allocator.free(preview);
    const path_copy = try allocator.dupe(u8, path);
    errdefer allocator.free(path_copy);
    const source = try allocator.dupe(u8, transcript.source orelse "cli");
    errdefer allocator.free(source);
    const thread_source = if (transcript.thread_source) |value| try allocator.dupe(u8, value) else null;
    errdefer if (thread_source) |value| allocator.free(value);
    const cli_version = try allocator.dupe(u8, transcript.cli_version orelse "0.0.1");
    errdefer allocator.free(cli_version);
    const token_usage_turn_id = try transcriptTokenUsageTurnId(allocator, transcript);
    errdefer if (token_usage_turn_id) |value| allocator.free(value);
    const name = if (transcript.title) |title| try allocator.dupe(u8, title) else null;
    errdefer if (name) |value| allocator.free(value);
    const git_sha = if (transcript.git_sha) |value| try allocator.dupe(u8, value) else null;
    errdefer if (git_sha) |value| allocator.free(value);
    const git_branch = if (transcript.git_branch) |value| try allocator.dupe(u8, value) else null;
    errdefer if (git_branch) |value| allocator.free(value);
    const git_origin_url = if (transcript.git_origin_url) |value| try allocator.dupe(u8, value) else null;
    errdefer if (git_origin_url) |value| allocator.free(value);
    const turns_json = try renderTranscriptTurnsJson(allocator, transcript, true);
    errdefer allocator.free(turns_json);
    var transcript_copy = try transcript.clone(allocator);
    errdefer transcript_copy.deinit(allocator);

    const model = try allocator.dupe(u8, optionalStringParam(params, "model") orelse cfg.model);
    errdefer allocator.free(model);

    const configured_model_provider = try config.loadModelProviderId(allocator, cfg.active_profile);
    defer if (configured_model_provider) |value| allocator.free(value);
    const model_provider = try allocator.dupe(u8, optionalStringParam(params, "modelProvider") orelse transcript.model_provider orelse configured_model_provider orelse "openai");
    errdefer allocator.free(model_provider);

    const service_tier = try threadStartServiceTier(allocator, cfg, params);
    errdefer if (service_tier) |value| allocator.free(value);

    const cwd = try threadResumeCwd(allocator, transcript, params);
    errdefer allocator.free(cwd);

    const approval_policy = try allocator.dupe(u8, optionalStringParam(params, "approvalPolicy") orelse cfg.approval_policy.label());
    errdefer allocator.free(approval_policy);

    const approvals_reviewer = try allocator.dupe(u8, optionalStringParam(params, "approvalsReviewer") orelse "user");
    errdefer allocator.free(approvals_reviewer);

    const sandbox_mode = try allocator.dupe(u8, optionalStringParam(params, "sandbox") orelse cfg.sandbox_mode.label());
    errdefer allocator.free(sandbox_mode);

    const reasoning_effort = if (cfg.model_reasoning_effort) |effort|
        try allocator.dupe(u8, effort.label())
    else
        null;
    errdefer if (reasoning_effort) |value| allocator.free(value);

    const now = currentUnixSeconds();
    return .{
        .id = thread_id,
        .session_id = session_id,
        .forked_from_id = forked_from_id,
        .preview = preview,
        .model = model,
        .model_provider = model_provider,
        .service_tier = service_tier,
        .cwd = cwd,
        .approval_policy = approval_policy,
        .approvals_reviewer = approvals_reviewer,
        .sandbox_mode = sandbox_mode,
        .reasoning_effort = reasoning_effort,
        .runtime_overrides = .{
            .model = paramPresent(params, "model"),
            .model_provider = paramPresent(params, "modelProvider") or transcript.model_provider != null,
            .service_tier = paramPresent(params, "serviceTier"),
            .approval_policy = paramPresent(params, "approvalPolicy"),
            .sandbox_mode = paramPresent(params, "sandbox"),
        },
        .ephemeral = false,
        .path = path_copy,
        .source = source,
        .thread_source = thread_source,
        .agent_nickname = null,
        .agent_role = null,
        .cli_version = cli_version,
        .token_usage = transcript.token_usage,
        .token_usage_turn_id = token_usage_turn_id,
        .name = name,
        .elicitation_count = 0,
        .git_sha = git_sha,
        .git_branch = git_branch,
        .git_origin_url = git_origin_url,
        .goal = null,
        .transcript = transcript_copy,
        .turns_json = turns_json,
        .created_at = now,
        .updated_at = now,
    };
}

fn createLoadedThreadFromForkPath(
    allocator: std.mem.Allocator,
    cfg: config.Config,
    params: std.json.ObjectMap,
    path_raw: []const u8,
) !LoadedThread {
    var transcript = try session_store.loadTranscript(allocator, path_raw);
    defer transcript.deinit(allocator);

    const path = try std.Io.Dir.cwd().realPathFileAlloc(std.Io.Threaded.global_single_threaded.io(), path_raw, allocator);
    defer allocator.free(path);

    return createLoadedThreadFromResumeParams(allocator, cfg, params, path, &transcript);
}

fn createLoadedThreadFromForkParams(
    allocator: std.mem.Allocator,
    cfg: config.Config,
    params: std.json.ObjectMap,
    source: *const LoadedThread,
) !LoadedThread {
    const thread_id = try generateUuidString(allocator);
    errdefer allocator.free(thread_id);
    const session_id = try allocator.dupe(u8, thread_id);
    errdefer allocator.free(session_id);
    const forked_from_id = try allocator.dupe(u8, source.id);
    errdefer allocator.free(forked_from_id);
    const preview = try allocator.dupe(u8, source.preview);
    errdefer allocator.free(preview);
    const source_label = try allocator.dupe(u8, "appServer");
    errdefer allocator.free(source_label);
    const cli_version = try allocator.dupe(u8, "0.0.1");
    errdefer allocator.free(cli_version);
    const token_usage_turn_id = if (source.token_usage_turn_id) |value| try allocator.dupe(u8, value) else null;
    errdefer if (token_usage_turn_id) |value| allocator.free(value);
    const git_sha = if (source.git_sha) |value| try allocator.dupe(u8, value) else null;
    errdefer if (git_sha) |value| allocator.free(value);
    const git_branch = if (source.git_branch) |value| try allocator.dupe(u8, value) else null;
    errdefer if (git_branch) |value| allocator.free(value);
    const git_origin_url = if (source.git_origin_url) |value| try allocator.dupe(u8, value) else null;
    errdefer if (git_origin_url) |value| allocator.free(value);
    const turns_json = try allocator.dupe(u8, source.turns_json);
    errdefer allocator.free(turns_json);
    var transcript = try source.transcript.clone(allocator);
    errdefer transcript.deinit(allocator);

    const model = try allocator.dupe(u8, optionalStringParam(params, "model") orelse source.model);
    errdefer allocator.free(model);

    const model_provider = try allocator.dupe(u8, optionalStringParam(params, "modelProvider") orelse source.model_provider);
    errdefer allocator.free(model_provider);

    const service_tier = try lifecycleServiceTier(allocator, source.service_tier, params);
    errdefer if (service_tier) |value| allocator.free(value);

    const cwd = if (optionalStringParam(params, "cwd")) |value|
        try realPathFileAllocPlain(allocator, value)
    else
        try allocator.dupe(u8, source.cwd);
    errdefer allocator.free(cwd);

    const approval_policy = try allocator.dupe(u8, optionalStringParam(params, "approvalPolicy") orelse source.approval_policy);
    errdefer allocator.free(approval_policy);

    const approvals_reviewer = try allocator.dupe(u8, optionalStringParam(params, "approvalsReviewer") orelse source.approvals_reviewer);
    errdefer allocator.free(approvals_reviewer);

    const sandbox_mode = try allocator.dupe(u8, optionalStringParam(params, "sandbox") orelse source.sandbox_mode);
    errdefer allocator.free(sandbox_mode);

    const reasoning_effort = if (source.reasoning_effort) |value|
        try allocator.dupe(u8, value)
    else
        null;
    errdefer if (reasoning_effort) |value| allocator.free(value);

    const ephemeral = optionalBoolParam(params, "ephemeral") orelse false;
    const path = if (ephemeral)
        null
    else
        try session_store.createSessionPathForId(allocator, cfg.codex_home, thread_id);
    errdefer if (path) |value| allocator.free(value);

    const thread_source = if (optionalStringParam(params, "threadSource")) |value|
        try allocator.dupe(u8, value)
    else
        null;
    errdefer if (thread_source) |value| allocator.free(value);

    const now = currentUnixSeconds();
    try transcript.setId(allocator, thread_id);
    try transcript.setForkedFromId(allocator, source.id);
    try transcript.setSource(allocator, source_label);
    try transcript.setModelProvider(allocator, model_provider);
    try transcript.setCwd(allocator, cwd);
    try transcript.setCliVersion(allocator, cli_version);
    if (thread_source) |value| try transcript.setThreadSource(allocator, value);

    return .{
        .id = thread_id,
        .session_id = session_id,
        .forked_from_id = forked_from_id,
        .preview = preview,
        .model = model,
        .model_provider = model_provider,
        .service_tier = service_tier,
        .cwd = cwd,
        .approval_policy = approval_policy,
        .approvals_reviewer = approvals_reviewer,
        .sandbox_mode = sandbox_mode,
        .reasoning_effort = reasoning_effort,
        .runtime_overrides = .{
            .model = paramPresent(params, "model") or source.runtime_overrides.model,
            .model_provider = paramPresent(params, "modelProvider") or source.runtime_overrides.model_provider,
            .service_tier = paramPresent(params, "serviceTier") or source.runtime_overrides.service_tier,
            .approval_policy = paramPresent(params, "approvalPolicy") or source.runtime_overrides.approval_policy,
            .sandbox_mode = paramPresent(params, "sandbox") or source.runtime_overrides.sandbox_mode,
            .reasoning_effort = source.runtime_overrides.reasoning_effort,
        },
        .ephemeral = ephemeral,
        .path = path,
        .source = source_label,
        .thread_source = thread_source,
        .agent_nickname = null,
        .agent_role = null,
        .cli_version = cli_version,
        .token_usage = source.token_usage,
        .token_usage_turn_id = token_usage_turn_id,
        .name = null,
        .elicitation_count = 0,
        .git_sha = git_sha,
        .git_branch = git_branch,
        .git_origin_url = git_origin_url,
        .goal = null,
        .transcript = transcript,
        .turns_json = turns_json,
        .created_at = now,
        .updated_at = now,
    };
}

fn threadStartServiceTier(
    allocator: std.mem.Allocator,
    cfg: config.Config,
    params: ?std.json.ObjectMap,
) !?[]const u8 {
    if (params) |object| {
        if (object.get("serviceTier")) |value| {
            if (value == .null) return null;
            return try allocator.dupe(u8, value.string);
        }
    }
    if (cfg.service_tier) |value| return try allocator.dupe(u8, value);
    return null;
}

fn lifecycleServiceTier(
    allocator: std.mem.Allocator,
    default_value: ?[]const u8,
    params: std.json.ObjectMap,
) !?[]const u8 {
    if (params.get("serviceTier")) |value| {
        if (value == .null) return null;
        return try allocator.dupe(u8, value.string);
    }
    if (default_value) |value| return try allocator.dupe(u8, value);
    return null;
}

fn resumePreview(allocator: std.mem.Allocator, transcript: *const session_mod.Transcript) ![]const u8 {
    for (transcript.history.items) |item| {
        if (item.kind == .message and item.text != null) {
            if (item.role) |role| {
                if (std.mem.eql(u8, role, "user")) return allocator.dupe(u8, item.text.?);
            }
        }
    }
    for (transcript.history.items) |item| {
        if (item.kind == .message and item.text != null) return allocator.dupe(u8, item.text.?);
    }
    return allocator.dupe(u8, "");
}

fn transcriptTokenUsageTurnId(allocator: std.mem.Allocator, transcript: *const session_mod.Transcript) !?[]const u8 {
    if (transcript.token_usage == null) return null;
    const turn_index = transcript.token_usage_turn_index orelse return null;
    const rendered_turn_index = if (transcriptHasExternalAgentImportedMarker(transcript))
        groupedTurnIndexForMessageTurnIndex(transcript, turn_index) orelse turn_index
    else
        turn_index;
    const turn_id = try std.fmt.allocPrint(allocator, "turn-{d}", .{rendered_turn_index});
    return turn_id;
}

fn transcriptFromResponseHistory(allocator: std.mem.Allocator, history: []const std.json.Value) !session_mod.Transcript {
    return session_mod.transcriptFromResponseHistory(allocator, history);
}

fn renderTranscriptTurnsJson(allocator: std.mem.Allocator, transcript: *const session_mod.Transcript, include_turns: bool) ![]const u8 {
    if (!include_turns) return allocator.dupe(u8, "[]");
    if (transcriptHasExternalAgentImportedMarker(transcript)) return renderGroupedTranscriptTurnsJson(allocator, transcript);

    var out = std.ArrayList(u8).empty;
    errdefer out.deinit(allocator);
    try out.append(allocator, '[');
    var turn_index: usize = 0;
    for (transcript.history.items, 0..) |item, item_index| {
        if (item.kind != .message) continue;
        if (turn_index > 0) try out.append(allocator, ',');
        try out.appendSlice(allocator, "{\"id\":\"turn-");
        try appendUsize(allocator, &out, turn_index);
        try out.appendSlice(allocator, "\",\"items\":[");
        try appendHistoryMessageThreadItemJson(allocator, &out, item, item_index);
        try out.appendSlice(allocator, "],\"itemsView\":\"full\",\"status\":\"completed\",\"error\":null,\"startedAt\":null,\"completedAt\":null,\"durationMs\":null}");
        turn_index += 1;
    }
    try out.append(allocator, ']');
    return out.toOwnedSlice(allocator);
}

fn renderGroupedTranscriptTurnsJson(allocator: std.mem.Allocator, transcript: *const session_mod.Transcript) ![]const u8 {
    var out = std.ArrayList(u8).empty;
    errdefer out.deinit(allocator);
    try out.append(allocator, '[');

    var turn_index: usize = 0;
    var turn_open = false;
    var turn_item_count: usize = 0;
    for (transcript.history.items, 0..) |item, item_index| {
        if (item.kind != .message) continue;
        if (turn_open and turn_item_count > 0 and historyItemIsUserMessage(item)) {
            try out.appendSlice(allocator, "],\"itemsView\":\"full\",\"status\":\"completed\",\"error\":null,\"startedAt\":null,\"completedAt\":null,\"durationMs\":null}");
            turn_open = false;
            turn_item_count = 0;
            turn_index += 1;
        }

        if (!turn_open) {
            if (turn_index > 0) try out.append(allocator, ',');
            try out.appendSlice(allocator, "{\"id\":\"turn-");
            try appendUsize(allocator, &out, turn_index);
            try out.appendSlice(allocator, "\",\"items\":[");
            turn_open = true;
        } else if (turn_item_count > 0) {
            try out.append(allocator, ',');
        }

        try appendHistoryMessageThreadItemJson(allocator, &out, item, item_index);
        turn_item_count += 1;
    }

    if (turn_open) {
        try out.appendSlice(allocator, "],\"itemsView\":\"full\",\"status\":\"completed\",\"error\":null,\"startedAt\":null,\"completedAt\":null,\"durationMs\":null}");
    }
    try out.append(allocator, ']');
    return out.toOwnedSlice(allocator);
}

fn transcriptHasExternalAgentImportedMarker(transcript: *const session_mod.Transcript) bool {
    for (transcript.history.items) |item| {
        if (item.kind != .message) continue;
        if (item.text) |text| {
            if (std.mem.eql(u8, text, session_store.external_agent_session_imported_marker)) return true;
        }
    }
    return false;
}

fn historyItemIsUserMessage(item: api.HistoryItem) bool {
    if (item.role) |role| return std.mem.eql(u8, role, "user");
    return false;
}

fn groupedTurnIndexForMessageTurnIndex(transcript: *const session_mod.Transcript, target_message_turn_index: usize) ?usize {
    var message_turn_index: usize = 0;
    var grouped_turn_index: usize = 0;
    var turn_has_items = false;
    for (transcript.history.items) |item| {
        if (item.kind != .message) continue;
        if (turn_has_items and historyItemIsUserMessage(item)) {
            grouped_turn_index += 1;
        }
        if (message_turn_index == target_message_turn_index) return grouped_turn_index;
        turn_has_items = true;
        message_turn_index += 1;
    }
    return null;
}

fn appendHistoryMessageThreadItemJson(allocator: std.mem.Allocator, out: *std.ArrayList(u8), item: api.HistoryItem, index: usize) !void {
    const text = item.text orelse "";
    const role = item.role orelse "";
    try out.appendSlice(allocator, "{\"type\":");
    if (std.mem.eql(u8, role, "assistant")) {
        try appendJsonString(allocator, out, "agentMessage");
        try out.appendSlice(allocator, ",\"id\":\"item-");
        try appendUsize(allocator, out, index);
        try out.appendSlice(allocator, "\",\"text\":");
        try appendJsonString(allocator, out, text);
        try out.appendSlice(allocator, ",\"phase\":null,\"memoryCitation\":null}");
    } else {
        try appendJsonString(allocator, out, "userMessage");
        try out.appendSlice(allocator, ",\"id\":\"item-");
        try appendUsize(allocator, out, index);
        try out.appendSlice(allocator, "\",\"content\":[{\"type\":\"text\",\"text\":");
        try appendJsonString(allocator, out, text);
        try out.appendSlice(allocator, ",\"text_elements\":[]}]}");
    }
}

fn appendUsize(allocator: std.mem.Allocator, out: *std.ArrayList(u8), value: usize) !void {
    const text = try std.fmt.allocPrint(allocator, "{d}", .{value});
    defer allocator.free(text);
    try out.appendSlice(allocator, text);
}

fn threadStartCwd(allocator: std.mem.Allocator, params: ?std.json.ObjectMap) ![]const u8 {
    const cwd = optionalStringParam(params, "cwd") orelse ".";
    return realPathFileAllocPlain(allocator, cwd);
}

fn threadResumeCwd(
    allocator: std.mem.Allocator,
    transcript: *const session_mod.Transcript,
    params: std.json.ObjectMap,
) ![]const u8 {
    if (optionalStringParam(params, "cwd")) |cwd| {
        return realPathFileAllocPlain(allocator, cwd);
    }
    if (transcript.cwd) |cwd| return allocator.dupe(u8, cwd);
    return threadStartCwd(allocator, params);
}

fn realPathFileAllocPlain(allocator: std.mem.Allocator, path: []const u8) ![]const u8 {
    const real_path = try std.Io.Dir.cwd().realPathFileAlloc(std.Io.Threaded.global_single_threaded.io(), path, allocator);
    defer allocator.free(real_path);
    return allocator.dupe(u8, real_path);
}

fn optionalStringParam(params: ?std.json.ObjectMap, name: []const u8) ?[]const u8 {
    const object = params orelse return null;
    const value = object.get(name) orelse return null;
    if (value == .null) return null;
    return value.string;
}

fn optionalBoolParam(params: ?std.json.ObjectMap, name: []const u8) ?bool {
    const object = params orelse return null;
    const value = object.get(name) orelse return null;
    if (value == .null) return null;
    return value.bool;
}

fn paramPresent(params: ?std.json.ObjectMap, name: []const u8) bool {
    const object = params orelse return false;
    return object.get(name) != null;
}

fn optionalJsonParam(params: std.json.ObjectMap, name: []const u8) ?std.json.Value {
    const value = params.get(name) orelse return null;
    if (value == .null) return null;
    return value;
}

fn replaceOwnedString(allocator: std.mem.Allocator, slot: *[]const u8, value: []const u8) !void {
    const copy = try allocator.dupe(u8, value);
    allocator.free(slot.*);
    slot.* = copy;
}

fn generateUuidString(allocator: std.mem.Allocator) ![]const u8 {
    var bytes: [16]u8 = undefined;
    std.Io.Threaded.global_single_threaded.io().random(&bytes);
    bytes[6] = (bytes[6] & 0x0f) | 0x40;
    bytes[8] = (bytes[8] & 0x3f) | 0x80;

    const hex = "0123456789abcdef";
    var out = try allocator.alloc(u8, 36);
    var out_index: usize = 0;
    for (bytes, 0..) |byte, byte_index| {
        if (byte_index == 4 or byte_index == 6 or byte_index == 8 or byte_index == 10) {
            out[out_index] = '-';
            out_index += 1;
        }
        out[out_index] = hex[byte >> 4];
        out[out_index + 1] = hex[byte & 0x0f];
        out_index += 2;
    }
    return out;
}

fn currentUnixSeconds() i64 {
    const now_ns = std.Io.Timestamp.now(std.Io.Threaded.global_single_threaded.io(), .real).nanoseconds;
    return @intCast(@divTrunc(now_ns, 1_000_000_000));
}

fn currentUnixMilliseconds() i64 {
    const now_ns = std.Io.Timestamp.now(std.Io.Threaded.global_single_threaded.io(), .real).nanoseconds;
    return @intCast(@divTrunc(now_ns, std.time.ns_per_ms));
}

fn findLoadedThread(state: *const AppServerState, thread_id: []const u8) ?*const LoadedThread {
    const index = findLoadedThreadIndex(state, thread_id) orelse return null;
    return &state.loaded_threads.items[index];
}

fn findLoadedThreadForRolloutFile(state: *const AppServerState, file: session_store.RolloutFile) ?*const LoadedThread {
    for (state.loaded_threads.items) |*thread| {
        if (std.mem.eql(u8, thread.id, file.id)) return thread;
        if (thread.path) |path| {
            if (std.mem.eql(u8, path, file.path)) return thread;
        }
    }
    return null;
}

fn findLoadedThreadIndex(state: *const AppServerState, thread_id: []const u8) ?usize {
    for (state.loaded_threads.items, 0..) |thread, index| {
        if (std.mem.eql(u8, thread.id, thread_id)) return index;
    }
    return null;
}

fn removeLoadedThread(allocator: std.mem.Allocator, state: *AppServerState, thread_id: []const u8) bool {
    const index = findLoadedThreadIndex(state, thread_id) orelse return false;
    var removed = state.loaded_threads.orderedRemove(index);
    removed.deinit(allocator);
    return true;
}

fn upsertLoadedThread(allocator: std.mem.Allocator, state: *AppServerState, thread: LoadedThread) !void {
    if (findLoadedThreadIndex(state, thread.id)) |index| {
        var existing = state.loaded_threads.items[index];
        state.loaded_threads.items[index] = thread;
        existing.deinit(allocator);
        return;
    }
    try state.loaded_threads.append(allocator, thread);
}

fn ensureThreadSubscribed(allocator: std.mem.Allocator, state: *AppServerState, thread_id: []const u8) !bool {
    for (state.subscribed_thread_ids.items) |subscribed_id| {
        if (std.mem.eql(u8, subscribed_id, thread_id)) return false;
    }
    const owned_id = try allocator.dupe(u8, thread_id);
    errdefer allocator.free(owned_id);
    try state.subscribed_thread_ids.append(allocator, owned_id);
    return true;
}

fn removeThreadSubscription(allocator: std.mem.Allocator, state: *AppServerState, thread_id: []const u8) bool {
    for (state.subscribed_thread_ids.items, 0..) |subscribed_id, index| {
        if (std.mem.eql(u8, subscribed_id, thread_id)) {
            const removed = state.subscribed_thread_ids.orderedRemove(index);
            allocator.free(removed);
            return true;
        }
    }
    return false;
}

fn renderThreadLoadedListResult(
    allocator: std.mem.Allocator,
    state: *const AppServerState,
    params_value: ?std.json.Value,
) ![]const u8 {
    var ids = std.ArrayList([]const u8).empty;
    defer ids.deinit(allocator);
    for (state.loaded_threads.items) |thread| try ids.append(allocator, thread.id);
    if (ids.items.len == 0) {
        return allocator.dupe(u8, "{\"data\":[],\"nextCursor\":null}");
    }
    std.mem.sort([]const u8, ids.items, {}, stringLessThan);

    const cursor = threadLoadedListCursor(params_value);
    const limit = threadLoadedListLimit(params_value);
    var start: usize = 0;
    if (cursor) |cursor_value| {
        const normalized_cursor = canonicalUuidString(allocator, cursor_value) catch |err| switch (err) {
            error.InvalidUuidString => return error.InvalidThreadLoadedListCursor,
            else => return err,
        };
        defer allocator.free(normalized_cursor);
        for (ids.items, 0..) |id, index| {
            if (std.mem.eql(u8, id, normalized_cursor)) {
                start = index + 1;
                break;
            }
            if (std.mem.order(u8, id, normalized_cursor) == .gt) {
                start = index;
                break;
            }
        } else {
            start = ids.items.len;
        }
    }
    const effective_limit = if (limit) |value| @max(value, 1) else ids.items.len;
    const capped_end = @min(ids.items.len, start +| effective_limit);

    var result = std.ArrayList(u8).empty;
    errdefer result.deinit(allocator);
    try result.appendSlice(allocator, "{\"data\":[");
    for (ids.items[start..capped_end], 0..) |thread_id, index| {
        if (index > 0) try result.appendSlice(allocator, ",");
        try appendJsonString(allocator, &result, thread_id);
    }
    try result.appendSlice(allocator, "],\"nextCursor\":");
    if (capped_end < ids.items.len and capped_end > 0) {
        try appendJsonString(allocator, &result, ids.items[capped_end - 1]);
    } else {
        try result.appendSlice(allocator, "null");
    }
    try result.appendSlice(allocator, "}");
    return result.toOwnedSlice(allocator);
}

const ThreadListSortKey = enum {
    created_at,
    updated_at,
};

const ThreadListSortDirection = enum {
    asc,
    desc,
};

const ThreadListSortContext = struct {
    key: ThreadListSortKey,
    direction: ThreadListSortDirection,
};

const SavedThreadListItem = struct {
    id: []const u8,
    session_id: []const u8,
    forked_from_id: ?[]const u8,
    preview: []const u8,
    model_provider: []const u8,
    created_at: i64,
    updated_at: i64,
    created_at_ms: i64,
    updated_at_ms: i64,
    archived: bool,
    path: []const u8,
    cwd: []const u8,
    cli_version: []const u8,
    source: []const u8,
    thread_source: ?[]const u8,
    agent_nickname: ?[]const u8,
    agent_role: ?[]const u8,
    git_sha: ?[]const u8,
    git_branch: ?[]const u8,
    git_origin_url: ?[]const u8,
    name: ?[]const u8,
    status: ThreadRuntimeStatus,

    fn fromRolloutFile(
        allocator: std.mem.Allocator,
        file: session_store.RolloutFile,
        fallback_model_provider: []const u8,
        thread_names: []const session_store.ThreadNameEntry,
        status: ThreadRuntimeStatus,
    ) !SavedThreadListItem {
        var summary = try session_store.loadThreadListSummary(allocator, file.path, file.id);
        defer summary.deinit(allocator);

        const id = try allocator.dupe(u8, summary.id);
        errdefer allocator.free(id);
        const session_id = try allocator.dupe(u8, id);
        errdefer allocator.free(session_id);
        const forked_from_id = if (summary.forked_from_id) |value| try allocator.dupe(u8, value) else null;
        errdefer if (forked_from_id) |value| allocator.free(value);
        const preview_value = stateThreadStringOrFallback(file.first_user_message, summary.preview);
        const preview = try allocator.dupe(u8, preview_value);
        errdefer allocator.free(preview);
        const model_provider_value = stateThreadStringOrFallback(file.model_provider, summary.model_provider orelse fallback_model_provider);
        const model_provider = try allocator.dupe(u8, model_provider_value);
        errdefer allocator.free(model_provider);
        const path = try allocator.dupe(u8, file.path);
        errdefer allocator.free(path);
        const cwd = try allocator.dupe(u8, stateThreadStringOrFallback(file.cwd, summary.cwd orelse ""));
        errdefer allocator.free(cwd);
        const cli_version = try allocator.dupe(u8, stateThreadStringOrFallback(file.cli_version, summary.cli_version orelse "0.0.1"));
        errdefer allocator.free(cli_version);
        const source_value = if (file.state_lifecycle_loaded) file.source orelse summary.source orelse "cli" else summary.source orelse "cli";
        const source = try allocator.dupe(u8, source_value);
        errdefer allocator.free(source);
        const thread_source_value = if (file.state_lifecycle_loaded) file.thread_source else summary.thread_source;
        const thread_source = if (thread_source_value) |value| try allocator.dupe(u8, value) else null;
        errdefer if (thread_source) |value| allocator.free(value);
        const agent_nickname_value = if (file.state_lifecycle_loaded) file.agent_nickname else null;
        const agent_nickname = if (agent_nickname_value) |value| try allocator.dupe(u8, value) else null;
        errdefer if (agent_nickname) |value| allocator.free(value);
        const agent_role_value = if (file.state_lifecycle_loaded) file.agent_role else null;
        const agent_role = if (agent_role_value) |value| try allocator.dupe(u8, value) else null;
        errdefer if (agent_role) |value| allocator.free(value);
        const git_sha_value = if (file.state_metadata_loaded) file.git_sha else summary.git_sha;
        const git_sha = if (git_sha_value) |value| try allocator.dupe(u8, value) else null;
        errdefer if (git_sha) |value| allocator.free(value);
        const git_branch_value = if (file.state_metadata_loaded) file.git_branch else summary.git_branch;
        const git_branch = if (git_branch_value) |value| try allocator.dupe(u8, value) else null;
        errdefer if (git_branch) |value| allocator.free(value);
        const git_origin_url_value = if (file.state_metadata_loaded) file.git_origin_url else summary.git_origin_url;
        const git_origin_url = if (git_origin_url_value) |value| try allocator.dupe(u8, value) else null;
        errdefer if (git_origin_url) |value| allocator.free(value);
        const indexed_name = session_store.threadNameFromIndex(thread_names, summary.id);
        const state_name = if (file.state_metadata_loaded) stateThreadTitle(file.title, preview_value) else null;
        const name_value: ?[]const u8 = if (state_name) |value|
            value
        else if (indexed_name) |value|
            value
        else
            summary.title;
        const name = if (name_value) |value| try allocator.dupe(u8, value) else null;
        errdefer if (name) |value| allocator.free(value);

        return .{
            .id = id,
            .session_id = session_id,
            .forked_from_id = forked_from_id,
            .preview = preview,
            .model_provider = model_provider,
            .created_at = rolloutFileTimestampSeconds(file.state_lifecycle_loaded, file.created_at_ms, file.modified_at_seconds),
            .updated_at = rolloutFileTimestampSeconds(file.state_lifecycle_loaded, file.updated_at_ms, file.modified_at_seconds),
            .created_at_ms = rolloutFileTimestampMilliseconds(file.state_lifecycle_loaded, file.created_at_ms, file.modified_at_seconds),
            .updated_at_ms = rolloutFileTimestampMilliseconds(file.state_lifecycle_loaded, file.updated_at_ms, file.modified_at_seconds),
            .archived = file.archived,
            .path = path,
            .cwd = cwd,
            .cli_version = cli_version,
            .source = source,
            .thread_source = thread_source,
            .agent_nickname = agent_nickname,
            .agent_role = agent_role,
            .git_sha = git_sha,
            .git_branch = git_branch,
            .git_origin_url = git_origin_url,
            .name = name,
            .status = status,
        };
    }

    fn deinit(self: *SavedThreadListItem, allocator: std.mem.Allocator) void {
        allocator.free(self.id);
        allocator.free(self.session_id);
        if (self.forked_from_id) |value| allocator.free(value);
        allocator.free(self.preview);
        allocator.free(self.model_provider);
        allocator.free(self.path);
        allocator.free(self.cwd);
        allocator.free(self.cli_version);
        allocator.free(self.source);
        if (self.thread_source) |value| allocator.free(value);
        if (self.agent_nickname) |value| allocator.free(value);
        if (self.agent_role) |value| allocator.free(value);
        if (self.git_sha) |value| allocator.free(value);
        if (self.git_branch) |value| allocator.free(value);
        if (self.git_origin_url) |value| allocator.free(value);
        if (self.name) |value| allocator.free(value);
    }
};

fn rolloutFileTimestampSeconds(lifecycle_loaded: bool, value_ms: ?i64, fallback_seconds: i64) i64 {
    if (!lifecycle_loaded) return fallback_seconds;
    const value = value_ms orelse return fallback_seconds;
    return @divFloor(value, 1000);
}

fn rolloutFileTimestampMilliseconds(lifecycle_loaded: bool, value_ms: ?i64, fallback_seconds: i64) i64 {
    if (!lifecycle_loaded) return fallback_seconds * 1000;
    return value_ms orelse fallback_seconds * 1000;
}

fn stateThreadTitle(title: ?[]const u8, preview: []const u8) ?[]const u8 {
    const raw = title orelse return null;
    const trimmed = std.mem.trim(u8, raw, " \t\r\n");
    if (trimmed.len == 0) return null;
    if (std.mem.eql(u8, trimmed, std.mem.trim(u8, preview, " \t\r\n"))) return null;
    return trimmed;
}

fn stateThreadString(value: ?[]const u8) ?[]const u8 {
    const text = value orelse return null;
    if (text.len == 0) return null;
    return text;
}

fn stateThreadReasoningEffort(value: ?[]const u8) ?[]const u8 {
    const text = stateThreadString(value) orelse return null;
    _ = config.ReasoningEffort.parse(text) catch return null;
    return text;
}

fn stateThreadStringOrFallback(value: ?[]const u8, fallback: []const u8) []const u8 {
    return stateThreadString(value) orelse fallback;
}

const ThreadListItem = union(enum) {
    loaded: *const LoadedThread,
    saved: SavedThreadListItem,

    fn deinit(self: *ThreadListItem, allocator: std.mem.Allocator) void {
        switch (self.*) {
            .loaded => {},
            .saved => |*saved| saved.deinit(allocator),
        }
    }
};

fn renderThreadListResult(
    allocator: std.mem.Allocator,
    state: *const AppServerState,
    cfg: config.Config,
    params_value: std.json.Value,
) ![]const u8 {
    const params = params_value.object;
    var threads = std.ArrayList(ThreadListItem).empty;
    defer {
        for (threads.items) |*thread| thread.deinit(allocator);
        threads.deinit(allocator);
    }

    const state_db_only = optionalBoolParam(params, "useStateDbOnly") orelse false;
    const archived = optionalBoolParam(params, "archived") orelse false;
    const thread_names = try session_store.loadThreadNameIndex(allocator, cfg.codex_home);
    defer session_store.freeThreadNameIndex(allocator, thread_names);
    const fallback_model_provider = try config.loadModelProviderId(allocator, cfg.active_profile);
    defer if (fallback_model_provider) |value| allocator.free(value);
    const default_model_provider = fallback_model_provider orelse "openai";
    if (state_db_only) {
        const rollout_files = try thread_state.listRolloutFiles(allocator, cfg.codex_home);
        defer session_store.freeRolloutFiles(allocator, rollout_files);
        try appendSavedThreadListItems(allocator, &threads, params, rollout_files, default_model_provider, false, state, thread_names);
    } else {
        if (!archived) {
            for (state.loaded_threads.items) |*thread| {
                const item = ThreadListItem{ .loaded = thread };
                if (threadListItemMatchesParams(item, params, default_model_provider)) {
                    try threads.append(allocator, item);
                }
            }
        }

        const rollout_files = try session_store.listRolloutFiles(allocator, cfg.codex_home, archived);
        defer session_store.freeRolloutFiles(allocator, rollout_files);
        try appendSavedThreadListItems(allocator, &threads, params, rollout_files, default_model_provider, !archived, state, thread_names);
    }

    const sort_context = threadListSortContext(params);
    std.mem.sort(ThreadListItem, threads.items, sort_context, threadListLessThan);

    const cursor_ms = if (optionalStringParam(params, "cursor")) |cursor_value|
        parseThreadListCursorMilliseconds(cursor_value) orelse return error.InvalidThreadListCursor
    else
        null;
    var start: usize = 0;
    if (cursor_ms) |anchor_ms| {
        for (threads.items, 0..) |thread, index| {
            if (threadListItemIsPastCursor(thread, sort_context, anchor_ms)) {
                start = index;
                break;
            }
        } else {
            start = threads.items.len;
        }
    }

    const limit = threadListLimit(params);
    const capped_end = @min(threads.items.len, start + limit);
    const page = threads.items[start..capped_end];

    var result = std.ArrayList(u8).empty;
    errdefer result.deinit(allocator);
    try result.appendSlice(allocator, "{\"data\":[");
    for (page, 0..) |thread, index| {
        if (index > 0) try result.appendSlice(allocator, ",");
        try appendThreadListItemJson(allocator, &result, thread);
    }
    try result.appendSlice(allocator, "],\"nextCursor\":");
    if (capped_end < threads.items.len and page.len > 0) {
        const next_cursor = try formatThreadListCursorMilliseconds(allocator, threadListItemSortTimestampMs(page[page.len - 1], sort_context.key), false);
        defer allocator.free(next_cursor);
        try appendJsonString(allocator, &result, next_cursor);
    } else {
        try result.appendSlice(allocator, "null");
    }
    try result.appendSlice(allocator, ",\"backwardsCursor\":");
    if (page.len > 0) {
        if (threadListBackwardsCursorTimestampMs(page[0], sort_context)) |cursor_timestamp| {
            const backwards_cursor = try formatThreadListCursorMilliseconds(allocator, cursor_timestamp, true);
            defer allocator.free(backwards_cursor);
            try appendJsonString(allocator, &result, backwards_cursor);
        } else {
            try result.appendSlice(allocator, "null");
        }
    } else {
        try result.appendSlice(allocator, "null");
    }
    try result.appendSlice(allocator, "}");
    return result.toOwnedSlice(allocator);
}

fn threadListItemMatchesParams(thread: ThreadListItem, params: std.json.ObjectMap, default_model_provider: []const u8) bool {
    const archived = optionalBoolParam(params, "archived") orelse false;
    if (threadListItemArchived(thread) != archived) return false;
    if (!threadListModelProviderMatches(params.get("modelProviders"), threadListItemModelProvider(thread), default_model_provider)) return false;
    if (!jsonStringArrayContainsOrEmpty(params.get("sourceKinds"), threadListItemSource(thread))) return false;
    if (!threadListCwdMatches(params.get("cwd"), threadListItemCwd(thread))) return false;
    if (optionalStringParam(params, "searchTerm")) |search| {
        if (search.len > 0 and !threadListItemMatchesSearchTerm(thread, search)) return false;
    }
    return true;
}

fn appendSavedThreadListItems(
    allocator: std.mem.Allocator,
    threads: *std.ArrayList(ThreadListItem),
    params: std.json.ObjectMap,
    rollout_files: []session_store.RolloutFile,
    fallback_model_provider: []const u8,
    dedupe_loaded: bool,
    state: *const AppServerState,
    thread_names: []const session_store.ThreadNameEntry,
) !void {
    for (rollout_files) |file| {
        const loaded_duplicate = findLoadedThreadForRolloutFile(state, file) != null;
        if (dedupe_loaded and loaded_duplicate) continue;
        const status: ThreadRuntimeStatus = if (loaded_duplicate) .idle else .not_loaded;
        var saved = SavedThreadListItem.fromRolloutFile(allocator, file, fallback_model_provider, thread_names, status) catch |err| switch (err) {
            error.OutOfMemory => return err,
            else => continue,
        };
        var saved_moved = false;
        errdefer if (!saved_moved) saved.deinit(allocator);
        const item = ThreadListItem{ .saved = saved };
        if (threadListItemMatchesParams(item, params, fallback_model_provider)) {
            try threads.append(allocator, item);
            saved_moved = true;
        } else {
            saved.deinit(allocator);
        }
    }
}

fn threadListModelProviderMatches(value: ?std.json.Value, candidate: []const u8, default_model_provider: []const u8) bool {
    const actual = value orelse return std.mem.eql(u8, candidate, default_model_provider);
    if (actual == .null) return std.mem.eql(u8, candidate, default_model_provider);
    if (actual.array.items.len == 0) return true;
    for (actual.array.items) |item| {
        if (std.mem.eql(u8, item.string, candidate)) return true;
    }
    return false;
}

fn jsonStringArrayContainsOrEmpty(value: ?std.json.Value, candidate: []const u8) bool {
    const actual = value orelse return true;
    if (actual == .null) return true;
    if (actual.array.items.len == 0) return true;
    for (actual.array.items) |item| {
        if (std.mem.eql(u8, item.string, candidate)) return true;
    }
    return false;
}

fn threadListCwdMatches(value: ?std.json.Value, cwd: []const u8) bool {
    const actual = value orelse return true;
    if (actual == .null) return true;
    if (actual == .string) return std.mem.eql(u8, actual.string, cwd);
    if (actual.array.items.len == 0) return false;
    for (actual.array.items) |item| {
        if (std.mem.eql(u8, item.string, cwd)) return true;
    }
    return false;
}

fn threadListItemMatchesSearchTerm(thread: ThreadListItem, search: []const u8) bool {
    if (threadListItemName(thread)) |name| {
        if (std.mem.indexOf(u8, name, search) != null) return true;
    }
    return std.mem.indexOf(u8, threadListItemPreview(thread), search) != null;
}

fn threadListSortContext(params: std.json.ObjectMap) ThreadListSortContext {
    const key_text = optionalStringParam(params, "sortKey") orelse "created_at";
    const direction_text = optionalStringParam(params, "sortDirection") orelse "desc";
    return .{
        .key = if (std.mem.eql(u8, key_text, "updated_at")) .updated_at else .created_at,
        .direction = if (std.mem.eql(u8, direction_text, "asc")) .asc else .desc,
    };
}

fn threadListLessThan(context: ThreadListSortContext, lhs: ThreadListItem, rhs: ThreadListItem) bool {
    const lhs_timestamp = threadListItemSortTimestampMs(lhs, context.key);
    const rhs_timestamp = threadListItemSortTimestampMs(rhs, context.key);
    if (lhs_timestamp != rhs_timestamp) {
        return if (context.direction == .asc) lhs_timestamp < rhs_timestamp else lhs_timestamp > rhs_timestamp;
    }
    return stringLessThan({}, threadListItemId(lhs), threadListItemId(rhs));
}

fn threadListItemIsPastCursor(thread: ThreadListItem, context: ThreadListSortContext, cursor_ms: i64) bool {
    const timestamp_ms = threadListItemSortTimestampMs(thread, context.key);
    return switch (context.direction) {
        .asc => timestamp_ms > cursor_ms,
        .desc => timestamp_ms < cursor_ms,
    };
}

fn threadListBackwardsCursorTimestampMs(thread: ThreadListItem, context: ThreadListSortContext) ?i64 {
    const timestamp_ms = threadListItemSortTimestampMs(thread, context.key);
    return switch (context.direction) {
        .asc => timestamp_ms + 1,
        .desc => if (timestamp_ms > 0) timestamp_ms - 1 else null,
    };
}

fn threadListItemId(thread: ThreadListItem) []const u8 {
    return switch (thread) {
        .loaded => |loaded| loaded.id,
        .saved => |saved| saved.id,
    };
}

fn threadListItemPreview(thread: ThreadListItem) []const u8 {
    return switch (thread) {
        .loaded => |loaded| loaded.preview,
        .saved => |saved| saved.preview,
    };
}

fn threadListItemModelProvider(thread: ThreadListItem) []const u8 {
