fn threadListLimit(params: std.json.ObjectMap) usize {
    const value = params.get("limit") orelse return THREAD_LIST_DEFAULT_LIMIT;
    if (value == .null) return THREAD_LIST_DEFAULT_LIMIT;
    return @min(@max(@as(usize, @intCast(value.integer)), 1), THREAD_LIST_MAX_LIMIT);
}

fn parseThreadListCursorMilliseconds(value: []const u8) ?i64 {
    if (std.mem.indexOfScalar(u8, value, '|') != null) return null;
    if (parseThreadListRfc3339Milliseconds(value)) |timestamp_ms| return timestamp_ms;
    return parseThreadListLegacyTimestampMilliseconds(value);
}

fn parseThreadListRfc3339Milliseconds(value: []const u8) ?i64 {
    if (value.len < "YYYY-MM-DDTHH:MM:SSZ".len) return null;
    if (value[4] != '-' or value[7] != '-' or value[10] != 'T' or value[13] != ':' or value[16] != ':') {
        return null;
    }

    const year = parseFixedUnsigned(u16, value[0..4]) orelse return null;
    const month = parseFixedUnsigned(u8, value[5..7]) orelse return null;
    const day = parseFixedUnsigned(u8, value[8..10]) orelse return null;
    const hour = parseFixedUnsigned(u8, value[11..13]) orelse return null;
    const minute = parseFixedUnsigned(u8, value[14..16]) orelse return null;
    const second = parseFixedUnsigned(u8, value[17..19]) orelse return null;

    var index: usize = 19;
    var millisecond: i64 = 0;
    if (index < value.len and value[index] == '.') {
        index += 1;
        const fraction_start = index;
        var digits_seen: u8 = 0;
        while (index < value.len and std.ascii.isDigit(value[index])) : (index += 1) {
            if (digits_seen < 3) {
                millisecond = millisecond * 10 + (value[index] - '0');
                digits_seen += 1;
            }
        }
        if (index == fraction_start) return null;
        while (digits_seen < 3) : (digits_seen += 1) {
            millisecond *= 10;
        }
    }

    const offset_seconds: i64 = blk: {
        if (index >= value.len) return null;
        if (value[index] == 'Z') {
            if (index + 1 != value.len) return null;
            break :blk 0;
        }
        const sign_char = value[index];
        if (sign_char != '+' and sign_char != '-') return null;
        if (index + 6 != value.len) return null;
        if (value[index + 3] != ':') return null;
        const offset_hours = parseFixedUnsigned(u8, value[index + 1 .. index + 3]) orelse return null;
        const offset_minutes = parseFixedUnsigned(u8, value[index + 4 .. index + 6]) orelse return null;
        if (offset_hours > 23 or offset_minutes > 59) return null;
        const offset = @as(i64, offset_hours) * 60 * 60 + @as(i64, offset_minutes) * 60;
        break :blk if (sign_char == '+') offset else -offset;
    };

    const local_seconds = epochSecondsFromDate(year, month, day, hour, minute, second) orelse return null;
    const utc_seconds = local_seconds - offset_seconds;
    if (utc_seconds < 0) return null;
    return utc_seconds * 1000 + millisecond;
}

fn parseThreadListLegacyTimestampMilliseconds(value: []const u8) ?i64 {
    if (value.len != "YYYY-MM-DDTHH-MM-SS".len) return null;
    if (value[4] != '-' or value[7] != '-' or value[10] != 'T' or value[13] != '-' or value[16] != '-') {
        return null;
    }

    const year = parseFixedUnsigned(u16, value[0..4]) orelse return null;
    const month = parseFixedUnsigned(u8, value[5..7]) orelse return null;
    const day = parseFixedUnsigned(u8, value[8..10]) orelse return null;
    const hour = parseFixedUnsigned(u8, value[11..13]) orelse return null;
    const minute = parseFixedUnsigned(u8, value[14..16]) orelse return null;
    const second = parseFixedUnsigned(u8, value[17..19]) orelse return null;
    const seconds = epochSecondsFromDate(year, month, day, hour, minute, second) orelse return null;
    return seconds * 1000;
}

fn epochSecondsFromDate(year: u16, month: u8, day: u8, hour: u8, minute: u8, second: u8) ?i64 {
    if (year < std.time.epoch.epoch_year or month < 1 or month > 12 or hour > 23 or minute > 59 or second > 59) {
        return null;
    }
    const month_enum: std.time.epoch.Month = @enumFromInt(month);
    const days_in_month = std.time.epoch.getDaysInMonth(year, month_enum);
    if (day < 1 or day > days_in_month) return null;

    var days: i64 = 0;
    var y: u16 = std.time.epoch.epoch_year;
    while (y < year) : (y += 1) {
        days += std.time.epoch.getDaysInYear(y);
    }

    var m: u8 = 1;
    while (m < month) : (m += 1) {
        days += std.time.epoch.getDaysInMonth(year, @enumFromInt(m));
    }
    days += day - 1;

    return days * (24 * 60 * 60) + @as(i64, hour) * 60 * 60 + @as(i64, minute) * 60 + second;
}

fn parseFixedUnsigned(comptime T: type, value: []const u8) ?T {
    for (value) |char| {
        if (!std.ascii.isDigit(char)) return null;
    }
    return std.fmt.parseUnsigned(T, value, 10) catch null;
}

fn formatThreadListCursorMilliseconds(allocator: std.mem.Allocator, timestamp_ms: i64, force_millis: bool) ![]const u8 {
    if (timestamp_ms < 0) return error.InvalidThreadListCursor;
    const seconds: u64 = @intCast(@divFloor(timestamp_ms, 1000));
    const millisecond: u16 = @intCast(@mod(timestamp_ms, 1000));
    const seconds_text = try auth_mod.rfc3339FromSeconds(allocator, seconds);
    if (!force_millis and millisecond == 0) return seconds_text;
    defer allocator.free(seconds_text);
    return std.fmt.allocPrint(allocator, "{s}.{d:0>3}Z", .{ seconds_text[0 .. seconds_text.len - 1], millisecond });
}

fn stringLessThan(_: void, lhs: []const u8, rhs: []const u8) bool {
    return std.mem.order(u8, lhs, rhs) == .lt;
}

fn threadLoadedListCursor(params_value: ?std.json.Value) ?[]const u8 {
    const params = params_value orelse return null;
    if (params != .object) return null;
    const cursor = params.object.get("cursor") orelse return null;
    if (cursor == .null) return null;
    return cursor.string;
}

fn threadLoadedListLimit(params_value: ?std.json.Value) ?usize {
    const params = params_value orelse return null;
    if (params != .object) return null;
    const limit = params.object.get("limit") orelse return null;
    if (limit == .null) return null;
    return @intCast(limit.integer);
}

const ThreadRuntimeStatus = enum {
    active,
    idle,
    not_loaded,
    system_error,
};

fn renderThreadLifecycleResponse(allocator: std.mem.Allocator, thread: *const LoadedThread, include_turns: bool) ![]const u8 {
    var result = std.ArrayList(u8).empty;
    errdefer result.deinit(allocator);

    try result.appendSlice(allocator, "{\"thread\":");
    try appendLoadedThreadJson(allocator, &result, thread, include_turns, thread.status);
    try result.appendSlice(allocator, ",\"model\":");
    try appendJsonString(allocator, &result, thread.model);
    try result.appendSlice(allocator, ",\"modelProvider\":");
    try appendJsonString(allocator, &result, thread.model_provider);
    try result.appendSlice(allocator, ",\"serviceTier\":");
    try appendOptionalJsonString(allocator, &result, thread.service_tier);
    try result.appendSlice(allocator, ",\"cwd\":");
    try appendJsonString(allocator, &result, thread.cwd);
    try result.appendSlice(allocator, ",\"instructionSources\":[],\"approvalPolicy\":");
    try appendJsonString(allocator, &result, thread.approval_policy);
    try result.appendSlice(allocator, ",\"approvalsReviewer\":");
    try appendJsonString(allocator, &result, thread.approvals_reviewer);
    try result.appendSlice(allocator, ",\"sandbox\":");
    try appendSandboxPolicyJson(allocator, &result, thread.sandbox_mode);
    try result.appendSlice(allocator, ",\"reasoningEffort\":");
    try appendOptionalJsonString(allocator, &result, thread.reasoning_effort);
    try result.appendSlice(allocator, "}");

    return result.toOwnedSlice(allocator);
}

fn renderThreadReadResponse(allocator: std.mem.Allocator, thread: *const LoadedThread, include_turns: bool) ![]const u8 {
    return renderThreadReadResponseWithStatus(allocator, thread, include_turns, thread.status);
}

fn loadedThreadHasMaterializedTurns(allocator: std.mem.Allocator, thread: *const LoadedThread) !bool {
    if (thread.transcript.history.items.len > 0) return true;
    var parsed_turns = try std.json.parseFromSlice(std.json.Value, allocator, thread.turns_json, .{});
    defer parsed_turns.deinit();
    if (parsed_turns.value != .array) return true;
    return parsed_turns.value.array.items.len > 0;
}

fn renderStoredThreadReadResponse(allocator: std.mem.Allocator, thread: *const LoadedThread, include_turns: bool) ![]const u8 {
    return renderThreadReadResponseWithStatus(allocator, thread, include_turns, .not_loaded);
}

fn renderThreadReadResponseWithStatus(
    allocator: std.mem.Allocator,
    thread: *const LoadedThread,
    include_turns: bool,
    status: ThreadRuntimeStatus,
) ![]const u8 {
    var result = std.ArrayList(u8).empty;
    errdefer result.deinit(allocator);
    try result.appendSlice(allocator, "{\"thread\":");
    try appendLoadedThreadJson(allocator, &result, thread, include_turns, status);
    try result.appendSlice(allocator, "}");
    return result.toOwnedSlice(allocator);
}

const ConversationSummaryView = struct {
    conversation_id: []const u8,
    path: []const u8,
    preview: []const u8,
    model_provider: []const u8,
    cwd: []const u8,
    cli_version: []const u8,
    source: []const u8,
    git_sha: ?[]const u8,
    git_branch: ?[]const u8,
    git_origin_url: ?[]const u8,
};

fn renderConversationSummaryResponseFromLoadedThread(allocator: std.mem.Allocator, thread: *const LoadedThread) ![]const u8 {
    return renderConversationSummaryResponse(allocator, .{
        .conversation_id = thread.id,
        .path = thread.path orelse "",
        .preview = thread.preview,
        .model_provider = thread.model_provider,
        .cwd = thread.cwd,
        .cli_version = thread.cli_version,
        .source = thread.source,
        .git_sha = thread.git_sha,
        .git_branch = thread.git_branch,
        .git_origin_url = thread.git_origin_url,
    });
}

fn renderConversationSummaryResponseFromTranscript(
    allocator: std.mem.Allocator,
    path: []const u8,
    transcript: *const session_mod.Transcript,
    fallback_model_provider: []const u8,
) ![]const u8 {
    const owned_id = if (transcript.id == null) try session_store.sessionIdFromPath(allocator, path) else null;
    defer if (owned_id) |value| allocator.free(value);

    const preview = try resumePreview(allocator, transcript);
    defer allocator.free(preview);

    return renderConversationSummaryResponse(allocator, .{
        .conversation_id = transcript.id orelse owned_id.?,
        .path = path,
        .preview = preview,
        .model_provider = transcript.model_provider orelse fallback_model_provider,
        .cwd = transcript.cwd orelse "",
        .cli_version = transcript.cli_version orelse "0.0.1",
        .source = transcript.source orelse "unknown",
        .git_sha = transcript.git_sha,
        .git_branch = transcript.git_branch,
        .git_origin_url = transcript.git_origin_url,
    });
}

fn renderConversationSummaryResponse(allocator: std.mem.Allocator, summary: ConversationSummaryView) ![]const u8 {
    var result = std.ArrayList(u8).empty;
    errdefer result.deinit(allocator);

    try result.appendSlice(allocator, "{\"summary\":{\"conversationId\":");
    try appendJsonString(allocator, &result, summary.conversation_id);
    try result.appendSlice(allocator, ",\"path\":");
    try appendJsonString(allocator, &result, summary.path);
    try result.appendSlice(allocator, ",\"preview\":");
    try appendJsonString(allocator, &result, summary.preview);
    try result.appendSlice(allocator, ",\"timestamp\":null,\"updatedAt\":null,\"modelProvider\":");
    try appendJsonString(allocator, &result, summary.model_provider);
    try result.appendSlice(allocator, ",\"cwd\":");
    try appendJsonString(allocator, &result, summary.cwd);
    try result.appendSlice(allocator, ",\"cliVersion\":");
    try appendJsonString(allocator, &result, summary.cli_version);
    try result.appendSlice(allocator, ",\"source\":");
    try appendConversationSummarySourceJson(allocator, &result, summary.source);
    try result.appendSlice(allocator, ",\"gitInfo\":");
    try appendConversationSummaryGitInfoJson(allocator, &result, summary);
    try result.appendSlice(allocator, "}}");
    return result.toOwnedSlice(allocator);
}

fn appendConversationSummarySourceJson(allocator: std.mem.Allocator, out: *std.ArrayList(u8), source: []const u8) !void {
    if (std.mem.eql(u8, source, "cli") or
        std.mem.eql(u8, source, "vscode") or
        std.mem.eql(u8, source, "exec") or
        std.mem.eql(u8, source, "mcp") or
        std.mem.eql(u8, source, "unknown"))
    {
        try appendJsonString(allocator, out, source);
        return;
    }
    if (std.mem.eql(u8, source, "memory_consolidation")) {
        try out.appendSlice(allocator, "{\"internal\":\"memory_consolidation\"}");
        return;
    }
    try out.appendSlice(allocator, "{\"custom\":");
    try appendJsonString(allocator, out, source);
    try out.appendSlice(allocator, "}");
}

fn appendConversationSummaryGitInfoJson(allocator: std.mem.Allocator, out: *std.ArrayList(u8), summary: ConversationSummaryView) !void {
    if (summary.git_sha == null and summary.git_branch == null and summary.git_origin_url == null) {
        try out.appendSlice(allocator, "null");
        return;
    }
    try out.appendSlice(allocator, "{\"sha\":");
    try appendOptionalJsonString(allocator, out, summary.git_sha);
    try out.appendSlice(allocator, ",\"branch\":");
    try appendOptionalJsonString(allocator, out, summary.git_branch);
    try out.appendSlice(allocator, ",\"origin_url\":");
    try appendOptionalJsonString(allocator, out, summary.git_origin_url);
    try out.appendSlice(allocator, "}");
}

fn renderThreadElicitationResponse(allocator: std.mem.Allocator, count: u64) ![]const u8 {
    var result = std.ArrayList(u8).empty;
    errdefer result.deinit(allocator);
    try result.appendSlice(allocator, "{\"count\":");
    try appendInt(allocator, &result, count);
    try result.appendSlice(allocator, ",\"paused\":");
    try result.appendSlice(allocator, if (count > 0) "true" else "false");
    try result.appendSlice(allocator, "}");
    return result.toOwnedSlice(allocator);
}

