fn appendSandboxPolicyJson(allocator: std.mem.Allocator, result: *std.ArrayList(u8), sandbox_mode: []const u8) !void {
    if (std.mem.eql(u8, sandbox_mode, "danger-full-access")) {
        try result.appendSlice(allocator, "{\"type\":\"dangerFullAccess\"}");
    } else if (std.mem.eql(u8, sandbox_mode, "read-only")) {
        try result.appendSlice(allocator, "{\"type\":\"readOnly\",\"networkAccess\":false}");
    } else {
        try result.appendSlice(allocator, "{\"type\":\"workspaceWrite\",\"writableRoots\":[],\"networkAccess\":false,\"excludeTmpdirEnvVar\":false,\"excludeSlashTmp\":false}");
    }
}

fn updateOptOutNotificationMethods(allocator: std.mem.Allocator, state: *AppServerState, params_value: ?std.json.Value) !void {
    clearOptOutNotificationMethods(allocator, state);
    const params = params_value orelse return;
    if (params != .object) return;
    const capabilities = params.object.get("capabilities") orelse return;
    if (capabilities == .null) return;
    if (capabilities != .object) return;
    const opt_out = capabilities.object.get("optOutNotificationMethods") orelse return;
    if (opt_out == .null) return;
    if (opt_out != .array) return;
    for (opt_out.array.items) |method| {
        if (method != .string) continue;
        const owned = try allocator.dupe(u8, method.string);
        errdefer allocator.free(owned);
        try state.opt_out_notification_methods.append(allocator, owned);
    }
}

fn clearOptOutNotificationMethods(allocator: std.mem.Allocator, state: *AppServerState) void {
    for (state.opt_out_notification_methods.items) |method| allocator.free(method);
    state.opt_out_notification_methods.clearRetainingCapacity();
}

fn notificationMethodOptedOut(state: *const AppServerState, method: []const u8) bool {
    for (state.opt_out_notification_methods.items) |opt_out_method| {
        if (std.mem.eql(u8, opt_out_method, method)) return true;
    }
    return false;
}

fn renderThreadNotFoundForThreadIdParam(
    allocator: std.mem.Allocator,
    id_value: std.json.Value,
    method: []const u8,
    params_value: ?std.json.Value,
) ![]const u8 {
    const object = parseThreadObjectParams(params_value) catch |err| switch (err) {
        error.InvalidThreadParams => return renderThreadObjectParamsError(allocator, id_value, method),
    };
    const thread_id = requiredThreadIdParam(object) catch |err| switch (err) {
        error.MissingThreadId => return renderJsonRpcError(allocator, id_value, -32602, "threadId must be a string"),
    };
    if (!isUuidString(thread_id)) {
        return renderInvalidThreadId(allocator, id_value, thread_id);
    }
    return renderThreadNotFound(allocator, id_value, thread_id);
}

fn parseThreadObjectParams(params_value: ?std.json.Value) !std.json.ObjectMap {
    const params = params_value orelse return error.InvalidThreadParams;
    if (params != .object) return error.InvalidThreadParams;
    return params.object;
}

fn requiredThreadIdParam(object: std.json.ObjectMap) ![]const u8 {
    const thread_id = object.get("threadId") orelse return error.MissingThreadId;
    if (thread_id != .string) return error.MissingThreadId;
    return thread_id.string;
}

fn requiredThreadNumTurnsParam(object: std.json.ObjectMap) !u32 {
    const num_turns = object.get("numTurns") orelse return error.InvalidNumTurns;
    if (num_turns != .integer) return error.InvalidNumTurns;
    if (num_turns.integer < 0 or num_turns.integer > std.math.maxInt(u32)) return error.InvalidNumTurns;
    return @intCast(num_turns.integer);
}

fn appServerFeatureEnabled(allocator: std.mem.Allocator, state: *const AppServerState, key: []const u8) !bool {
    var cfg = try config.load(allocator);
    defer cfg.deinit(allocator);
    var config_overrides = try features_cmd.loadFeatureOverridesForProfile(allocator, cfg.codex_home, cfg.active_profile);
    defer config_overrides.deinit(allocator);

    if (config_overrides.get(key)) |enabled| return enabled;
    if (state.runtime_feature_enablement.get(key)) |enabled| return enabled;
    for (features_cmd.FeatureSpec.all) |feature| {
        if (std.mem.eql(u8, feature.key, key)) return feature.default_enabled;
    }
    return false;
}

fn guardianAssessmentEventIsValid(value: std.json.Value) bool {
    if (value != .object) return false;
    const object = value.object;
    if (!jsonRequiredStringFieldIsValid(object, "id")) return false;
    if (object.get("target_item_id")) |field| {
        if (!jsonOptionalStringValueIsValid(field)) return false;
    }
    if (object.get("turn_id")) |field| {
        if (field != .string) return false;
    }
    const status = object.get("status") orelse return false;
    if (!enumStringIsValid(status, &.{ "in_progress", "approved", "denied", "timed_out", "aborted" })) return false;
    if (object.get("risk_level")) |field| {
        if (!optionalEnumStringIsValid(field, &.{ "low", "medium", "high", "critical" })) return false;
    }
    if (object.get("user_authorization")) |field| {
        if (!optionalEnumStringIsValid(field, &.{ "unknown", "low", "medium", "high" })) return false;
    }
    if (object.get("rationale")) |field| {
        if (!jsonOptionalStringValueIsValid(field)) return false;
    }
    if (object.get("decision_source")) |field| {
        if (!optionalEnumStringIsValid(field, &.{"agent"})) return false;
    }
    const action = object.get("action") orelse return false;
    return guardianAssessmentActionIsValid(action);
}

fn guardianAssessmentActionIsValid(value: std.json.Value) bool {
    if (value != .object) return false;
    const object = value.object;
    const action_type = object.get("type") orelse return false;
    if (action_type != .string) return false;
    if (std.mem.eql(u8, action_type.string, "command")) {
        return guardianCommandSourceFieldIsValid(object) and
            jsonRequiredStringFieldIsValid(object, "command") and
            jsonRequiredStringFieldIsValid(object, "cwd");
    }
    if (std.mem.eql(u8, action_type.string, "execve")) {
        return guardianCommandSourceFieldIsValid(object) and
            jsonRequiredStringFieldIsValid(object, "program") and
            jsonRequiredStringArrayFieldIsValid(object, "argv") and
            jsonRequiredStringFieldIsValid(object, "cwd");
    }
    if (std.mem.eql(u8, action_type.string, "apply_patch")) {
        return jsonRequiredStringFieldIsValid(object, "cwd") and
            jsonRequiredStringArrayFieldIsValid(object, "files");
    }
    if (std.mem.eql(u8, action_type.string, "network_access")) {
        return jsonRequiredStringFieldIsValid(object, "target") and
            jsonRequiredStringFieldIsValid(object, "host") and
            guardianNetworkProtocolFieldIsValid(object) and
            jsonRequiredU16FieldIsValid(object, "port");
    }
    if (std.mem.eql(u8, action_type.string, "mcp_tool_call")) {
        return jsonRequiredStringFieldIsValid(object, "server") and
            jsonRequiredStringFieldIsValid(object, "tool_name") and
            jsonOptionalStringFieldIsValid(object, "connector_id") and
            jsonOptionalStringFieldIsValid(object, "connector_name") and
            jsonOptionalStringFieldIsValid(object, "tool_title");
    }
    if (std.mem.eql(u8, action_type.string, "request_permissions")) {
        return jsonOptionalStringFieldIsValid(object, "reason") and
            jsonRequiredObjectFieldIsValid(object, "permissions");
    }
    return false;
}

fn guardianCommandSourceFieldIsValid(object: std.json.ObjectMap) bool {
    const source = object.get("source") orelse return false;
    return enumStringIsValid(source, &.{ "shell", "unified_exec" });
}

fn guardianNetworkProtocolFieldIsValid(object: std.json.ObjectMap) bool {
    const protocol = object.get("protocol") orelse return false;
    return enumStringIsValid(protocol, &.{ "http", "https", "https_connect", "http-connect", "socks5_tcp", "socks5_udp" });
}

fn jsonRequiredStringFieldIsValid(object: std.json.ObjectMap, field: []const u8) bool {
    const value = object.get(field) orelse return false;
    return value == .string;
}

fn jsonOptionalStringFieldIsValid(object: std.json.ObjectMap, field: []const u8) bool {
    const value = object.get(field) orelse return true;
    return jsonOptionalStringValueIsValid(value);
}

fn jsonOptionalStringValueIsValid(value: std.json.Value) bool {
    return value == .null or value == .string;
}

fn jsonRequiredStringArrayFieldIsValid(object: std.json.ObjectMap, field: []const u8) bool {
    const value = object.get(field) orelse return false;
    if (value != .array) return false;
    for (value.array.items) |item| {
        if (item != .string) return false;
    }
    return true;
}

fn jsonRequiredObjectFieldIsValid(object: std.json.ObjectMap, field: []const u8) bool {
    const value = object.get(field) orelse return false;
    return value == .object;
}

fn jsonRequiredU16FieldIsValid(object: std.json.ObjectMap, field: []const u8) bool {
    const value = object.get(field) orelse return false;
    return value == .integer and value.integer >= 0 and value.integer <= std.math.maxInt(u16);
}

fn jsonRequiredU32FieldIsValid(object: std.json.ObjectMap, field: []const u8) bool {
    const value = object.get(field) orelse return false;
    return value == .integer and value.integer >= 0 and value.integer <= std.math.maxInt(u32);
}

fn threadMemoryModeParamIsValid(object: std.json.ObjectMap) bool {
    const mode = object.get("mode") orelse return false;
    if (mode != .string) return false;
    return std.mem.eql(u8, mode.string, "enabled") or std.mem.eql(u8, mode.string, "disabled");
}

fn threadReadIncludeTurnsParamIsValid(object: std.json.ObjectMap) bool {
    const include_turns = object.get("includeTurns") orelse return true;
    return include_turns == .bool;
}

fn threadReadIncludeTurnsParam(object: std.json.ObjectMap) bool {
    const include_turns = object.get("includeTurns") orelse return false;
    return include_turns.bool;
}

fn threadTurnsListLimit(object: std.json.ObjectMap) ?usize {
    const limit = object.get("limit") orelse return null;
    if (limit == .null) return null;
    return @intCast(limit.integer);
}

fn validateThreadTurnsListParams(object: std.json.ObjectMap) ?[]const u8 {
    if (object.get("cursor")) |value| {
        if (value != .null and value != .string) return "cursor must be a string or null";
    }
    if (object.get("limit")) |value| {
        switch (value) {
            .null => {},
            .integer => |integer| if (integer < 0 or integer > std.math.maxInt(u32)) return "limit must be a non-negative integer or null",
            else => return "limit must be a non-negative integer or null",
        }
    }
    if (object.get("sortDirection")) |value| {
        if (!optionalEnumStringIsValid(value, &.{ "asc", "desc" })) return "sortDirection must be asc or desc";
    }
    return null;
}

fn validateThreadRealtimeAudioParam(object: std.json.ObjectMap) ?[]const u8 {
    const audio = object.get("audio") orelse return "audio must be an object";
    if (audio != .object) return "audio must be an object";
    return validateThreadRealtimeAudioChunk(audio.object);
}

fn validateThreadRealtimeAudioChunk(object: std.json.ObjectMap) ?[]const u8 {
    if (!jsonRequiredStringFieldIsValid(object, "data")) return "audio.data must be a string";
    if (!jsonRequiredU32FieldIsValid(object, "sampleRate")) return "audio.sampleRate must be a non-negative integer";
    if (!jsonRequiredU16FieldIsValid(object, "numChannels")) return "audio.numChannels must be a non-negative integer";
    if (object.get("samplesPerChannel")) |value| {
        switch (value) {
            .null => {},
            .integer => |integer| if (integer < 0 or integer > std.math.maxInt(u32)) return "audio.samplesPerChannel must be a non-negative integer or null",
            else => return "audio.samplesPerChannel must be a non-negative integer or null",
        }
    }
    if (object.get("itemId")) |value| {
        if (!jsonOptionalStringValueIsValid(value)) return "audio.itemId must be a string or null";
    }
    return null;
}

fn validateThreadGoalSetParams(object: std.json.ObjectMap) ?[]const u8 {
    const has_objective = object.get("objective") != null;
    const has_token_budget = object.get("tokenBudget") != null;
    if (object.get("objective")) |value| {
        if (!jsonOptionalStringValueIsValid(value)) return "goal objective must be a string or null";
        if (value == .string) {
            const objective = std.mem.trim(u8, value.string, " \t\r\n");
            if (objective.len == 0) return "goal objective must not be empty";
            const count = std.unicode.utf8CountCodepoints(objective) catch objective.len;
            if (count > 4000) return "goal objective must be at most 4000 characters";
        }
    }
    if (object.get("status")) |value| {
        if (!optionalEnumStringIsValid(value, &.{ "active", "paused", "budgetLimited", "complete" })) return "goal status must be active, paused, budgetLimited, complete, or null";
    }
    if (object.get("tokenBudget")) |value| {
        if (value != .null and value != .integer) return "goal tokenBudget must be a positive integer or null";
        if ((has_objective or has_token_budget) and value == .integer and value.integer <= 0) {
            return "goal budgets must be positive when provided";
        }
    }
    return null;
}

fn validateThreadRealtimeStartParams(object: std.json.ObjectMap) ?[]const u8 {
    const output_modality = object.get("outputModality") orelse return "outputModality must be text or audio";
    if (!enumStringIsValid(output_modality, &.{ "text", "audio" })) return "outputModality must be text or audio";
    if (object.get("prompt")) |value| {
        if (!jsonOptionalStringValueIsValid(value)) return "prompt must be a string or null";
    }
    if (object.get("realtimeSessionId")) |value| {
        if (!jsonOptionalStringValueIsValid(value)) return "realtimeSessionId must be a string or null";
    }
    if (object.get("voice")) |value| {
        if (!optionalEnumStringIsValid(value, &.{ "alloy", "arbor", "ash", "ballad", "breeze", "cedar", "coral", "cove", "echo", "ember", "juniper", "maple", "marin", "sage", "shimmer", "sol", "spruce", "vale", "verse" })) return "voice must be a supported realtime voice or null";
    }
    if (object.get("transport")) |value| {
        if (value == .null) return null;
        if (value != .object) return "transport must be an object or null";
        return validateThreadRealtimeStartTransport(value.object);
    }
    return null;
}

fn validateThreadRealtimeStartTransport(object: std.json.ObjectMap) ?[]const u8 {
    const transport_type = object.get("type") orelse return "transport.type must be websocket or webrtc";
    if (transport_type != .string) return "transport.type must be websocket or webrtc";
    if (std.mem.eql(u8, transport_type.string, "websocket")) return null;
    if (std.mem.eql(u8, transport_type.string, "webrtc")) {
        if (!jsonRequiredStringFieldIsValid(object, "sdp")) return "transport.sdp must be a string";
        return null;
    }
    return "transport.type must be websocket or webrtc";
}

const ThreadMetadataGitInfoValidationError = struct {
    code: i64,
    message: []const u8,
};

fn validateThreadMetadataGitInfoParams(object: std.json.ObjectMap) ?ThreadMetadataGitInfoValidationError {
    const git_info = object.get("gitInfo") orelse return .{ .code = -32600, .message = "gitInfo must include at least one field" };
    if (git_info == .null) return .{ .code = -32600, .message = "gitInfo must include at least one field" };
    if (git_info != .object) return .{ .code = -32602, .message = "gitInfo must be an object or null" };

    var saw_field = false;
    if (validateThreadMetadataGitInfoField(git_info.object, "sha", &saw_field)) |err| return err;
    if (validateThreadMetadataGitInfoField(git_info.object, "branch", &saw_field)) |err| return err;
    if (validateThreadMetadataGitInfoField(git_info.object, "originUrl", &saw_field)) |err| return err;
    if (!saw_field) return .{ .code = -32600, .message = "gitInfo must include at least one field" };
    return null;
}

fn validateThreadMetadataGitInfoField(
    object: std.json.ObjectMap,
    field_name: []const u8,
    saw_field: *bool,
) ?ThreadMetadataGitInfoValidationError {
    const value = object.get(field_name) orelse return null;
    saw_field.* = true;
    if (value == .null) return null;
    if (value != .string) {
        return .{ .code = -32602, .message = "gitInfo fields must be strings or null" };
    }
    if (std.mem.trim(u8, value.string, " \t\r\n").len == 0) {
        if (std.mem.eql(u8, field_name, "sha")) return .{ .code = -32600, .message = "gitInfo.sha must not be empty" };
        if (std.mem.eql(u8, field_name, "branch")) return .{ .code = -32600, .message = "gitInfo.branch must not be empty" };
        return .{ .code = -32600, .message = "gitInfo.originUrl must not be empty" };
    }
    return null;
}

