fn appendExternalAgentRolloutLine(allocator: std.mem.Allocator, out: *std.ArrayList(u8), value: anytype) !void {
    const line = try std.json.Stringify.valueAlloc(allocator, value, .{ .emit_null_optional_fields = false });
    defer allocator.free(line);
    try out.appendSlice(allocator, line);
    try out.append(allocator, '\n');
}

fn externalAgentRfc3339Seconds(allocator: std.mem.Allocator, seconds: i64) ![]const u8 {
    const safe_seconds: u64 = if (seconds < 0) 0 else @intCast(seconds);
    return auth_mod.rfc3339FromSeconds(allocator, safe_seconds);
}

fn externalAgentSessionTokenUsage(import_data: ExternalAgentSessionImportData) ExternalAgentRolloutTokenUsage {
    var input_bytes: usize = 0;
    var output_bytes: usize = EXTERNAL_AGENT_SESSION_IMPORTED_MARKER.len;
    for (import_data.messages.items) |message| {
        switch (message.role) {
            .user => input_bytes += message.text.len,
            .assistant => output_bytes += message.text.len,
        }
    }

    const input_tokens = estimateExternalAgentTokenCount(input_bytes);
    const output_tokens = estimateExternalAgentTokenCount(output_bytes);
    return .{
        .input_tokens = input_tokens,
        .cached_input_tokens = 0,
        .output_tokens = output_tokens,
        .reasoning_output_tokens = 0,
        .total_tokens = input_tokens + output_tokens,
    };
}

fn estimateExternalAgentTokenCount(byte_count: usize) i64 {
    if (byte_count == 0) return 0;
    const tokens = @max(@divFloor(byte_count + 3, 4), 1);
    return @intCast(tokens);
}

fn isExternalAgentConfigMigrationItemType(value: []const u8) bool {
    return std.mem.eql(u8, value, "AGENTS_MD") or
        std.mem.eql(u8, value, "CONFIG") or
        std.mem.eql(u8, value, "SKILLS") or
        std.mem.eql(u8, value, "PLUGINS") or
        std.mem.eql(u8, value, "MCP_SERVER_CONFIG") or
        std.mem.eql(u8, value, "SUBAGENTS") or
        std.mem.eql(u8, value, "HOOKS") or
        std.mem.eql(u8, value, "COMMANDS") or
        std.mem.eql(u8, value, "SESSIONS");
}

fn isSupportedExternalAgentConfigImportItem(item: std.json.ObjectMap) bool {
    const item_type = item.get("itemType") orelse return false;
    if (item_type != .string) return false;
    if (!std.mem.eql(u8, item_type.string, "CONFIG") and
        !std.mem.eql(u8, item_type.string, "MCP_SERVER_CONFIG") and
        !std.mem.eql(u8, item_type.string, "HOOKS") and
        !std.mem.eql(u8, item_type.string, "AGENTS_MD") and
        !std.mem.eql(u8, item_type.string, "PLUGINS") and
        !std.mem.eql(u8, item_type.string, "SKILLS") and
        !std.mem.eql(u8, item_type.string, "COMMANDS") and
        !std.mem.eql(u8, item_type.string, "SUBAGENTS") and
        !std.mem.eql(u8, item_type.string, "SESSIONS")) return false;
    if (item.get("cwd")) |cwd| {
        if (cwd != .null and cwd != .string) return false;
    }
    if (item.get("details")) |details| {
        if (details != .null and details != .object) return false;
    }
    return true;
}

fn renderExternalAgentConfigDetectResponse(
    allocator: std.mem.Allocator,
    codex_home: []const u8,
    include_home: bool,
    cwds: []const std.json.Value,
) ![]const u8 {
    var result = std.ArrayList(u8).empty;
    errdefer result.deinit(allocator);
    try result.appendSlice(allocator, "{\"items\":[");
    var first = true;
    if (include_home and try externalAgentHomeConfigNeedsMigration(allocator, codex_home)) {
        const external_settings = try externalAgentHomeSettingsPath(allocator);
        defer allocator.free(external_settings);
        const target_config = try config.configTomlPath(allocator, codex_home);
        defer allocator.free(target_config);
        const description = try std.fmt.allocPrint(allocator, "Migrate {s} into {s}", .{ external_settings, target_config });
        defer allocator.free(description);
        try appendExternalAgentConfigMigrationItem(allocator, &result, &first, "CONFIG", description, null);
    }
    if (include_home) {
        var mcp_plan = try loadExternalAgentHomeMcpPlan(allocator);
        defer mcp_plan.deinit(allocator);
        if (!mcp_plan.isEmpty()) {
            const target_config = try config.configTomlPath(allocator, codex_home);
            defer allocator.free(target_config);
            const config_bytes = try config.readConfigTomlFile(allocator, target_config);
            defer if (config_bytes) |bytes| allocator.free(bytes);
            if (externalAgentMcpPlanHasMissingValues(config_bytes orelse "", mcp_plan)) {
                const source_root = try externalAgentHomeSourceRootPath(allocator);
                defer allocator.free(source_root);
                var names = try externalAgentMcpServerNames(allocator, mcp_plan);
                defer deinitExternalAgentNamedItems(allocator, &names);
                const description = try std.fmt.allocPrint(allocator, "Migrate MCP servers from {s} into {s}", .{ source_root, target_config });
                defer allocator.free(description);
                try appendExternalAgentConfigMigrationItemWithNamedDetails(allocator, &result, &first, "MCP_SERVER_CONFIG", description, null, "mcpServers", names.items);
            }
        }
    }
    if (include_home) {
        const source_hooks_dir = try externalAgentHomePath(allocator);
        defer allocator.free(source_hooks_dir);
        const target_hooks = try externalAgentTargetHooksPath(allocator, codex_home);
        defer allocator.free(target_hooks);
        var hook_names = try missingExternalAgentHookEventNames(allocator, source_hooks_dir, target_hooks);
        defer deinitExternalAgentNamedItems(allocator, &hook_names);
        if (hook_names.items.len > 0) {
            const description = try std.fmt.allocPrint(allocator, "Migrate hooks from {s} to {s}", .{ source_hooks_dir, target_hooks });
            defer allocator.free(description);
            try appendExternalAgentConfigMigrationItemWithNamedDetails(allocator, &result, &first, "HOOKS", description, null, "hooks", hook_names.items);
        }
    }
    if (include_home and try externalAgentHomeSkillsNeedsMigration(allocator, codex_home)) {
        const source_skills = try externalAgentHomeSkillsPath(allocator);
        defer allocator.free(source_skills);
        const target_skills = try externalAgentTargetSkillsPath(allocator, codex_home);
        defer allocator.free(target_skills);
        const description = try std.fmt.allocPrint(allocator, "Migrate skills from {s} to {s}", .{ source_skills, target_skills });
        defer allocator.free(description);
        try appendExternalAgentConfigMigrationItem(allocator, &result, &first, "SKILLS", description, null);
    }
    if (include_home) {
        const source_commands = try externalAgentHomeCommandsPath(allocator);
        defer allocator.free(source_commands);
        const target_skills = try externalAgentTargetSkillsPath(allocator, codex_home);
        defer allocator.free(target_skills);
        var command_names = try missingExternalAgentCommandNames(allocator, source_commands, target_skills);
        defer deinitExternalAgentNamedItems(allocator, &command_names);
        if (command_names.items.len > 0) {
            const description = try std.fmt.allocPrint(allocator, "Migrate commands from {s} to {s}", .{ source_commands, target_skills });
            defer allocator.free(description);
            try appendExternalAgentConfigMigrationItemWithNamedDetails(allocator, &result, &first, "COMMANDS", description, null, "commands", command_names.items);
        }
    }
    if (include_home) {
        const source_agents = try externalAgentHomeSubagentsPath(allocator);
        defer allocator.free(source_agents);
        const target_agents = try externalAgentTargetSubagentsPath(allocator, codex_home);
        defer allocator.free(target_agents);
        var subagent_names = try missingExternalAgentSubagentNames(allocator, source_agents, target_agents);
        defer deinitExternalAgentNamedItems(allocator, &subagent_names);
        if (subagent_names.items.len > 0) {
            const description = try std.fmt.allocPrint(allocator, "Migrate subagents from {s} to {s}", .{ source_agents, target_agents });
            defer allocator.free(description);
            try appendExternalAgentConfigMigrationItemWithNamedDetails(allocator, &result, &first, "SUBAGENTS", description, null, "subagents", subagent_names.items);
        }
    }
    if (include_home and try externalAgentHomeAgentsMdNeedsMigration(allocator, codex_home)) {
        const source_agents_md = try externalAgentHomeAgentsMdPath(allocator);
        defer allocator.free(source_agents_md);
        const target_agents_md = try externalAgentTargetAgentsMdPath(allocator, codex_home);
        defer allocator.free(target_agents_md);
        const description = try std.fmt.allocPrint(allocator, "Migrate {s} to {s}", .{ source_agents_md, target_agents_md });
        defer allocator.free(description);
        try appendExternalAgentConfigMigrationItem(allocator, &result, &first, "AGENTS_MD", description, null);
    }
    if (include_home) {
        const source_settings = try externalAgentHomeSettingsPath(allocator);
        defer allocator.free(source_settings);
        const source_root = try externalAgentHomePath(allocator);
        defer allocator.free(source_root);
        var plugin_details = try externalAgentPluginMigrationDetails(allocator, source_settings, source_root, codex_home);
        defer plugin_details.deinit(allocator);
        if (!plugin_details.isEmpty()) {
            const description = try std.fmt.allocPrint(allocator, "Migrate enabled plugins from {s}", .{source_settings});
            defer allocator.free(description);
            try appendExternalAgentConfigMigrationItemWithPluginDetails(allocator, &result, &first, description, null, plugin_details);
        }
    }
    if (include_home) {
        var session_details = try externalAgentSessionMigrationDetails(allocator, codex_home);
        defer session_details.deinit(allocator);
        if (!session_details.isEmpty()) {
            const external_home = try externalAgentHomePath(allocator);
            defer allocator.free(external_home);
            const projects_dir = try std.fs.path.join(allocator, &.{ external_home, "projects" });
            defer allocator.free(projects_dir);
            const description = try std.fmt.allocPrint(allocator, "Migrate recent sessions from {s}", .{projects_dir});
            defer allocator.free(description);
            try appendExternalAgentConfigMigrationItemWithSessionDetails(allocator, &result, &first, description, session_details);
        }
    }

    for (cwds) |cwd| {
        const repo_root = (try findExternalAgentRepoRoot(allocator, cwd.string)) orelse continue;
        defer allocator.free(repo_root);

        if (try externalAgentProjectConfigNeedsMigration(allocator, repo_root)) {
            const source_settings = try externalAgentProjectSettingsPath(allocator, repo_root);
            defer allocator.free(source_settings);
            const target_config = try externalAgentProjectConfigPath(allocator, repo_root);
            defer allocator.free(target_config);
            const description = try std.fmt.allocPrint(allocator, "Migrate {s} into {s}", .{ source_settings, target_config });
            defer allocator.free(description);
            try appendExternalAgentConfigMigrationItem(allocator, &result, &first, "CONFIG", description, repo_root);
        }
        {
            var mcp_plan = try loadExternalAgentProjectMcpPlan(allocator, repo_root);
            defer mcp_plan.deinit(allocator);
            if (!mcp_plan.isEmpty()) {
                const target_config = try externalAgentProjectConfigPath(allocator, repo_root);
                defer allocator.free(target_config);
                const config_bytes = try config.readConfigTomlFile(allocator, target_config);
                defer if (config_bytes) |bytes| allocator.free(bytes);
                if (externalAgentMcpPlanHasMissingValues(config_bytes orelse "", mcp_plan)) {
                    var names = try externalAgentMcpServerNames(allocator, mcp_plan);
                    defer deinitExternalAgentNamedItems(allocator, &names);
                    const description = try std.fmt.allocPrint(allocator, "Migrate MCP servers from {s} into {s}", .{ repo_root, target_config });
                    defer allocator.free(description);
                    try appendExternalAgentConfigMigrationItemWithNamedDetails(allocator, &result, &first, "MCP_SERVER_CONFIG", description, repo_root, "mcpServers", names.items);
                }
            }
        }
        {
            const source_hooks_dir = try externalAgentProjectDirPath(allocator, repo_root);
            defer allocator.free(source_hooks_dir);
            const target_hooks = try externalAgentProjectTargetHooksPath(allocator, repo_root);
            defer allocator.free(target_hooks);
            var hook_names = try missingExternalAgentHookEventNames(allocator, source_hooks_dir, target_hooks);
            defer deinitExternalAgentNamedItems(allocator, &hook_names);
            if (hook_names.items.len > 0) {
                const description = try std.fmt.allocPrint(allocator, "Migrate hooks from {s} to {s}", .{ source_hooks_dir, target_hooks });
                defer allocator.free(description);
                try appendExternalAgentConfigMigrationItemWithNamedDetails(allocator, &result, &first, "HOOKS", description, repo_root, "hooks", hook_names.items);
            }
        }
        if (try externalAgentProjectSkillsNeedsMigration(allocator, repo_root)) {
            const source_skills = try externalAgentProjectSkillsPath(allocator, repo_root);
            defer allocator.free(source_skills);
            const target_skills = try externalAgentProjectTargetSkillsPath(allocator, repo_root);
            defer allocator.free(target_skills);
            const description = try std.fmt.allocPrint(allocator, "Migrate skills from {s} to {s}", .{ source_skills, target_skills });
            defer allocator.free(description);
            try appendExternalAgentConfigMigrationItem(allocator, &result, &first, "SKILLS", description, repo_root);
        }
        {
            const source_commands = try externalAgentProjectCommandsPath(allocator, repo_root);
            defer allocator.free(source_commands);
            const target_skills = try externalAgentProjectTargetSkillsPath(allocator, repo_root);
            defer allocator.free(target_skills);
            var command_names = try missingExternalAgentCommandNames(allocator, source_commands, target_skills);
            defer deinitExternalAgentNamedItems(allocator, &command_names);
            if (command_names.items.len > 0) {
                const description = try std.fmt.allocPrint(allocator, "Migrate commands from {s} to {s}", .{ source_commands, target_skills });
                defer allocator.free(description);
                try appendExternalAgentConfigMigrationItemWithNamedDetails(allocator, &result, &first, "COMMANDS", description, repo_root, "commands", command_names.items);
            }
        }
        {
            const source_agents = try externalAgentProjectSubagentsPath(allocator, repo_root);
            defer allocator.free(source_agents);
            const target_agents = try externalAgentProjectTargetSubagentsPath(allocator, repo_root);
            defer allocator.free(target_agents);
            var subagent_names = try missingExternalAgentSubagentNames(allocator, source_agents, target_agents);
            defer deinitExternalAgentNamedItems(allocator, &subagent_names);
            if (subagent_names.items.len > 0) {
                const description = try std.fmt.allocPrint(allocator, "Migrate subagents from {s} to {s}", .{ source_agents, target_agents });
                defer allocator.free(description);
                try appendExternalAgentConfigMigrationItemWithNamedDetails(allocator, &result, &first, "SUBAGENTS", description, repo_root, "subagents", subagent_names.items);
            }
        }
        if (try externalAgentProjectAgentsMdNeedsMigration(allocator, repo_root)) {
            const source_agents_md = (try externalAgentProjectAgentsMdSourcePath(allocator, repo_root)).?;
            defer allocator.free(source_agents_md);
            const target_agents_md = try externalAgentProjectTargetAgentsMdPath(allocator, repo_root);
            defer allocator.free(target_agents_md);
            const description = try std.fmt.allocPrint(allocator, "Migrate {s} to {s}", .{ source_agents_md, target_agents_md });
            defer allocator.free(description);
            try appendExternalAgentConfigMigrationItem(allocator, &result, &first, "AGENTS_MD", description, repo_root);
        }
        {
            const source_settings = try externalAgentProjectSettingsPath(allocator, repo_root);
            defer allocator.free(source_settings);
            var plugin_details = try externalAgentPluginMigrationDetails(allocator, source_settings, repo_root, codex_home);
            defer plugin_details.deinit(allocator);
            if (!plugin_details.isEmpty()) {
                const description = try std.fmt.allocPrint(allocator, "Migrate enabled plugins from {s}", .{source_settings});
                defer allocator.free(description);
                try appendExternalAgentConfigMigrationItemWithPluginDetails(allocator, &result, &first, description, repo_root, plugin_details);
            }
        }
    }
    try result.appendSlice(allocator, "]}");
    return result.toOwnedSlice(allocator);
}

fn appendExternalAgentConfigMigrationItem(
    allocator: std.mem.Allocator,
    result: *std.ArrayList(u8),
    first: *bool,
    item_type: []const u8,
    description: []const u8,
    cwd: ?[]const u8,
) !void {
    if (!first.*) try result.appendSlice(allocator, ",");
    try result.appendSlice(allocator, "{\"itemType\":");
    try appendJsonString(allocator, result, item_type);
    try result.appendSlice(allocator, ",\"description\":");
    try appendJsonString(allocator, result, description);
    try result.appendSlice(allocator, ",\"cwd\":");
    if (cwd) |cwd_value| {
        try appendJsonString(allocator, result, cwd_value);
    } else {
        try result.appendSlice(allocator, "null");
    }
    try result.appendSlice(allocator, ",\"details\":null}");
    first.* = false;
}

fn appendExternalAgentConfigMigrationItemWithNamedDetails(
    allocator: std.mem.Allocator,
    result: *std.ArrayList(u8),
    first: *bool,
    item_type: []const u8,
    description: []const u8,
    cwd: ?[]const u8,
    detail_field: []const u8,
    names: []const []const u8,
) !void {
    if (!first.*) try result.appendSlice(allocator, ",");
    try result.appendSlice(allocator, "{\"itemType\":");
    try appendJsonString(allocator, result, item_type);
    try result.appendSlice(allocator, ",\"description\":");
    try appendJsonString(allocator, result, description);
    try result.appendSlice(allocator, ",\"cwd\":");
    if (cwd) |cwd_value| {
        try appendJsonString(allocator, result, cwd_value);
    } else {
        try result.appendSlice(allocator, "null");
    }
    try result.appendSlice(allocator, ",\"details\":{\"plugins\":[],\"sessions\":[],\"mcpServers\":");
    if (std.mem.eql(u8, detail_field, "mcpServers")) {
        try appendExternalAgentNamedDetailsArray(allocator, result, names);
    } else {
        try result.appendSlice(allocator, "[]");
    }
    try result.appendSlice(allocator, ",\"hooks\":");
    if (std.mem.eql(u8, detail_field, "hooks")) {
        try appendExternalAgentNamedDetailsArray(allocator, result, names);
    } else {
        try result.appendSlice(allocator, "[]");
    }
    try result.appendSlice(allocator, ",\"subagents\":");
    if (std.mem.eql(u8, detail_field, "subagents")) {
        try appendExternalAgentNamedDetailsArray(allocator, result, names);
    } else {
        try result.appendSlice(allocator, "[]");
    }
    try result.appendSlice(allocator, ",\"commands\":");
    if (std.mem.eql(u8, detail_field, "commands")) {
        try appendExternalAgentNamedDetailsArray(allocator, result, names);
    } else {
        try result.appendSlice(allocator, "[]");
    }
    try result.appendSlice(allocator, "}}");
    first.* = false;
}

fn appendExternalAgentConfigMigrationItemWithPluginDetails(
    allocator: std.mem.Allocator,
    result: *std.ArrayList(u8),
    first: *bool,
    description: []const u8,
    cwd: ?[]const u8,
    details: ExternalAgentPluginMigrationDetails,
) !void {
    if (!first.*) try result.appendSlice(allocator, ",");
    try result.appendSlice(allocator, "{\"itemType\":\"PLUGINS\",\"description\":");
    try appendJsonString(allocator, result, description);
    try result.appendSlice(allocator, ",\"cwd\":");
    if (cwd) |cwd_value| {
        try appendJsonString(allocator, result, cwd_value);
    } else {
        try result.appendSlice(allocator, "null");
    }
    try result.appendSlice(allocator, ",\"details\":{\"plugins\":[");
    for (details.groups.items, 0..) |group, group_index| {
        if (group_index != 0) try result.appendSlice(allocator, ",");
        try result.appendSlice(allocator, "{\"marketplaceName\":");
        try appendJsonString(allocator, result, group.marketplace_name);
        try result.appendSlice(allocator, ",\"pluginNames\":");
        try appendJsonStringArray(allocator, result, group.plugin_names.items);
        try result.appendSlice(allocator, "}");
    }
    try result.appendSlice(allocator, "],\"sessions\":[],\"mcpServers\":[],\"hooks\":[],\"subagents\":[],\"commands\":[]}}");
    first.* = false;
}

fn appendExternalAgentConfigMigrationItemWithSessionDetails(
    allocator: std.mem.Allocator,
    result: *std.ArrayList(u8),
    first: *bool,
    description: []const u8,
    details: ExternalAgentSessionMigrationDetails,
) !void {
    if (!first.*) try result.appendSlice(allocator, ",");
    try result.appendSlice(allocator, "{\"itemType\":\"SESSIONS\",\"description\":");
    try appendJsonString(allocator, result, description);
    try result.appendSlice(allocator, ",\"cwd\":null,\"details\":{\"plugins\":[],\"sessions\":[");
    for (details.sessions.items, 0..) |session, index| {
        if (index != 0) try result.appendSlice(allocator, ",");
        try result.appendSlice(allocator, "{\"path\":");
        try appendJsonString(allocator, result, session.path);
        try result.appendSlice(allocator, ",\"cwd\":");
        try appendJsonString(allocator, result, session.cwd);
        try result.appendSlice(allocator, ",\"title\":");
        try appendOptionalJsonString(allocator, result, session.title);
        try result.appendSlice(allocator, "}");
    }
    try result.appendSlice(allocator, "],\"mcpServers\":[],\"hooks\":[],\"subagents\":[],\"commands\":[]}}");
    first.* = false;
}

fn appendExternalAgentNamedDetailsArray(allocator: std.mem.Allocator, result: *std.ArrayList(u8), names: []const []const u8) !void {
    try result.appendSlice(allocator, "[");
    for (names, 0..) |name, index| {
        if (index != 0) try result.appendSlice(allocator, ",");
        try result.appendSlice(allocator, "{\"name\":");
        try appendJsonString(allocator, result, name);
        try result.appendSlice(allocator, "}");
    }
    try result.appendSlice(allocator, "]");
}

