fn importExternalAgentPluginsAt(
    allocator: std.mem.Allocator,
    codex_home: []const u8,
    source_settings: []const u8,
    source_root: []const u8,
    details_value: ?std.json.Value,
) !void {
    var details = try parseExternalAgentPluginMigrationDetails(allocator, details_value);
    defer details.deinit(allocator);
    if (details.isEmpty()) return;

    var sources = try loadExternalAgentMarketplaceImportSources(allocator, source_settings, source_root);
    defer deinitExternalAgentMarketplaceImportSources(allocator, &sources);

    const config_path = try config.configTomlPath(allocator, codex_home);
    defer allocator.free(config_path);
    const config_bytes = try config.readConfigTomlFile(allocator, config_path);
    defer if (config_bytes) |bytes| allocator.free(bytes);
    var current: []const u8 = try allocator.dupe(u8, config_bytes orelse "");
    defer allocator.free(current);

    const empty_sparse_paths: []const []const u8 = &.{};
    for (details.groups.items) |group| {
        const import_source = externalAgentMarketplaceImportSourceForName(sources.items, group.marketplace_name) orelse continue;
        if (!externalAgentMarketplaceSourceIsLocal(import_source.source)) continue;

        var add = marketplace_config.addLocalMarketplace(allocator, current, import_source.source, import_source.ref_name, empty_sparse_paths) catch |err| switch (err) {
            error.OutOfMemory => return err,
            else => continue,
        };
        defer add.deinit(allocator);
        try config.writeConfigTomlFile(config_path, add.updated_config);
        allocator.free(current);
        current = try allocator.dupe(u8, add.updated_config);

        const marketplace_path = (try externalAgentMarketplaceManifestPath(allocator, add.installed_root)) orelse continue;
        defer allocator.free(marketplace_path);
        for (group.plugin_names.items) |plugin_name| {
            var install = plugin_list.installLocalPlugin(allocator, codex_home, current, marketplace_path, plugin_name) catch |err| switch (err) {
                error.OutOfMemory => return err,
                else => continue,
            };
            defer install.deinit(allocator);
            try config.writeConfigTomlFile(config_path, install.updated_config);
            allocator.free(current);
            current = try allocator.dupe(u8, install.updated_config);
        }
    }
}

fn externalAgentPluginMigrationDetails(
    allocator: std.mem.Allocator,
    source_settings: []const u8,
    source_root: []const u8,
    codex_home: []const u8,
) !ExternalAgentPluginMigrationDetails {
    var enabled_plugins = try loadExternalAgentEnabledPlugins(allocator, source_settings);
    defer deinitExternalAgentNamedItems(allocator, &enabled_plugins);
    var sources = try loadExternalAgentMarketplaceImportSources(allocator, source_settings, source_root);
    defer deinitExternalAgentMarketplaceImportSources(allocator, &sources);

    const config_path = try config.configTomlPath(allocator, codex_home);
    defer allocator.free(config_path);
    const config_bytes = try config.readConfigTomlFile(allocator, config_path);
    defer if (config_bytes) |bytes| allocator.free(bytes);
    const configured_plugins = try plugin_config.enabledPluginIds(allocator, config_bytes orelse "");
    defer plugin_config.freeStringList(allocator, configured_plugins);

    var details = ExternalAgentPluginMigrationDetails{};
    errdefer details.deinit(allocator);
    for (enabled_plugins.items) |plugin_id| {
        if (externalAgentStringListContains(configured_plugins, plugin_id)) continue;
        const parts = plugin_config.splitPluginId(plugin_id) orelse continue;
        const import_source = externalAgentMarketplaceImportSourceForName(sources.items, parts.marketplace) orelse continue;
        if (!externalAgentMarketplaceSourceIsLocal(import_source.source)) continue;
        if (!try externalAgentMarketplaceContainsPlugin(allocator, import_source.source, parts.name)) continue;
        try putExternalAgentPluginMigration(allocator, &details, parts.marketplace, parts.name);
    }
    std.mem.sort(ExternalAgentPluginMigrationGroup, details.groups.items, {}, externalAgentPluginMigrationGroupLessThan);
    return details;
}

fn parseExternalAgentPluginMigrationDetails(allocator: std.mem.Allocator, details_value: ?std.json.Value) !ExternalAgentPluginMigrationDetails {
    const details_object = details_value orelse return error.InvalidExternalAgentPluginDetails;
    if (details_object != .object) return error.InvalidExternalAgentPluginDetails;
    const plugins = details_object.object.get("plugins") orelse return error.InvalidExternalAgentPluginDetails;
    if (plugins != .array) return error.InvalidExternalAgentPluginDetails;

    var details = ExternalAgentPluginMigrationDetails{};
    errdefer details.deinit(allocator);
    for (plugins.array.items) |group_value| {
        if (group_value != .object) return error.InvalidExternalAgentPluginDetails;
        const marketplace_name = group_value.object.get("marketplaceName") orelse return error.InvalidExternalAgentPluginDetails;
        const plugin_names = group_value.object.get("pluginNames") orelse return error.InvalidExternalAgentPluginDetails;
        if (marketplace_name != .string or plugin_names != .array) return error.InvalidExternalAgentPluginDetails;
        if (!plugin_config.isValidPluginSegment(marketplace_name.string)) continue;
        for (plugin_names.array.items) |plugin_name| {
            if (plugin_name != .string or !plugin_config.isValidPluginSegment(plugin_name.string)) continue;
            try putExternalAgentPluginMigration(allocator, &details, marketplace_name.string, plugin_name.string);
        }
    }
    return details;
}

fn externalAgentSessionMigrationDetails(allocator: std.mem.Allocator, codex_home: []const u8) !ExternalAgentSessionMigrationDetails {
    var ledger = try loadExternalAgentSessionImportLedger(allocator, codex_home);
    defer ledger.deinit(allocator);

    const external_home = try externalAgentHomePath(allocator);
    defer allocator.free(external_home);
    const projects_dir = try std.fs.path.join(allocator, &.{ external_home, "projects" });
    defer allocator.free(projects_dir);

    var details = ExternalAgentSessionMigrationDetails{};
    errdefer details.deinit(allocator);

    const io = std.Io.Threaded.global_single_threaded.io();
    var projects = std.Io.Dir.openDirAbsolute(io, projects_dir, .{ .iterate = true }) catch |err| switch (err) {
        error.FileNotFound => return details,
        error.NotDir => return details,
        else => return err,
    };
    defer projects.close(io);

    var project_iter = projects.iterate();
    while (try project_iter.next(io)) |project_entry| {
        if (project_entry.kind != .directory) continue;
        const project_dir = try std.fs.path.join(allocator, &.{ projects_dir, project_entry.name });
        defer allocator.free(project_dir);
        try appendExternalAgentSessionMigrationsInProjectDir(allocator, &details, &ledger, project_dir);
    }

    std.mem.sort(ExternalAgentSessionMigration, details.sessions.items, {}, externalAgentSessionMigrationLessThan);
    while (details.sessions.items.len > EXTERNAL_AGENT_SESSION_IMPORT_MAX_COUNT) {
        details.sessions.items[details.sessions.items.len - 1].deinit(allocator);
        details.sessions.shrinkRetainingCapacity(details.sessions.items.len - 1);
    }
    return details;
}

fn appendExternalAgentSessionMigrationsInProjectDir(
    allocator: std.mem.Allocator,
    details: *ExternalAgentSessionMigrationDetails,
    ledger: *ExternalAgentSessionImportLedger,
    project_dir: []const u8,
) !void {
    const io = std.Io.Threaded.global_single_threaded.io();
    var dir = std.Io.Dir.openDirAbsolute(io, project_dir, .{ .iterate = true }) catch |err| switch (err) {
        error.FileNotFound => return,
        error.NotDir => return,
        else => return err,
    };
    defer dir.close(io);

    var iter = dir.iterate();
    while (try iter.next(io)) |entry| {
        if (entry.kind != .file) continue;
        if (!std.mem.endsWith(u8, entry.name, ".jsonl")) continue;

        const raw_path = try std.fs.path.join(allocator, &.{ project_dir, entry.name });
        defer allocator.free(raw_path);
        const source_path = externalAgentSessionSourcePath(allocator, raw_path) catch |err| switch (err) {
            error.OutOfMemory => return err,
            else => continue,
        };
        defer allocator.free(source_path);

        if (ledger.containsCurrentSource(allocator, source_path) catch |err| switch (err) {
            error.OutOfMemory => return err,
            else => continue,
        }) continue;

        var import_data = (loadExternalAgentSessionForImport(allocator, source_path) catch |err| switch (err) {
            error.OutOfMemory => return err,
            else => continue,
        }) orelse continue;
        defer import_data.deinit(allocator);

        if (!externalAgentSessionIsRecent(import_data.latest_timestamp_seconds)) continue;
        const cwd_exists = externalAgentPathExists(allocator, import_data.cwd) catch |err| switch (err) {
            error.OutOfMemory => return err,
            else => false,
        };
        if (!cwd_exists) continue;

        var migration = ExternalAgentSessionMigration{
            .path = try allocator.dupe(u8, source_path),
            .cwd = try allocator.dupe(u8, import_data.cwd),
            .title = if (import_data.title) |title| try allocator.dupe(u8, title) else null,
            .latest_timestamp_seconds = import_data.latest_timestamp_seconds,
        };
        errdefer migration.deinit(allocator);
        try details.sessions.append(allocator, migration);
    }
}

fn parseExternalAgentSessionMigrationDetails(allocator: std.mem.Allocator, details_value: ?std.json.Value) !ExternalAgentSessionMigrationDetails {
    const details_object = details_value orelse return error.InvalidExternalAgentSessionDetails;
    if (details_object != .object) return error.InvalidExternalAgentSessionDetails;
    const sessions = details_object.object.get("sessions") orelse return error.InvalidExternalAgentSessionDetails;
    if (sessions != .array) return error.InvalidExternalAgentSessionDetails;

    var details = ExternalAgentSessionMigrationDetails{};
    errdefer details.deinit(allocator);
    for (sessions.array.items) |session_value| {
        if (session_value != .object) return error.InvalidExternalAgentSessionDetails;
        const path = externalAgentJsonString(session_value.object, "path") orelse return error.InvalidExternalAgentSessionDetails;
        const cwd = externalAgentJsonString(session_value.object, "cwd") orelse return error.InvalidExternalAgentSessionDetails;
        const title = externalAgentJsonString(session_value.object, "title");
        var migration = ExternalAgentSessionMigration{
            .path = try allocator.dupe(u8, path),
            .cwd = try allocator.dupe(u8, cwd),
            .title = if (title) |value| try allocator.dupe(u8, value) else null,
        };
        errdefer migration.deinit(allocator);
        try details.sessions.append(allocator, migration);
    }
    return details;
}

fn externalAgentSessionDetailsContainsPath(details: ExternalAgentSessionMigrationDetails, path: []const u8) bool {
    for (details.sessions.items) |session_migration| {
        if (std.mem.eql(u8, session_migration.path, path)) return true;
    }
    return false;
}

fn loadExternalAgentSessionForImport(allocator: std.mem.Allocator, source_path: []const u8) !?ExternalAgentSessionImportData {
    const bytes = try readExternalAgentSessionFile(allocator, source_path);
    defer allocator.free(bytes);

    var cwd: ?[]const u8 = null;
    errdefer if (cwd) |value| allocator.free(value);
    var custom_title: ?[]const u8 = null;
    errdefer if (custom_title) |value| allocator.free(value);
    var ai_title: ?[]const u8 = null;
    errdefer if (ai_title) |value| allocator.free(value);
    var fallback_title: ?[]const u8 = null;
    errdefer if (fallback_title) |value| allocator.free(value);
    var latest_timestamp: ?i64 = null;
    var messages = std.ArrayList(ExternalAgentSessionMessage).empty;
    errdefer {
        for (messages.items) |*message| message.deinit(allocator);
        messages.deinit(allocator);
    }

    var lines = std.mem.splitScalar(u8, bytes, '\n');
    while (lines.next()) |line_raw| {
        const line = std.mem.trim(u8, line_raw, " \t\r");
        if (line.len == 0) continue;

        var parsed = std.json.parseFromSlice(std.json.Value, allocator, line, .{}) catch |err| switch (err) {
            error.OutOfMemory => return err,
            else => continue,
        };
        defer parsed.deinit();
        if (parsed.value != .object) continue;

        if (cwd == null) {
            if (externalAgentJsonString(parsed.value.object, "cwd")) |value| {
                cwd = try allocator.dupe(u8, value);
            }
        }
        if (externalAgentTitleFromRecord(parsed.value.object, "custom-title", "customTitle")) |title| {
            if (custom_title) |previous| allocator.free(previous);
            custom_title = try allocator.dupe(u8, title);
        }
        if (externalAgentTitleFromRecord(parsed.value.object, "ai-title", "aiTitle")) |title| {
            if (ai_title) |previous| allocator.free(previous);
            ai_title = try allocator.dupe(u8, title);
        }

        var message = (try externalAgentConversationMessageFromRecord(allocator, parsed.value.object)) orelse continue;
        errdefer message.deinit(allocator);
        if (fallback_title == null and message.role == .user) {
            fallback_title = try summarizeExternalAgentSessionTitle(allocator, message.text);
        }
        if (message.timestamp_seconds) |timestamp| {
            latest_timestamp = if (latest_timestamp) |current| @max(current, timestamp) else timestamp;
        }
        try messages.append(allocator, message);
    }

    if (cwd == null or messages.items.len == 0 or latest_timestamp == null) return null;
    var title: ?[]const u8 = null;
    if (custom_title) |value| {
        title = value;
        custom_title = null;
    } else if (ai_title) |value| {
        title = value;
        ai_title = null;
    } else if (fallback_title) |value| {
        title = value;
        fallback_title = null;
    }

    const owned_cwd = cwd.?;
    cwd = null;
    return ExternalAgentSessionImportData{
        .cwd = owned_cwd,
        .title = title,
        .latest_timestamp_seconds = latest_timestamp.?,
        .messages = messages,
    };
}

fn externalAgentConversationMessageFromRecord(
    allocator: std.mem.Allocator,
    object: std.json.ObjectMap,
) !?ExternalAgentSessionMessage {
    const record_type = externalAgentJsonString(object, "type") orelse return null;
    const is_user = std.mem.eql(u8, record_type, "user");
    const is_assistant = std.mem.eql(u8, record_type, "assistant");
    if (!is_user and !is_assistant) return null;
    if (externalAgentJsonBoolIsTrue(object, "isMeta") or externalAgentJsonBoolIsTrue(object, "isSidechain")) return null;
    const message = object.get("message") orelse return null;
    if (message != .object) return null;
    const content = message.object.get("content") orelse return null;

    var extracted = (try extractExternalAgentMessageText(allocator, content)) orelse return null;
    defer extracted.deinit(allocator);

    const timestamp_seconds = if (externalAgentJsonString(object, "timestamp")) |timestamp|
        if (parseThreadListRfc3339Milliseconds(timestamp)) |timestamp_ms| @divFloor(timestamp_ms, 1000) else null
    else
        null;

    const role: ExternalAgentSessionRole = if (is_assistant or extracted.only_tool_result) .assistant else .user;
    return ExternalAgentSessionMessage{
        .role = role,
        .text = try allocator.dupe(u8, extracted.text),
        .timestamp_seconds = timestamp_seconds,
    };
}

fn extractExternalAgentMessageText(allocator: std.mem.Allocator, content: std.json.Value) !?ExternalAgentExtractedMessage {
    if (content == .string) {
        if (std.mem.trim(u8, content.string, " \t\r\n").len == 0) return null;
        return .{ .text = try allocator.dupe(u8, content.string), .only_tool_result = false };
    }
    if (content != .array) return null;

    var parts = std.ArrayList([]const u8).empty;
    defer deinitExternalAgentNamedItems(allocator, &parts);
    var only_tool_result = content.array.items.len > 0;

    for (content.array.items) |block| {
        if (block != .object) continue;
        const block_type = externalAgentJsonString(block.object, "type") orelse continue;
        if (std.mem.eql(u8, block_type, "text")) {
            const text = externalAgentJsonString(block.object, "text") orelse continue;
            if (std.mem.trim(u8, text, " \t\r\n").len == 0) continue;
            try parts.append(allocator, try allocator.dupe(u8, text));
            only_tool_result = false;
        } else if (std.mem.eql(u8, block_type, "tool_use")) {
            try parts.append(allocator, try externalAgentToolCallNote(allocator, block.object));
            only_tool_result = false;
        } else if (std.mem.eql(u8, block_type, "tool_result")) {
            try parts.append(allocator, try externalAgentToolResultNote(allocator, block.object));
        } else if (std.mem.eql(u8, block_type, "thinking")) {
            continue;
        } else {
            const note = try std.fmt.allocPrint(allocator, "[external unsupported block: {s}]", .{block_type});
            try parts.append(allocator, note);
            only_tool_result = false;
        }
    }

    const text = try joinExternalAgentMessageParts(allocator, parts.items);
    if (std.mem.trim(u8, text, " \t\r\n").len == 0) {
        allocator.free(text);
        return null;
    }
    return .{ .text = text, .only_tool_result = only_tool_result };
}

fn externalAgentToolCallNote(allocator: std.mem.Allocator, block: std.json.ObjectMap) ![]const u8 {
    const name = externalAgentJsonString(block, "name") orelse "unknown";
    var out = std.ArrayList(u8).empty;
    errdefer out.deinit(allocator);
    try out.appendSlice(allocator, "[");
    try out.appendSlice(allocator, EXTERNAL_AGENT_TOOL_CALL_TAG);
    try out.appendSlice(allocator, ": ");
    try out.appendSlice(allocator, name);
    try out.appendSlice(allocator, "]");

    if (block.get("input")) |input| {
        if (input == .object) {
            var added_field = false;
            if (externalAgentJsonString(input.object, "description")) |description| {
                try out.appendSlice(allocator, "\ndescription: ");
                try out.appendSlice(allocator, description);
                added_field = true;
            }
            if (externalAgentJsonString(input.object, "command")) |command| {
                try out.appendSlice(allocator, "\ncommand: ");
                try out.appendSlice(allocator, command);
                added_field = true;
            }
            const file = externalAgentJsonString(input.object, "file_path") orelse externalAgentJsonString(input.object, "file");
            if (file) |file_value| {
                try out.appendSlice(allocator, "\nfile: ");
                try out.appendSlice(allocator, file_value);
                added_field = true;
            }
            if (!added_field) try appendExternalAgentJsonNote(allocator, &out, "input", input, EXTERNAL_AGENT_NOTE_MAX_LEN);
        } else {
            try appendExternalAgentJsonNote(allocator, &out, "input", input, EXTERNAL_AGENT_NOTE_MAX_LEN);
        }
    }

    try out.appendSlice(allocator, "\n[/");
    try out.appendSlice(allocator, EXTERNAL_AGENT_TOOL_CALL_TAG);
    try out.appendSlice(allocator, "]");
    return out.toOwnedSlice(allocator);
}

fn externalAgentToolResultNote(allocator: std.mem.Allocator, block: std.json.ObjectMap) ![]const u8 {
    const text = try externalAgentToolResultText(allocator, block.get("content"));
    defer allocator.free(text);
    const truncated = try externalAgentTruncate(allocator, text, EXTERNAL_AGENT_TOOL_RESULT_MAX_LEN);
    defer allocator.free(truncated);

    var out = std.ArrayList(u8).empty;
    errdefer out.deinit(allocator);
    if (externalAgentJsonBoolIsTrue(block, "is_error")) {
        try out.appendSlice(allocator, "[");
        try out.appendSlice(allocator, EXTERNAL_AGENT_TOOL_RESULT_TAG);
        try out.appendSlice(allocator, ": error]");
    } else {
        try out.appendSlice(allocator, "[");
        try out.appendSlice(allocator, EXTERNAL_AGENT_TOOL_RESULT_TAG);
        try out.appendSlice(allocator, "]");
    }
    if (truncated.len > 0) {
        try out.append(allocator, '\n');
        try out.appendSlice(allocator, truncated);
    }
    try out.appendSlice(allocator, "\n[/");
    try out.appendSlice(allocator, EXTERNAL_AGENT_TOOL_RESULT_TAG);
    try out.appendSlice(allocator, "]");
    return out.toOwnedSlice(allocator);
}

fn externalAgentToolResultText(allocator: std.mem.Allocator, content_value: ?std.json.Value) ![]const u8 {
    const content = content_value orelse return allocator.dupe(u8, "");
    if (content == .string) return allocator.dupe(u8, content.string);
    if (content != .array) return allocator.dupe(u8, "");

    var parts = std.ArrayList([]const u8).empty;
    defer deinitExternalAgentNamedItems(allocator, &parts);
    for (content.array.items) |item| {
        if (item != .object) continue;
        const text = externalAgentJsonString(item.object, "text") orelse continue;
        if (text.len == 0) continue;
        try parts.append(allocator, try allocator.dupe(u8, text));
    }
    return joinExternalAgentTextParts(allocator, parts.items, "\n");
}

fn appendExternalAgentJsonNote(
    allocator: std.mem.Allocator,
    out: *std.ArrayList(u8),
    label: []const u8,
    value: std.json.Value,
    max_len: usize,
) !void {
    const raw = try std.json.Stringify.valueAlloc(allocator, value, .{});
    defer allocator.free(raw);
    const truncated = try externalAgentTruncate(allocator, raw, max_len);
    defer allocator.free(truncated);
    try out.append(allocator, '\n');
    try out.appendSlice(allocator, label);
    try out.appendSlice(allocator, ": ");
    try out.appendSlice(allocator, truncated);
}

fn joinExternalAgentMessageParts(allocator: std.mem.Allocator, parts: []const []const u8) ![]const u8 {
    return joinExternalAgentTextParts(allocator, parts, "\n\n");
}

fn joinExternalAgentTextParts(allocator: std.mem.Allocator, parts: []const []const u8, separator: []const u8) ![]const u8 {
    var out = std.ArrayList(u8).empty;
    errdefer out.deinit(allocator);
    var first = true;
    for (parts) |part| {
        if (std.mem.trim(u8, part, " \t\r\n").len == 0) continue;
        if (!first) try out.appendSlice(allocator, separator);
        try out.appendSlice(allocator, part);
        first = false;
    }
    return out.toOwnedSlice(allocator);
}

fn externalAgentTruncate(allocator: std.mem.Allocator, text: []const u8, max_len: usize) ![]const u8 {
    if (text.len <= max_len) return allocator.dupe(u8, text);
    var out = try allocator.alloc(u8, max_len + 3);
    @memcpy(out[0..max_len], text[0..max_len]);
    @memcpy(out[max_len..], "...");
    return out;
}

fn summarizeExternalAgentSessionTitle(allocator: std.mem.Allocator, text: []const u8) ![]const u8 {
    const first_line_end = std.mem.indexOfScalar(u8, text, '\n') orelse text.len;
    const first_line = std.mem.trim(u8, text[0..first_line_end], " \t\r\n");
    if (first_line.len <= 120) return allocator.dupe(u8, first_line);
    return externalAgentTruncate(allocator, first_line, 120);
}

fn externalAgentTitleFromRecord(object: std.json.ObjectMap, record_type: []const u8, field: []const u8) ?[]const u8 {
    const actual_type = externalAgentJsonString(object, "type") orelse return null;
    if (!std.mem.eql(u8, actual_type, record_type)) return null;
    const title = externalAgentJsonString(object, field) orelse return null;
    const trimmed = std.mem.trim(u8, title, " \t\r\n");
    if (trimmed.len == 0) return null;
    return trimmed;
}

fn externalAgentSessionIsRecent(latest_timestamp_seconds: i64) bool {
    return latest_timestamp_seconds >= currentUnixSeconds() - EXTERNAL_AGENT_SESSION_IMPORT_MAX_AGE_SECONDS;
}

fn externalAgentSessionMigrationLessThan(_: void, lhs: ExternalAgentSessionMigration, rhs: ExternalAgentSessionMigration) bool {
    if (lhs.latest_timestamp_seconds != rhs.latest_timestamp_seconds) return lhs.latest_timestamp_seconds > rhs.latest_timestamp_seconds;
    return std.mem.lessThan(u8, lhs.path, rhs.path);
}

fn externalAgentSessionSourcePath(allocator: std.mem.Allocator, path: []const u8) ![]const u8 {
    const source_path = try realPathFileAllocPlain(allocator, path);
    errdefer allocator.free(source_path);

    const external_home = try externalAgentHomePath(allocator);
    defer allocator.free(external_home);
    const projects_path = try std.fs.path.join(allocator, &.{ external_home, "projects" });
    defer allocator.free(projects_path);
    const projects_real = try realPathFileAllocPlain(allocator, projects_path);
    defer allocator.free(projects_real);

    if (!externalAgentPathIsUnderDirectory(source_path, projects_real)) return error.ExternalAgentSessionPathOutsideProjects;
    return source_path;
}

fn externalAgentPathIsUnderDirectory(path: []const u8, directory: []const u8) bool {
    if (path.len <= directory.len) return false;
    if (!std.mem.eql(u8, path[0..directory.len], directory)) return false;
    return path[directory.len] == std.fs.path.sep;
}

fn readExternalAgentSessionFile(allocator: std.mem.Allocator, path: []const u8) ![]const u8 {
    return std.Io.Dir.cwd().readFileAlloc(
        std.Io.Threaded.global_single_threaded.io(),
        path,
        allocator,
        .limited(1024 * 1024 * 16),
    );
}

fn externalAgentSessionContentSha256(allocator: std.mem.Allocator, path: []const u8) ![]const u8 {
    const bytes = try readExternalAgentSessionFile(allocator, path);
    defer allocator.free(bytes);
    var digest: [std.crypto.hash.sha2.Sha256.digest_length]u8 = undefined;
    std.crypto.hash.sha2.Sha256.hash(bytes, &digest, .{});
    var out = try allocator.alloc(u8, digest.len * 2);
    const hex = "0123456789abcdef";
    for (digest, 0..) |byte, index| {
        out[index * 2] = hex[byte >> 4];
        out[index * 2 + 1] = hex[byte & 0x0f];
    }
    return out;
}

fn loadExternalAgentSessionImportLedger(allocator: std.mem.Allocator, codex_home: []const u8) !ExternalAgentSessionImportLedger {
    const ledger_path = try externalAgentSessionImportLedgerPath(allocator, codex_home);
    defer allocator.free(ledger_path);
    const bytes = readTextFile(allocator, ledger_path) catch |err| switch (err) {
        error.FileNotFound => return .{},
        error.NotDir => return .{},
        else => return err,
    };
    defer allocator.free(bytes);

    var parsed = try std.json.parseFromSlice(std.json.Value, allocator, bytes, .{});
    defer parsed.deinit();
    if (parsed.value != .object) return error.InvalidExternalAgentSessionImportLedger;
    const records = parsed.value.object.get("records") orelse return error.InvalidExternalAgentSessionImportLedger;
    if (records != .array) return error.InvalidExternalAgentSessionImportLedger;

    var ledger = ExternalAgentSessionImportLedger{};
    errdefer ledger.deinit(allocator);
    for (records.array.items) |record_value| {
        if (record_value != .object) return error.InvalidExternalAgentSessionImportLedger;
        const source_path = externalAgentJsonString(record_value.object, "source_path") orelse return error.InvalidExternalAgentSessionImportLedger;
        const content_sha256 = externalAgentJsonString(record_value.object, "content_sha256") orelse return error.InvalidExternalAgentSessionImportLedger;
        const imported_thread_id = externalAgentJsonString(record_value.object, "imported_thread_id") orelse return error.InvalidExternalAgentSessionImportLedger;
        const imported_at_value = record_value.object.get("imported_at") orelse return error.InvalidExternalAgentSessionImportLedger;
        if (imported_at_value != .integer) return error.InvalidExternalAgentSessionImportLedger;
        var record = ExternalAgentSessionImportLedgerRecord{
            .source_path = try allocator.dupe(u8, source_path),
            .content_sha256 = try allocator.dupe(u8, content_sha256),
            .imported_thread_id = try allocator.dupe(u8, imported_thread_id),
            .imported_at = imported_at_value.integer,
        };
        errdefer record.deinit(allocator);
        try ledger.records.append(allocator, record);
    }
    return ledger;
}

fn saveExternalAgentSessionImportLedger(
    allocator: std.mem.Allocator,
    codex_home: []const u8,
    ledger: ExternalAgentSessionImportLedger,
) !void {
    const ledger_path = try externalAgentSessionImportLedgerPath(allocator, codex_home);
    defer allocator.free(ledger_path);
    var out = std.ArrayList(u8).empty;
    defer out.deinit(allocator);

    try out.appendSlice(allocator, "{\"records\":[");
    for (ledger.records.items, 0..) |record, index| {
        if (index != 0) try out.appendSlice(allocator, ",");
        try out.appendSlice(allocator, "{\"source_path\":");
        try appendJsonString(allocator, &out, record.source_path);
        try out.appendSlice(allocator, ",\"content_sha256\":");
        try appendJsonString(allocator, &out, record.content_sha256);
        try out.appendSlice(allocator, ",\"imported_thread_id\":");
        try appendJsonString(allocator, &out, record.imported_thread_id);
        try out.appendSlice(allocator, ",\"imported_at\":");
        try appendInt(allocator, &out, record.imported_at);
        try out.appendSlice(allocator, "}");
    }
    try out.appendSlice(allocator, "]}\n");
    try writeTextFile(ledger_path, out.items);
}

fn externalAgentSessionImportLedgerPath(allocator: std.mem.Allocator, codex_home: []const u8) ![]const u8 {
    return std.fs.path.join(allocator, &.{ codex_home, EXTERNAL_AGENT_SESSION_IMPORT_LEDGER_FILE });
}

fn externalAgentJsonString(object: std.json.ObjectMap, field: []const u8) ?[]const u8 {
    const value = object.get(field) orelse return null;
    if (value != .string) return null;
    return value.string;
}

fn externalAgentJsonBoolIsTrue(object: std.json.ObjectMap, field: []const u8) bool {
    const value = object.get(field) orelse return false;
    return value == .bool and value.bool;
}

fn loadExternalAgentEnabledPlugins(allocator: std.mem.Allocator, settings_path: []const u8) !std.ArrayList([]const u8) {
    const settings_dir = std.fs.path.dirname(settings_path) orelse return .empty;
    const local_settings_path = try std.fs.path.join(allocator, &.{ settings_dir, "settings.local.json" });
    defer allocator.free(local_settings_path);

    var settings = try readExternalAgentSettings(allocator, settings_path, false);
    defer if (settings) |*parsed| parsed.deinit();
    var local_settings = try readExternalAgentSettings(allocator, local_settings_path, true);
    defer if (local_settings) |*parsed| parsed.deinit();

    var enabled = std.ArrayList([]const u8).empty;
    errdefer deinitExternalAgentNamedItems(allocator, &enabled);
    try applyExternalAgentEnabledPluginsValue(allocator, &enabled, if (settings) |parsed| parsed.value else null);
    try applyExternalAgentEnabledPluginsValue(allocator, &enabled, if (local_settings) |parsed| parsed.value else null);
    std.mem.sort([]const u8, enabled.items, {}, stringLessThan);
    return enabled;
}

fn applyExternalAgentEnabledPluginsValue(allocator: std.mem.Allocator, enabled: *std.ArrayList([]const u8), value: ?std.json.Value) !void {
    const object = value orelse return;
    if (object != .object) return;
    const enabled_plugins = object.object.get("enabledPlugins") orelse return;
    if (enabled_plugins != .object) return;
    var iterator = enabled_plugins.object.iterator();
    while (iterator.next()) |entry| {
        if (!plugin_config.isValidPluginId(entry.key_ptr.*)) continue;
        if (entry.value_ptr.* == .bool and entry.value_ptr.*.bool) {
            try putExternalAgentNamedItem(allocator, enabled, entry.key_ptr.*);
        } else {
            removeExternalAgentNamedItem(allocator, enabled, entry.key_ptr.*);
        }
    }
}

fn loadExternalAgentMarketplaceImportSources(allocator: std.mem.Allocator, settings_path: []const u8, source_root: []const u8) !std.ArrayList(ExternalAgentMarketplaceImportSource) {
    const settings_dir = std.fs.path.dirname(settings_path) orelse return .empty;
    const local_settings_path = try std.fs.path.join(allocator, &.{ settings_dir, "settings.local.json" });
    defer allocator.free(local_settings_path);

    var settings = try readExternalAgentSettings(allocator, settings_path, false);
    defer if (settings) |*parsed| parsed.deinit();
    var local_settings = try readExternalAgentSettings(allocator, local_settings_path, true);
    defer if (local_settings) |*parsed| parsed.deinit();

    var sources = std.ArrayList(ExternalAgentMarketplaceImportSource).empty;
    errdefer deinitExternalAgentMarketplaceImportSources(allocator, &sources);
    try applyExternalAgentMarketplaceSourcesValue(allocator, &sources, if (settings) |parsed| parsed.value else null, source_root);
    try applyExternalAgentMarketplaceSourcesValue(allocator, &sources, if (local_settings) |parsed| parsed.value else null, source_root);
    std.mem.sort(ExternalAgentMarketplaceImportSource, sources.items, {}, externalAgentMarketplaceImportSourceLessThan);
    return sources;
}

fn applyExternalAgentMarketplaceSourcesValue(
    allocator: std.mem.Allocator,
    sources: *std.ArrayList(ExternalAgentMarketplaceImportSource),
    value: ?std.json.Value,
    source_root: []const u8,
) !void {
    const object = value orelse return;
    if (object != .object) return;
    const marketplaces = object.object.get("extraKnownMarketplaces") orelse return;
    if (marketplaces != .object) return;
    var iterator = marketplaces.object.iterator();
    while (iterator.next()) |entry| {
        if (!plugin_config.isValidPluginSegment(entry.key_ptr.*)) continue;
        var source = try externalAgentMarketplaceImportSourceFromJson(allocator, entry.key_ptr.*, entry.value_ptr.*, source_root) orelse continue;
        errdefer source.deinit(allocator);
        try putExternalAgentMarketplaceImportSource(allocator, sources, source);
    }
}

fn externalAgentMarketplaceImportSourceFromJson(allocator: std.mem.Allocator, marketplace_name: []const u8, value: std.json.Value, source_root: []const u8) !?ExternalAgentMarketplaceImportSource {
    if (value != .object) return null;
    const source_fields = if (value.object.get("source")) |source_value|
        if (source_value == .object) source_value.object else value.object
    else
        value.object;

    const raw_source = externalAgentMarketplaceSourceString(source_fields, value.object) orelse return null;
    const trimmed_source = std.mem.trim(u8, raw_source, " \t\r\n");
    if (trimmed_source.len == 0) return null;
    const resolved_source = try resolveExternalAgentMarketplaceSource(allocator, trimmed_source, source_root);
    errdefer allocator.free(resolved_source);

    var ref_name: ?[]const u8 = null;
    errdefer if (ref_name) |value_ref| allocator.free(value_ref);
    const raw_ref = if (source_fields.get("ref")) |ref_value|
        if (ref_value == .string) ref_value.string else null
    else if (value.object.get("ref")) |ref_value|
        if (ref_value == .string) ref_value.string else null
    else
        null;
    if (raw_ref) |ref_value| {
        const trimmed_ref = std.mem.trim(u8, ref_value, " \t\r\n");
        if (trimmed_ref.len > 0) ref_name = try allocator.dupe(u8, trimmed_ref);
    }

    return .{
        .marketplace_name = try allocator.dupe(u8, marketplace_name),
        .source = resolved_source,
        .ref_name = ref_name,
    };
}

fn externalAgentMarketplaceSourceString(source_fields: std.json.ObjectMap, value_object: std.json.ObjectMap) ?[]const u8 {
    const source_value = source_fields.get("repo") orelse
        source_fields.get("url") orelse
        source_fields.get("path") orelse
        value_object.get("source") orelse
        return null;
    if (source_value != .string) return null;
    return source_value.string;
}

fn resolveExternalAgentMarketplaceSource(allocator: std.mem.Allocator, source: []const u8, source_root: []const u8) ![]const u8 {
    if (!looksLikeExternalAgentRelativeLocalPath(source)) return allocator.dupe(u8, source);
    return std.fs.path.join(allocator, &.{ source_root, source });
}

fn looksLikeExternalAgentRelativeLocalPath(source: []const u8) bool {
    return std.mem.startsWith(u8, source, "./") or
        std.mem.startsWith(u8, source, "../") or
        std.mem.eql(u8, source, ".") or
        std.mem.eql(u8, source, "..");
}

fn externalAgentMarketplaceSourceIsLocal(source: []const u8) bool {
    return std.fs.path.isAbsolute(source);
}

fn externalAgentMarketplaceContainsPlugin(allocator: std.mem.Allocator, source: []const u8, plugin_name: []const u8) !bool {
    const marketplace_path = (try externalAgentMarketplaceManifestPath(allocator, source)) orelse return false;
    defer allocator.free(marketplace_path);
    const bytes = readTextFile(allocator, marketplace_path) catch |err| switch (err) {
        error.FileNotFound => return false,
        else => return err,
    };
    defer allocator.free(bytes);
    var parsed = std.json.parseFromSlice(std.json.Value, allocator, bytes, .{}) catch return false;
    defer parsed.deinit();
    if (parsed.value != .object) return false;
    const plugins = parsed.value.object.get("plugins") orelse return false;
    if (plugins != .array) return false;
    for (plugins.array.items) |plugin| {
        if (plugin != .object) continue;
        const name = plugin.object.get("name") orelse continue;
        if (name == .string and std.mem.eql(u8, name.string, plugin_name)) return true;
    }
    return false;
}

fn externalAgentMarketplaceManifestPath(allocator: std.mem.Allocator, root: []const u8) !?[]const u8 {
    const agents_path = try std.fs.path.join(allocator, &.{ root, ".agents", "plugins", "marketplace.json" });
    errdefer allocator.free(agents_path);
    if (try externalAgentPathExists(allocator, agents_path)) return agents_path;
    allocator.free(agents_path);

    const external_path = try std.fs.path.join(allocator, &.{ root, ".claude-plugin", "marketplace.json" });
    errdefer allocator.free(external_path);
    if (try externalAgentPathExists(allocator, external_path)) return external_path;
    allocator.free(external_path);
    return null;
}

fn putExternalAgentPluginMigration(allocator: std.mem.Allocator, details: *ExternalAgentPluginMigrationDetails, marketplace_name: []const u8, plugin_name: []const u8) !void {
    for (details.groups.items) |*group| {
        if (!std.mem.eql(u8, group.marketplace_name, marketplace_name)) continue;
        try putExternalAgentNamedItem(allocator, &group.plugin_names, plugin_name);
        std.mem.sort([]const u8, group.plugin_names.items, {}, stringLessThan);
        return;
    }

    var group = ExternalAgentPluginMigrationGroup{ .marketplace_name = try allocator.dupe(u8, marketplace_name) };
    errdefer group.deinit(allocator);
    try putExternalAgentNamedItem(allocator, &group.plugin_names, plugin_name);
    try details.groups.append(allocator, group);
}

fn putExternalAgentNamedItem(allocator: std.mem.Allocator, names: *std.ArrayList([]const u8), name: []const u8) !void {
    for (names.items) |existing| {
        if (std.mem.eql(u8, existing, name)) return;
    }
    try names.append(allocator, try allocator.dupe(u8, name));
}

fn removeExternalAgentNamedItem(allocator: std.mem.Allocator, names: *std.ArrayList([]const u8), name: []const u8) void {
    for (names.items, 0..) |existing, index| {
        if (!std.mem.eql(u8, existing, name)) continue;
        allocator.free(existing);
        _ = names.swapRemove(index);
        return;
    }
}

fn externalAgentPluginMigrationGroupLessThan(_: void, lhs: ExternalAgentPluginMigrationGroup, rhs: ExternalAgentPluginMigrationGroup) bool {
    return std.mem.lessThan(u8, lhs.marketplace_name, rhs.marketplace_name);
}

fn externalAgentMarketplaceImportSourceForName(sources: []const ExternalAgentMarketplaceImportSource, marketplace_name: []const u8) ?ExternalAgentMarketplaceImportSource {
    for (sources) |source| {
        if (std.mem.eql(u8, source.marketplace_name, marketplace_name)) return source;
    }
    return null;
}

fn externalAgentMarketplaceImportSourceLessThan(_: void, lhs: ExternalAgentMarketplaceImportSource, rhs: ExternalAgentMarketplaceImportSource) bool {
    return std.mem.lessThan(u8, lhs.marketplace_name, rhs.marketplace_name);
}

fn putExternalAgentMarketplaceImportSource(allocator: std.mem.Allocator, sources: *std.ArrayList(ExternalAgentMarketplaceImportSource), source: ExternalAgentMarketplaceImportSource) !void {
    for (sources.items, 0..) |*existing, index| {
        if (!std.mem.eql(u8, existing.marketplace_name, source.marketplace_name)) continue;
        existing.deinit(allocator);
        _ = sources.swapRemove(index);
        break;
    }
    try sources.append(allocator, source);
}

const ExternalAgentKeyValue = struct {
    key: []const u8,
    value: []const u8,

    fn deinit(self: ExternalAgentKeyValue, allocator: std.mem.Allocator) void {
        allocator.free(self.key);
        allocator.free(self.value);
    }
};

const ExternalAgentMcpSettings = struct {
    enabled: std.ArrayList([]const u8) = .empty,
    disabled: std.ArrayList([]const u8) = .empty,

    fn deinit(self: *ExternalAgentMcpSettings, allocator: std.mem.Allocator) void {
        deinitExternalAgentNamedItems(allocator, &self.enabled);
        deinitExternalAgentNamedItems(allocator, &self.disabled);
    }
};

const ExternalAgentMcpServer = struct {
    name: []const u8,
    command: ?[]const u8 = null,
    url: ?[]const u8 = null,
    args: std.ArrayList([]const u8) = .empty,
    env_vars: std.ArrayList([]const u8) = .empty,
    env: std.ArrayList(ExternalAgentKeyValue) = .empty,
    http_headers: std.ArrayList(ExternalAgentKeyValue) = .empty,
    env_http_headers: std.ArrayList(ExternalAgentKeyValue) = .empty,
    bearer_token_env_var: ?[]const u8 = null,

    fn deinit(self: *ExternalAgentMcpServer, allocator: std.mem.Allocator) void {
        allocator.free(self.name);
        if (self.command) |value| allocator.free(value);
        if (self.url) |value| allocator.free(value);
        deinitExternalAgentNamedItems(allocator, &self.args);
        deinitExternalAgentNamedItems(allocator, &self.env_vars);
        deinitExternalAgentKeyValues(allocator, &self.env);
        deinitExternalAgentKeyValues(allocator, &self.http_headers);
        deinitExternalAgentKeyValues(allocator, &self.env_http_headers);
        if (self.bearer_token_env_var) |value| allocator.free(value);
        self.* = undefined;
    }
};

const ExternalAgentMcpPlan = struct {
    servers: std.ArrayList(ExternalAgentMcpServer) = .empty,

    fn deinit(self: *ExternalAgentMcpPlan, allocator: std.mem.Allocator) void {
        for (self.servers.items) |*server| server.deinit(allocator);
        self.servers.deinit(allocator);
    }

    fn isEmpty(self: ExternalAgentMcpPlan) bool {
        return self.servers.items.len == 0;
    }
};

fn deinitExternalAgentKeyValues(allocator: std.mem.Allocator, values: *std.ArrayList(ExternalAgentKeyValue)) void {
    for (values.items) |entry| entry.deinit(allocator);
    values.deinit(allocator);
}

fn importExternalAgentHomeMcpServerConfig(allocator: std.mem.Allocator, codex_home: []const u8) !void {
    var plan = try loadExternalAgentHomeMcpPlan(allocator);
    defer plan.deinit(allocator);
    const config_path = try config.configTomlPath(allocator, codex_home);
    defer allocator.free(config_path);
    try importExternalAgentMcpPlanAt(allocator, config_path, plan);
}

fn importExternalAgentProjectMcpServerConfig(allocator: std.mem.Allocator, repo_root: []const u8) !void {
    var plan = try loadExternalAgentProjectMcpPlan(allocator, repo_root);
    defer plan.deinit(allocator);
    const config_path = try externalAgentProjectConfigPath(allocator, repo_root);
    defer allocator.free(config_path);
    try importExternalAgentMcpPlanAt(allocator, config_path, plan);
}

fn loadExternalAgentHomeMcpPlan(allocator: std.mem.Allocator) !ExternalAgentMcpPlan {
    const source_root = try externalAgentHomeSourceRootPath(allocator);
    defer allocator.free(source_root);
    const external_home = try externalAgentHomePath(allocator);
    defer allocator.free(external_home);
    const settings_path = try externalAgentHomeSettingsPath(allocator);
    defer allocator.free(settings_path);
    var settings = try loadExternalAgentMcpSettingsFromPath(allocator, settings_path, false);
    defer settings.deinit(allocator);
    return loadExternalAgentMcpPlanForRoot(allocator, source_root, external_home, null, settings);
}

fn loadExternalAgentProjectMcpPlan(allocator: std.mem.Allocator, repo_root: []const u8) !ExternalAgentMcpPlan {
    const external_home = try externalAgentHomePath(allocator);
    defer allocator.free(external_home);
    const settings_path = try externalAgentProjectSettingsPath(allocator, repo_root);
    defer allocator.free(settings_path);
    var settings = try loadExternalAgentMcpSettingsFromPath(allocator, settings_path, false);
    if (settings.enabled.items.len == 0 and settings.disabled.items.len == 0 and !try externalAgentPathExists(allocator, settings_path)) {
        const home_settings_path = try externalAgentHomeSettingsPath(allocator);
        defer allocator.free(home_settings_path);
        settings.deinit(allocator);
        settings = try loadExternalAgentMcpSettingsFromPath(allocator, home_settings_path, true);
    }
    defer settings.deinit(allocator);
    return loadExternalAgentMcpPlanForRoot(allocator, repo_root, external_home, repo_root, settings);
}

fn loadExternalAgentMcpSettingsFromPath(allocator: std.mem.Allocator, settings_path: []const u8, ignore_invalid_main: bool) !ExternalAgentMcpSettings {
    const settings_dir = std.fs.path.dirname(settings_path) orelse return .{};
    const local_settings_path = try std.fs.path.join(allocator, &.{ settings_dir, "settings.local.json" });
    defer allocator.free(local_settings_path);

    var settings = try readExternalAgentSettings(allocator, settings_path, ignore_invalid_main);
    defer if (settings) |*parsed| parsed.deinit();
    var local_settings = try readExternalAgentSettings(allocator, local_settings_path, true);
    defer if (local_settings) |*parsed| parsed.deinit();

    var result = ExternalAgentMcpSettings{};
    errdefer result.deinit(allocator);
    try applyExternalAgentMcpSettingsValue(allocator, &result, if (settings) |parsed| parsed.value else null);
    try applyExternalAgentMcpSettingsValue(allocator, &result, if (local_settings) |parsed| parsed.value else null);
    std.mem.sort([]const u8, result.enabled.items, {}, stringLessThan);
    std.mem.sort([]const u8, result.disabled.items, {}, stringLessThan);
    return result;
}

fn applyExternalAgentMcpSettingsValue(allocator: std.mem.Allocator, settings: *ExternalAgentMcpSettings, value: ?std.json.Value) !void {
    const object = value orelse return;
    if (object != .object) return;
    if (object.object.get("enabledMcpjsonServers")) |enabled| {
        deinitExternalAgentNamedItems(allocator, &settings.enabled);
        settings.enabled = .empty;
        try appendExternalAgentJsonStringList(allocator, &settings.enabled, enabled);
    }
    if (object.object.get("disabledMcpjsonServers")) |disabled| {
        deinitExternalAgentNamedItems(allocator, &settings.disabled);
        settings.disabled = .empty;
        try appendExternalAgentJsonStringList(allocator, &settings.disabled, disabled);
    }
}

fn appendExternalAgentJsonStringList(allocator: std.mem.Allocator, list: *std.ArrayList([]const u8), value: std.json.Value) !void {
    if (value == .array) {
        for (value.array.items) |item| {
            const string = try externalAgentJsonValueToString(allocator, item) orelse continue;
            errdefer allocator.free(string);
            try list.append(allocator, string);
        }
    } else if (try externalAgentJsonValueToString(allocator, value)) |string| {
        errdefer allocator.free(string);
        try list.append(allocator, string);
    }
}

fn loadExternalAgentMcpPlanForRoot(
    allocator: std.mem.Allocator,
    source_root: []const u8,
    external_home: []const u8,
    repo_root: ?[]const u8,
    settings: ExternalAgentMcpSettings,
) !ExternalAgentMcpPlan {
    var plan = ExternalAgentMcpPlan{};
    errdefer plan.deinit(allocator);

    const mcp_path = try std.fs.path.join(allocator, &.{ source_root, ".mcp.json" });
    defer allocator.free(mcp_path);
    try appendExternalAgentMcpServersFromFile(allocator, &plan, mcp_path, settings, true);

    const claude_json_path = try std.fs.path.join(allocator, &.{ source_root, ".claude.json" });
    defer allocator.free(claude_json_path);
    try appendExternalAgentMcpServersFromFile(allocator, &plan, claude_json_path, settings, true);
    if (repo_root) |root| {
        try appendExternalAgentProjectMcpServersFromFile(allocator, &plan, claude_json_path, root, settings, true);
        const external_parent = std.fs.path.dirname(external_home);
        if (external_parent) |parent| {
            const home_claude_json_path = try std.fs.path.join(allocator, &.{ parent, ".claude.json" });
            defer allocator.free(home_claude_json_path);
            if (!std.mem.eql(u8, home_claude_json_path, claude_json_path)) {
                try appendExternalAgentProjectMcpServersFromFile(allocator, &plan, home_claude_json_path, root, settings, false);
            }
        }
    }

    std.mem.sort(ExternalAgentMcpServer, plan.servers.items, {}, externalAgentMcpServerLessThan);
    return plan;
}

fn appendExternalAgentMcpServersFromFile(
    allocator: std.mem.Allocator,
    plan: *ExternalAgentMcpPlan,
    path: []const u8,
    settings: ExternalAgentMcpSettings,
    overwrite: bool,
) !void {
    const bytes = readTextFile(allocator, path) catch |err| switch (err) {
        error.FileNotFound => return,
        else => return err,
    };
    defer allocator.free(bytes);
    var parsed = try std.json.parseFromSlice(std.json.Value, allocator, bytes, .{});
    defer parsed.deinit();
    try appendExternalAgentMcpServersFromValue(allocator, plan, parsed.value, settings, overwrite);
}

fn appendExternalAgentProjectMcpServersFromFile(
    allocator: std.mem.Allocator,
    plan: *ExternalAgentMcpPlan,
    path: []const u8,
    repo_root: []const u8,
    settings: ExternalAgentMcpSettings,
    overwrite: bool,
) !void {
    const bytes = readTextFile(allocator, path) catch |err| switch (err) {
        error.FileNotFound => return,
        else => return err,
    };
    defer allocator.free(bytes);
    var parsed = try std.json.parseFromSlice(std.json.Value, allocator, bytes, .{});
    defer parsed.deinit();
    if (parsed.value != .object) return;
    const projects = parsed.value.object.get("projects") orelse return;
    if (projects != .object) return;
    var iterator = projects.object.iterator();
    while (iterator.next()) |entry| {
        if (!try externalAgentProjectPathMatchesRoot(allocator, entry.key_ptr.*, repo_root)) continue;
        try appendExternalAgentMcpServersFromValue(allocator, plan, entry.value_ptr.*, settings, overwrite);
    }
}

fn appendExternalAgentMcpServersFromValue(
    allocator: std.mem.Allocator,
    plan: *ExternalAgentMcpPlan,
    value: std.json.Value,
    settings: ExternalAgentMcpSettings,
    overwrite: bool,
) !void {
    if (value != .object) return;
    const servers = value.object.get("mcpServers") orelse return;
    if (servers != .object) return;
    var iterator = servers.object.iterator();
    while (iterator.next()) |entry| {
        var server = try externalAgentMcpServerFromJson(allocator, entry.key_ptr.*, entry.value_ptr.*, settings) orelse continue;
        errdefer server.deinit(allocator);
        try putExternalAgentMcpServer(allocator, plan, server, overwrite);
    }
}

fn externalAgentMcpServerFromJson(allocator: std.mem.Allocator, name: []const u8, value: std.json.Value, settings: ExternalAgentMcpSettings) !?ExternalAgentMcpServer {
    if (!isBareTomlKeySegment(name)) return null;
    if (value != .object) return null;
    if (externalAgentMcpServerDisabled(name, value.object, settings)) return null;
    const transport_type = if (value.object.get("type")) |type_value| if (type_value == .string) type_value.string else null else null;

    var server = ExternalAgentMcpServer{ .name = try allocator.dupe(u8, name) };
    var keep_server = false;
    defer if (!keep_server) server.deinit(allocator);
    if (value.object.get("command")) |command_value| {
        const command = try externalAgentJsonValueToString(allocator, command_value) orelse return null;
        defer allocator.free(command);
        if (transport_type != null and !std.mem.eql(u8, transport_type.?, "stdio")) return null;
        if (containsExternalAgentEnvPlaceholder(command)) return null;
        server.command = try allocator.dupe(u8, command);
        if (value.object.get("args")) |args_value| {
            try appendExternalAgentMcpStringArgs(allocator, &server.args, args_value) orelse return null;
        }
        if (value.object.get("env")) |env_value| {
            try appendExternalAgentMcpEnv(allocator, &server, env_value) orelse return null;
        }
    } else if (value.object.get("url")) |url_value| {
        const url = try externalAgentJsonValueToString(allocator, url_value) orelse return null;
        defer allocator.free(url);
        if (transport_type) |kind| {
            if (!std.mem.eql(u8, kind, "http") and !std.mem.eql(u8, kind, "streamable_http")) return null;
        }
        if (containsExternalAgentEnvPlaceholder(url)) return null;
        server.url = try allocator.dupe(u8, url);
        if (value.object.get("headers")) |headers_value| {
            try appendExternalAgentMcpHeaders(allocator, &server, headers_value) orelse return null;
        }
    } else {
        return null;
    }

    std.mem.sort([]const u8, server.env_vars.items, {}, stringLessThan);
    std.mem.sort(ExternalAgentKeyValue, server.env.items, {}, externalAgentKeyValueLessThan);
    std.mem.sort(ExternalAgentKeyValue, server.http_headers.items, {}, externalAgentKeyValueLessThan);
    std.mem.sort(ExternalAgentKeyValue, server.env_http_headers.items, {}, externalAgentKeyValueLessThan);
    keep_server = true;
    return server;
}

fn externalAgentMcpServerDisabled(name: []const u8, object: std.json.ObjectMap, settings: ExternalAgentMcpSettings) bool {
    if (object.get("enabled")) |value| {
        if (value == .bool and !value.bool) return true;
    }
    if (object.get("disabled")) |value| {
        if (value == .bool and value.bool) return true;
    }
    if (settings.enabled.items.len > 0 and !externalAgentStringListContains(settings.enabled.items, name)) return true;
    if (externalAgentStringListContains(settings.disabled.items, name)) return true;
    return false;
}

fn appendExternalAgentMcpStringArgs(allocator: std.mem.Allocator, args: *std.ArrayList([]const u8), value: std.json.Value) !?void {
    if (value != .array) return {};
    for (value.array.items) |item| {
        const string = try externalAgentJsonValueToString(allocator, item) orelse continue;
        errdefer allocator.free(string);
        if (containsExternalAgentEnvPlaceholder(string)) {
            allocator.free(string);
            return null;
        }
        try args.append(allocator, string);
    }
    return {};
}

fn appendExternalAgentMcpEnv(allocator: std.mem.Allocator, server: *ExternalAgentMcpServer, value: std.json.Value) !?void {
    if (value != .object) return {};
    var iterator = value.object.iterator();
    while (iterator.next()) |entry| {
        if (!isBareTomlKeySegment(entry.key_ptr.*)) return null;
        const env_value = try externalAgentJsonValueToString(allocator, entry.value_ptr.*) orelse continue;
        defer allocator.free(env_value);
        if (try parseExternalAgentEnvPlaceholder(allocator, env_value)) |env_name| {
            defer allocator.free(env_name);
            if (!std.mem.eql(u8, env_name, entry.key_ptr.*)) return null;
            try server.env_vars.append(allocator, try allocator.dupe(u8, entry.key_ptr.*));
        } else if (containsExternalAgentEnvPlaceholder(env_value)) {
            return null;
        } else {
            try appendExternalAgentKeyValue(allocator, &server.env, entry.key_ptr.*, env_value);
        }
    }
    return {};
}

fn appendExternalAgentMcpHeaders(allocator: std.mem.Allocator, server: *ExternalAgentMcpServer, value: std.json.Value) !?void {
    if (value != .object) return {};
    var iterator = value.object.iterator();
    while (iterator.next()) |entry| {
        if (!isBareTomlKeySegment(entry.key_ptr.*)) return null;
        const header_value = try externalAgentJsonValueToString(allocator, entry.value_ptr.*) orelse continue;
        defer allocator.free(header_value);
        if (asciiRegionEqlIgnoreCase(entry.key_ptr.*, "authorization") and std.mem.startsWith(u8, header_value, "Bearer ")) {
            if (try parseExternalAgentEnvPlaceholder(allocator, std.mem.trim(u8, header_value["Bearer ".len..], " \t\r\n"))) |env_name| {
                if (server.bearer_token_env_var) |old| allocator.free(old);
                server.bearer_token_env_var = env_name;
                continue;
            }
        }
        if (try parseExternalAgentEnvPlaceholder(allocator, header_value)) |env_name| {
            defer allocator.free(env_name);
            try appendExternalAgentKeyValue(allocator, &server.env_http_headers, entry.key_ptr.*, env_name);
        } else if (containsExternalAgentEnvPlaceholder(header_value)) {
            return null;
        } else {
            try appendExternalAgentKeyValue(allocator, &server.http_headers, entry.key_ptr.*, header_value);
        }
    }
    return {};
}

fn putExternalAgentMcpServer(allocator: std.mem.Allocator, plan: *ExternalAgentMcpPlan, server: ExternalAgentMcpServer, overwrite: bool) !void {
    for (plan.servers.items, 0..) |*existing, index| {
        if (!std.mem.eql(u8, existing.name, server.name)) continue;
        if (!overwrite) {
            var discarded = server;
            discarded.deinit(allocator);
            return;
        }
        existing.deinit(allocator);
        _ = plan.servers.swapRemove(index);
        break;
    }
    try plan.servers.append(allocator, server);
}

fn importExternalAgentMcpPlanAt(allocator: std.mem.Allocator, config_path: []const u8, plan: ExternalAgentMcpPlan) !void {
    if (plan.isEmpty()) return;
    const current_bytes = try config.readConfigTomlFile(allocator, config_path);
    defer if (current_bytes) |bytes| allocator.free(bytes);
    var updated: []const u8 = try allocator.dupe(u8, current_bytes orelse "");
    defer allocator.free(updated);
    var changed = false;

    for (plan.servers.items) |server| {
        if (server.command) |command| {
            try maybeApplyExternalAgentTomlString(allocator, &updated, &changed, server.name, "command", command);
            if (server.args.items.len > 0) try maybeApplyExternalAgentTomlStringArray(allocator, &updated, &changed, server.name, "args", server.args.items);
            if (server.env_vars.items.len > 0) try maybeApplyExternalAgentTomlStringArray(allocator, &updated, &changed, server.name, "env_vars", server.env_vars.items);
            try maybeApplyExternalAgentTomlKeyValues(allocator, &updated, &changed, server.name, "env", server.env.items);
        } else if (server.url) |url| {
            try maybeApplyExternalAgentTomlString(allocator, &updated, &changed, server.name, "url", url);
            if (server.bearer_token_env_var) |env_name| try maybeApplyExternalAgentTomlString(allocator, &updated, &changed, server.name, "bearer_token_env_var", env_name);
            try maybeApplyExternalAgentTomlKeyValues(allocator, &updated, &changed, server.name, "http_headers", server.http_headers.items);
            try maybeApplyExternalAgentTomlKeyValues(allocator, &updated, &changed, server.name, "env_http_headers", server.env_http_headers.items);
        }
    }

    if (changed) try config.writeConfigTomlFile(config_path, updated);
}

fn maybeApplyExternalAgentTomlString(allocator: std.mem.Allocator, updated: *[]const u8, changed: *bool, server_name: []const u8, key: []const u8, value: []const u8) !void {
    const key_path = try std.fmt.allocPrint(allocator, "mcp_servers.{s}.{s}", .{ server_name, key });
    defer allocator.free(key_path);
    if (tomlKeyPathHasAssignment(updated.*, key_path)) return;
    const rendered = try renderTomlString(allocator, value);
    defer allocator.free(rendered);
    const next = try config.updateTomlRawValueForKeyPath(allocator, updated.*, key_path, rendered);
    allocator.free(updated.*);
    updated.* = next;
    changed.* = true;
}

fn maybeApplyExternalAgentTomlStringArray(allocator: std.mem.Allocator, updated: *[]const u8, changed: *bool, server_name: []const u8, key: []const u8, values: []const []const u8) !void {
    const key_path = try std.fmt.allocPrint(allocator, "mcp_servers.{s}.{s}", .{ server_name, key });
    defer allocator.free(key_path);
    if (tomlKeyPathHasAssignment(updated.*, key_path)) return;
    const rendered = try renderExternalAgentTomlStringArray(allocator, values);
    defer allocator.free(rendered);
    const next = try config.updateTomlRawValueForKeyPath(allocator, updated.*, key_path, rendered);
    allocator.free(updated.*);
    updated.* = next;
    changed.* = true;
}

fn maybeApplyExternalAgentTomlKeyValues(allocator: std.mem.Allocator, updated: *[]const u8, changed: *bool, server_name: []const u8, table: []const u8, values: []const ExternalAgentKeyValue) !void {
    for (values) |entry| {
        const key_path = try std.fmt.allocPrint(allocator, "mcp_servers.{s}.{s}.{s}", .{ server_name, table, entry.key });
        defer allocator.free(key_path);
        if (tomlKeyPathHasAssignment(updated.*, key_path)) continue;
        const rendered = try renderTomlString(allocator, entry.value);
        defer allocator.free(rendered);
        const next = try config.updateTomlRawValueForKeyPath(allocator, updated.*, key_path, rendered);
        allocator.free(updated.*);
        updated.* = next;
        changed.* = true;
    }
}

fn externalAgentMcpPlanHasMissingValues(bytes: []const u8, plan: ExternalAgentMcpPlan) bool {
    for (plan.servers.items) |server| {
        var key_path_buffer: [256]u8 = undefined;
        const key = if (server.command != null) "command" else "url";
        const key_path = std.fmt.bufPrint(&key_path_buffer, "mcp_servers.{s}.{s}", .{ server.name, key }) catch return true;
        if (!tomlKeyPathHasAssignment(bytes, key_path)) return true;
    }
    return false;
}

fn externalAgentMcpServerNames(allocator: std.mem.Allocator, plan: ExternalAgentMcpPlan) !std.ArrayList([]const u8) {
    var names = std.ArrayList([]const u8).empty;
    errdefer deinitExternalAgentNamedItems(allocator, &names);
    for (plan.servers.items) |server| {
        try names.append(allocator, try allocator.dupe(u8, server.name));
    }
    return names;
}

fn externalAgentMcpServerLessThan(_: void, lhs: ExternalAgentMcpServer, rhs: ExternalAgentMcpServer) bool {
    return std.mem.lessThan(u8, lhs.name, rhs.name);
}

fn externalAgentKeyValueLessThan(_: void, lhs: ExternalAgentKeyValue, rhs: ExternalAgentKeyValue) bool {
    return std.mem.lessThan(u8, lhs.key, rhs.key);
}

fn appendExternalAgentKeyValue(allocator: std.mem.Allocator, values: *std.ArrayList(ExternalAgentKeyValue), key: []const u8, value: []const u8) !void {
    const owned_key = try allocator.dupe(u8, key);
    errdefer allocator.free(owned_key);
    const owned_value = try allocator.dupe(u8, value);
    errdefer allocator.free(owned_value);
    try values.append(allocator, .{ .key = owned_key, .value = owned_value });
}

fn externalAgentJsonValueToString(allocator: std.mem.Allocator, value: std.json.Value) !?[]const u8 {
    return switch (value) {
        .string => |string| try allocator.dupe(u8, string),
        .bool => |boolean| try allocator.dupe(u8, if (boolean) "true" else "false"),
        .integer => |integer| try std.fmt.allocPrint(allocator, "{}", .{integer}),
        .float => |float| try std.fmt.allocPrint(allocator, "{d}", .{float}),
        .number_string => |number| try allocator.dupe(u8, number),
        .null, .array, .object => null,
    };
}

fn parseExternalAgentEnvPlaceholder(allocator: std.mem.Allocator, value: []const u8) !?[]const u8 {
    if (!std.mem.startsWith(u8, value, "${") or !std.mem.endsWith(u8, value, "}")) return null;
    var inner = value[2 .. value.len - 1];
    if (std.mem.indexOf(u8, inner, ":-")) |index| inner = inner[0..index];
    if (inner.len == 0) return null;
    if (!(inner[0] == '_' or std.ascii.isAlphabetic(inner[0]))) return null;
    for (inner[1..]) |byte| {
        if (byte == '_' or std.ascii.isAlphanumeric(byte)) continue;
        return null;
    }
    return try allocator.dupe(u8, inner);
}

fn containsExternalAgentEnvPlaceholder(value: []const u8) bool {
    return std.mem.indexOf(u8, value, "${") != null;
}

fn externalAgentStringListContains(values: []const []const u8, needle: []const u8) bool {
    for (values) |value| {
        if (std.mem.eql(u8, value, needle)) return true;
    }
    return false;
}

fn renderExternalAgentTomlStringArray(allocator: std.mem.Allocator, values: []const []const u8) ![]const u8 {
    var rendered = std.ArrayList(u8).empty;
    errdefer rendered.deinit(allocator);
    try rendered.append(allocator, '[');
    for (values, 0..) |value, index| {
        if (index != 0) try rendered.appendSlice(allocator, ", ");
        const string = try renderTomlString(allocator, value);
        defer allocator.free(string);
        try rendered.appendSlice(allocator, string);
    }
    try rendered.append(allocator, ']');
    return rendered.toOwnedSlice(allocator);
}

fn externalAgentProjectPathMatchesRoot(allocator: std.mem.Allocator, project_path: []const u8, repo_root: []const u8) !bool {
    if (std.mem.eql(u8, project_path, repo_root)) return true;
    const io = std.Io.Threaded.global_single_threaded.io();
    const project_real = std.Io.Dir.cwd().realPathFileAlloc(io, project_path, allocator) catch |err| switch (err) {
        error.FileNotFound => return false,
        else => return err,
    };
    defer allocator.free(project_real);
    const repo_real = std.Io.Dir.cwd().realPathFileAlloc(io, repo_root, allocator) catch |err| switch (err) {
        error.FileNotFound => return false,
        else => return err,
    };
    defer allocator.free(repo_real);
    return std.mem.eql(u8, project_real, repo_real);
}

const EXTERNAL_AGENT_HOOK_EVENTS = [_][]const u8{
    "PreToolUse",
    "PermissionRequest",
    "PostToolUse",
    "PreCompact",
    "PostCompact",
    "SessionStart",
    "UserPromptSubmit",
    "Stop",
};

const ExternalAgentHookTimeout = struct {
    field_name: []const u8,
    seconds: u64,
};

const ExternalAgentHookCommand = struct {
    command: []const u8,
    timeout: ?ExternalAgentHookTimeout = null,
    status_message: ?[]const u8 = null,

    fn deinit(self: ExternalAgentHookCommand, allocator: std.mem.Allocator) void {
        allocator.free(self.command);
        if (self.status_message) |value| allocator.free(value);
    }
};

const ExternalAgentHookGroup = struct {
    event_name: []const u8,
    matcher: ?[]const u8 = null,
    commands: std.ArrayList(ExternalAgentHookCommand) = .empty,

    fn deinit(self: *ExternalAgentHookGroup, allocator: std.mem.Allocator) void {
        allocator.free(self.event_name);
        if (self.matcher) |value| allocator.free(value);
        for (self.commands.items) |hook| hook.deinit(allocator);
        self.commands.deinit(allocator);
    }
};

const ExternalAgentHookPlan = struct {
    groups: std.ArrayList(ExternalAgentHookGroup) = .empty,

    fn deinit(self: *ExternalAgentHookPlan, allocator: std.mem.Allocator) void {
        for (self.groups.items) |*group| group.deinit(allocator);
        self.groups.deinit(allocator);
    }

    fn isEmpty(self: ExternalAgentHookPlan) bool {
        return self.groups.items.len == 0;
    }
};

fn importExternalAgentHomeHooks(allocator: std.mem.Allocator, codex_home: []const u8) !void {
    const source_hooks_dir = try externalAgentHomePath(allocator);
    defer allocator.free(source_hooks_dir);
    const target_hooks = try externalAgentTargetHooksPath(allocator, codex_home);
    defer allocator.free(target_hooks);
    return importExternalAgentHooksAt(allocator, source_hooks_dir, target_hooks);
}

fn importExternalAgentProjectHooks(allocator: std.mem.Allocator, repo_root: []const u8) !void {
    const source_hooks_dir = try externalAgentProjectDirPath(allocator, repo_root);
    defer allocator.free(source_hooks_dir);
    const target_hooks = try externalAgentProjectTargetHooksPath(allocator, repo_root);
    defer allocator.free(target_hooks);
    return importExternalAgentHooksAt(allocator, source_hooks_dir, target_hooks);
}

fn importExternalAgentHooksAt(allocator: std.mem.Allocator, source_external_agent_dir: []const u8, target_hooks: []const u8) !void {
    var plan = try loadExternalAgentHookPlan(allocator, source_external_agent_dir);
    defer plan.deinit(allocator);
    if (plan.isEmpty()) return;
    if (!try isMissingOrEmptyTextFile(allocator, target_hooks)) return;

    try copyExternalAgentHookScripts(allocator, source_external_agent_dir, target_hooks);

    const rendered = try renderExternalAgentHooksJson(allocator, plan);
    defer allocator.free(rendered);
    try writeTextFile(target_hooks, rendered);
}

fn missingExternalAgentHookEventNames(allocator: std.mem.Allocator, source_external_agent_dir: []const u8, target_hooks: []const u8) !std.ArrayList([]const u8) {
    var names = std.ArrayList([]const u8).empty;
    errdefer deinitExternalAgentNamedItems(allocator, &names);
    if (!try isMissingOrEmptyTextFile(allocator, target_hooks)) return names;

    var plan = try loadExternalAgentHookPlan(allocator, source_external_agent_dir);
    defer plan.deinit(allocator);
    if (plan.isEmpty()) return names;

    for (EXTERNAL_AGENT_HOOK_EVENTS) |event_name| {
        for (plan.groups.items) |group| {
            if (!std.mem.eql(u8, group.event_name, event_name)) continue;
            try names.append(allocator, try allocator.dupe(u8, event_name));
            break;
        }
    }
    return names;
}

fn loadExternalAgentHookPlan(allocator: std.mem.Allocator, source_external_agent_dir: []const u8) !ExternalAgentHookPlan {
    const settings_path = try std.fs.path.join(allocator, &.{ source_external_agent_dir, "settings.json" });
    defer allocator.free(settings_path);
    const local_settings_path = try std.fs.path.join(allocator, &.{ source_external_agent_dir, "settings.local.json" });
    defer allocator.free(local_settings_path);

    var settings = try readExternalAgentSettings(allocator, settings_path, false);
    defer if (settings) |*parsed| parsed.deinit();
    var local_settings = try readExternalAgentSettings(allocator, local_settings_path, true);
    defer if (local_settings) |*parsed| parsed.deinit();

    var plan = ExternalAgentHookPlan{};
    errdefer plan.deinit(allocator);
    var disable_all_hooks = false;
    if (settings) |parsed| {
        if (externalAgentHooksDisableAllValue(parsed.value)) |disabled| disable_all_hooks = disabled;
        try appendExternalAgentHookGroupsFromSettings(allocator, &plan, parsed.value);
    }
    if (local_settings) |parsed| {
        if (externalAgentHooksDisableAllValue(parsed.value)) |disabled| disable_all_hooks = disabled;
        try appendExternalAgentHookGroupsFromSettings(allocator, &plan, parsed.value);
    }
    if (disable_all_hooks) {
        plan.deinit(allocator);
        return .{};
    }
    return plan;
}

fn externalAgentHooksDisableAllValue(value: std.json.Value) ?bool {
    if (value != .object) return null;
    const disabled = value.object.get("disableAllHooks") orelse return null;
    if (disabled != .bool) return null;
    return disabled.bool;
}

fn appendExternalAgentHookGroupsFromSettings(allocator: std.mem.Allocator, plan: *ExternalAgentHookPlan, value: std.json.Value) !void {
    if (value != .object) return;
    const hooks = value.object.get("hooks") orelse return;
    if (hooks != .object) return;

    for (EXTERNAL_AGENT_HOOK_EVENTS) |event_name| {
        const groups = hooks.object.get(event_name) orelse continue;
        if (groups != .array) continue;
        for (groups.array.items) |group_value| {
            var group = try externalAgentHookGroupFromJson(allocator, event_name, group_value) orelse continue;
            errdefer group.deinit(allocator);
            try plan.groups.append(allocator, group);
        }
    }
}

fn externalAgentHookGroupFromJson(allocator: std.mem.Allocator, event_name: []const u8, value: std.json.Value) !?ExternalAgentHookGroup {
    if (value != .object) return null;
    if (!externalAgentHookGroupKeysSupported(value.object)) return null;
    const hooks = value.object.get("hooks") orelse return null;
    if (hooks != .array) return null;

    var group = ExternalAgentHookGroup{ .event_name = try allocator.dupe(u8, event_name) };
    errdefer group.deinit(allocator);

    if (externalAgentHookEventSupportsMatcher(event_name)) {
        if (value.object.get("matcher")) |matcher| {
            if (matcher == .string and matcher.string.len > 0) {
                group.matcher = try allocator.dupe(u8, matcher.string);
            }
        }
    }

    for (hooks.array.items) |hook_value| {
        const command = try externalAgentHookCommandFromJson(allocator, hook_value) orelse continue;
        errdefer command.deinit(allocator);
        try group.commands.append(allocator, command);
    }
    if (group.commands.items.len == 0) {
        group.deinit(allocator);
        return null;
    }
    return group;
}

fn externalAgentHookGroupKeysSupported(object: std.json.ObjectMap) bool {
    var iterator = object.iterator();
    while (iterator.next()) |entry| {
        if (std.mem.eql(u8, entry.key_ptr.*, "matcher")) continue;
        if (std.mem.eql(u8, entry.key_ptr.*, "hooks")) continue;
        return false;
    }
    return true;
}

fn externalAgentHookEventSupportsMatcher(event_name: []const u8) bool {
    return std.mem.eql(u8, event_name, "PreToolUse") or
        std.mem.eql(u8, event_name, "PermissionRequest") or
        std.mem.eql(u8, event_name, "PostToolUse") or
        std.mem.eql(u8, event_name, "PreCompact") or
        std.mem.eql(u8, event_name, "PostCompact") or
        std.mem.eql(u8, event_name, "SessionStart");
}

fn externalAgentHookCommandFromJson(allocator: std.mem.Allocator, value: std.json.Value) !?ExternalAgentHookCommand {
    if (value != .object) return null;
    if (!externalAgentHookCommandKeysSupported(value.object)) return null;
    const type_value = value.object.get("type") orelse return null;
    if (type_value != .string or !std.mem.eql(u8, type_value.string, "command")) return null;
    if (value.object.get("async")) |async_value| {
        if (async_value != .bool or async_value.bool) return null;
    }
    const command_value = value.object.get("command") orelse return null;
    if (command_value != .string) return null;
    const command_trimmed = std.mem.trim(u8, command_value.string, " \t\r\n");
    if (command_trimmed.len == 0) return null;

    if (value.object.get("statusMessage")) |status| {
        if (status != .string) return null;
    }

    var timeout: ?ExternalAgentHookTimeout = null;
    if (value.object.get("timeout")) |timeout_value| {
        const seconds = externalAgentHookTimeoutSeconds(timeout_value) orelse return null;
        timeout = .{ .field_name = "timeout", .seconds = seconds };
    }
    if (value.object.get("timeoutSec")) |timeout_value| {
        const seconds = externalAgentHookTimeoutSeconds(timeout_value) orelse return null;
        timeout = .{ .field_name = "timeoutSec", .seconds = seconds };
    }

    const command = try allocator.dupe(u8, command_value.string);
    errdefer allocator.free(command);

    var status_message: ?[]const u8 = null;
    errdefer if (status_message) |message| allocator.free(message);
    if (value.object.get("statusMessage")) |status| {
        status_message = try rewriteExternalAgentTerms(allocator, status.string);
    }

    return .{
        .command = command,
        .timeout = timeout,
        .status_message = status_message,
    };
}

fn externalAgentHookCommandKeysSupported(object: std.json.ObjectMap) bool {
    var iterator = object.iterator();
    while (iterator.next()) |entry| {
        if (std.mem.eql(u8, entry.key_ptr.*, "type")) continue;
        if (std.mem.eql(u8, entry.key_ptr.*, "command")) continue;
        if (std.mem.eql(u8, entry.key_ptr.*, "timeout")) continue;
        if (std.mem.eql(u8, entry.key_ptr.*, "timeoutSec")) continue;
        if (std.mem.eql(u8, entry.key_ptr.*, "async")) continue;
        if (std.mem.eql(u8, entry.key_ptr.*, "statusMessage")) continue;
        return false;
    }
    return true;
}

fn externalAgentHookTimeoutSeconds(value: std.json.Value) ?u64 {
    return switch (value) {
        .integer => |integer| if (integer >= 0) @intCast(integer) else null,
        .number_string => |number| std.fmt.parseUnsigned(u64, number, 10) catch null,
        else => null,
    };
}

fn renderExternalAgentHooksJson(allocator: std.mem.Allocator, plan: ExternalAgentHookPlan) ![]const u8 {
    var result = std.ArrayList(u8).empty;
    errdefer result.deinit(allocator);
    try result.appendSlice(allocator, "{\"hooks\":{");
    var first_event = true;
    for (EXTERNAL_AGENT_HOOK_EVENTS) |event_name| {
        var has_event = false;
        for (plan.groups.items) |group| {
            if (std.mem.eql(u8, group.event_name, event_name)) {
                has_event = true;
                break;
            }
        }
        if (!has_event) continue;

        if (!first_event) try result.appendSlice(allocator, ",");
        first_event = false;
        try appendJsonString(allocator, &result, event_name);
        try result.appendSlice(allocator, ":[");
        var first_group = true;
        for (plan.groups.items) |group| {
            if (!std.mem.eql(u8, group.event_name, event_name)) continue;
            if (!first_group) try result.appendSlice(allocator, ",");
            first_group = false;
            try appendExternalAgentHookGroupJson(allocator, &result, group);
        }
        try result.appendSlice(allocator, "]");
    }
    try result.appendSlice(allocator, "}}");
    return result.toOwnedSlice(allocator);
}

fn appendExternalAgentHookGroupJson(allocator: std.mem.Allocator, result: *std.ArrayList(u8), group: ExternalAgentHookGroup) !void {
    var first = true;
    try result.appendSlice(allocator, "{");
    if (group.matcher) |matcher| try appendJsonStringField(allocator, result, &first, "matcher", matcher);
    try appendJsonFieldName(allocator, result, &first, "hooks");
    try result.appendSlice(allocator, "[");
    for (group.commands.items, 0..) |hook, index| {
        if (index != 0) try result.appendSlice(allocator, ",");
        try appendExternalAgentHookCommandJson(allocator, result, hook);
    }
    try result.appendSlice(allocator, "]}");
}

fn appendExternalAgentHookCommandJson(allocator: std.mem.Allocator, result: *std.ArrayList(u8), hook: ExternalAgentHookCommand) !void {
    var first = true;
    try result.appendSlice(allocator, "{");
    try appendJsonStringField(allocator, result, &first, "type", "command");
    try appendJsonStringField(allocator, result, &first, "command", hook.command);
    if (hook.timeout) |timeout| try appendJsonU64Field(allocator, result, &first, timeout.field_name, timeout.seconds);
    if (hook.status_message) |status_message| try appendJsonStringField(allocator, result, &first, "statusMessage", status_message);
    try result.appendSlice(allocator, "}");
}

fn copyExternalAgentHookScripts(allocator: std.mem.Allocator, source_external_agent_dir: []const u8, target_hooks: []const u8) !void {
    const target_parent = std.fs.path.dirname(target_hooks) orelse return;
    const source_hooks = try std.fs.path.join(allocator, &.{ source_external_agent_dir, "hooks" });
    defer allocator.free(source_hooks);
    const target_hooks_dir = try std.fs.path.join(allocator, &.{ target_parent, "hooks" });
    defer allocator.free(target_hooks_dir);
    try copyExternalAgentHookScriptsRecursive(allocator, source_hooks, target_hooks_dir);
}

fn copyExternalAgentHookScriptsRecursive(allocator: std.mem.Allocator, source_root: []const u8, target_root: []const u8) !void {
    const io = std.Io.Threaded.global_single_threaded.io();
    var source_dir = std.Io.Dir.openDirAbsolute(io, source_root, .{ .iterate = true }) catch |err| switch (err) {
        error.FileNotFound => return,
        error.NotDir => return,
        else => return err,
    };
    defer source_dir.close(io);

    try std.Io.Dir.cwd().createDirPath(io, target_root);
    var iter = source_dir.iterate();
    while (try iter.next(io)) |entry| {
        const source_path = try std.fs.path.join(allocator, &.{ source_root, entry.name });
        defer allocator.free(source_path);
        const target_path = try std.fs.path.join(allocator, &.{ target_root, entry.name });
        defer allocator.free(target_path);

        if (entry.kind == .directory) {
            try copyExternalAgentHookScriptsRecursive(allocator, source_path, target_path);
        } else if (entry.kind == .file) {
            if (try externalAgentPathExists(allocator, target_path)) continue;
            try ensureParentDir(io, target_path);
            try std.Io.Dir.copyFileAbsolute(source_path, target_path, io, .{});
        }
    }
}

fn externalAgentHomeAgentsMdNeedsMigration(allocator: std.mem.Allocator, codex_home: []const u8) !bool {
    const source_path = try externalAgentHomeAgentsMdPath(allocator);
