fn importExternalAgentSkillsAt(allocator: std.mem.Allocator, source_skills: []const u8, target_skills: []const u8) !void {
    const io = std.Io.Threaded.global_single_threaded.io();
    var source_dir = std.Io.Dir.openDirAbsolute(io, source_skills, .{ .iterate = true }) catch |err| switch (err) {
        error.FileNotFound => return,
        error.NotDir => return,
        else => return err,
    };
    defer source_dir.close(io);

    try std.Io.Dir.cwd().createDirPath(io, target_skills);
    var iter = source_dir.iterate();
    while (try iter.next(io)) |entry| {
        if (entry.kind != .directory) continue;

        const source_path = try std.fs.path.join(allocator, &.{ source_skills, entry.name });
        defer allocator.free(source_path);
        const target_path = try std.fs.path.join(allocator, &.{ target_skills, entry.name });
        defer allocator.free(target_path);
        if (try dirExists(io, target_path)) continue;

        try copyExternalAgentSkillDirRecursive(allocator, source_path, target_path);
    }
}

fn externalAgentSkillsHaveMissingSubdirectories(allocator: std.mem.Allocator, source_skills: []const u8, target_skills: []const u8) !bool {
    const io = std.Io.Threaded.global_single_threaded.io();
    var source_dir = std.Io.Dir.openDirAbsolute(io, source_skills, .{ .iterate = true }) catch |err| switch (err) {
        error.FileNotFound => return false,
        error.NotDir => return false,
        else => return err,
    };
    defer source_dir.close(io);

    var iter = source_dir.iterate();
    while (try iter.next(io)) |entry| {
        if (entry.kind != .directory) continue;
        const target_path = try std.fs.path.join(allocator, &.{ target_skills, entry.name });
        defer allocator.free(target_path);
        if (!try dirExists(io, target_path)) return true;
    }
    return false;
}

const ExternalAgentCommandSource = struct {
    source_path: []const u8,
    name: []const u8,

    fn deinit(self: ExternalAgentCommandSource, allocator: std.mem.Allocator) void {
        allocator.free(self.source_path);
        allocator.free(self.name);
    }
};

fn deinitExternalAgentCommandSources(allocator: std.mem.Allocator, sources: *std.ArrayList(ExternalAgentCommandSource)) void {
    for (sources.items) |source| source.deinit(allocator);
    sources.deinit(allocator);
}

fn deinitExternalAgentNamedItems(allocator: std.mem.Allocator, names: *std.ArrayList([]const u8)) void {
    for (names.items) |name| allocator.free(name);
    names.deinit(allocator);
}

fn missingExternalAgentCommandNames(allocator: std.mem.Allocator, source_commands: []const u8, target_skills: []const u8) !std.ArrayList([]const u8) {
    var sources = try uniqueSupportedExternalAgentCommandSources(allocator, source_commands);
    defer deinitExternalAgentCommandSources(allocator, &sources);

    var names = std.ArrayList([]const u8).empty;
    errdefer deinitExternalAgentNamedItems(allocator, &names);
    for (sources.items) |source| {
        const target = try std.fs.path.join(allocator, &.{ target_skills, source.name });
        defer allocator.free(target);
        if (try externalAgentPathExists(allocator, target)) continue;
        try names.append(allocator, try allocator.dupe(u8, source.name));
    }
    return names;
}

fn importExternalAgentCommandsAt(allocator: std.mem.Allocator, source_commands: []const u8, target_skills: []const u8) !void {
    var sources = try uniqueSupportedExternalAgentCommandSources(allocator, source_commands);
    defer deinitExternalAgentCommandSources(allocator, &sources);
    if (sources.items.len == 0) return;

    const io = std.Io.Threaded.global_single_threaded.io();
    try std.Io.Dir.cwd().createDirPath(io, target_skills);
    for (sources.items) |source| {
        const target_dir = try std.fs.path.join(allocator, &.{ target_skills, source.name });
        defer allocator.free(target_dir);
        if (try externalAgentPathExists(allocator, target_dir)) continue;

        const bytes = try readTextFile(allocator, source.source_path);
        defer allocator.free(bytes);
        const document = parseExternalAgentCommandDocument(bytes);
        const description = document.description orelse continue;
        const source_name = try externalAgentCommandSourceName(allocator, source_commands, source.source_path);
        defer allocator.free(source_name);
        const rendered = try renderExternalAgentCommandSkill(allocator, document.body, source.name, description, source_name);
        defer allocator.free(rendered);
        const target_file = try std.fs.path.join(allocator, &.{ target_dir, "SKILL.md" });
        defer allocator.free(target_file);
        try writeTextFile(target_file, rendered);
    }
}

fn uniqueSupportedExternalAgentCommandSources(allocator: std.mem.Allocator, source_commands: []const u8) !std.ArrayList(ExternalAgentCommandSource) {
    var files = std.ArrayList([]const u8).empty;
    defer {
        for (files.items) |file| allocator.free(file);
        files.deinit(allocator);
    }
    try collectExternalAgentCommandMarkdownFiles(allocator, source_commands, &files);
    std.mem.sort([]const u8, files.items, {}, stringLessThan);

    var candidates = std.ArrayList(ExternalAgentCommandSource).empty;
    errdefer deinitExternalAgentCommandSources(allocator, &candidates);
    for (files.items) |file| {
        const name = try externalAgentCommandSkillNameIfSupported(allocator, source_commands, file) orelse continue;
        errdefer allocator.free(name);
        const source_path = try allocator.dupe(u8, file);
        errdefer allocator.free(source_path);
        try candidates.append(allocator, .{
            .source_path = source_path,
            .name = name,
        });
    }

    var unique = std.ArrayList(ExternalAgentCommandSource).empty;
    errdefer deinitExternalAgentCommandSources(allocator, &unique);
    for (candidates.items, 0..) |candidate, index| {
        var duplicate = false;
        for (candidates.items, 0..) |other, other_index| {
            if (index != other_index and std.mem.eql(u8, candidate.name, other.name)) {
                duplicate = true;
                break;
            }
        }
        if (!duplicate) {
            const source_path = try allocator.dupe(u8, candidate.source_path);
            errdefer allocator.free(source_path);
            const name = try allocator.dupe(u8, candidate.name);
            errdefer allocator.free(name);
            try unique.append(allocator, .{
                .source_path = source_path,
                .name = name,
            });
        }
    }
    deinitExternalAgentCommandSources(allocator, &candidates);
    return unique;
}

fn collectExternalAgentCommandMarkdownFiles(allocator: std.mem.Allocator, dir_path: []const u8, files: *std.ArrayList([]const u8)) !void {
    const io = std.Io.Threaded.global_single_threaded.io();
    var dir = std.Io.Dir.openDirAbsolute(io, dir_path, .{ .iterate = true }) catch |err| switch (err) {
        error.FileNotFound => return,
        error.NotDir => return,
        else => return err,
    };
    defer dir.close(io);

    var iter = dir.iterate();
    while (try iter.next(io)) |entry| {
        const path = try std.fs.path.join(allocator, &.{ dir_path, entry.name });
        if (entry.kind == .directory) {
            defer allocator.free(path);
            try collectExternalAgentCommandMarkdownFiles(allocator, path, files);
        } else if (entry.kind == .file and std.mem.eql(u8, std.fs.path.extension(entry.name), ".md")) {
            errdefer allocator.free(path);
            try files.append(allocator, path);
        } else {
            allocator.free(path);
        }
    }
}

const ExternalAgentCommandDocument = struct {
    description: ?[]const u8,
    body: []const u8,
};

fn externalAgentCommandSkillNameIfSupported(allocator: std.mem.Allocator, source_commands: []const u8, source_file: []const u8) !?[]const u8 {
    if (std.mem.eql(u8, std.fs.path.stem(source_file), "README")) return null;
    const bytes = try readTextFile(allocator, source_file);
    defer allocator.free(bytes);
    const document = parseExternalAgentCommandDocument(bytes);
    const description = document.description orelse return null;
    if (std.mem.trim(u8, description, " \t\r\n").len == 0) return null;
    const description_len = std.unicode.utf8CountCodepoints(description) catch description.len;
    if (description_len > 1024) return null;
    if (hasUnsupportedExternalAgentCommandTemplateFeatures(document.body)) return null;

    const source_name = try externalAgentCommandSourceName(allocator, source_commands, source_file);
    defer allocator.free(source_name);
    const skill_name = try externalAgentCommandSkillName(allocator, source_name);
    errdefer allocator.free(skill_name);
    const skill_name_len = std.unicode.utf8CountCodepoints(skill_name) catch skill_name.len;
    if (skill_name_len > 64) {
        allocator.free(skill_name);
        return null;
    }
    return skill_name;
}

fn parseExternalAgentCommandDocument(bytes: []const u8) ExternalAgentCommandDocument {
    var description: ?[]const u8 = null;
    var body = bytes;
    var found_end = false;
    var lines = std.mem.splitScalar(u8, bytes, '\n');
    const first = lines.next() orelse return .{ .description = null, .body = bytes };
    if (!std.mem.eql(u8, std.mem.trim(u8, first, " \t\r"), "---")) {
        return .{ .description = null, .body = bytes };
    }

    var cursor: usize = first.len;
    if (cursor < bytes.len and bytes[cursor] == '\n') cursor += 1;
    while (lines.next()) |raw_line| {
        cursor += raw_line.len;
        if (cursor < bytes.len and bytes[cursor] == '\n') cursor += 1;
        const line = std.mem.trim(u8, raw_line, " \t\r");
        if (std.mem.eql(u8, line, "---")) {
            body = bytes[cursor..];
            found_end = true;
            break;
        }
        const colon = std.mem.indexOfScalar(u8, line, ':') orelse continue;
        const key = std.mem.trim(u8, line[0..colon], " \t");
        if (std.mem.eql(u8, key, "description")) {
            description = trimExternalAgentFrontmatterValue(line[colon + 1 ..]);
        }
    }
    if (!found_end) return .{ .description = null, .body = bytes };
    return .{ .description = description, .body = body };
}

fn trimExternalAgentFrontmatterValue(raw: []const u8) []const u8 {
    var value = std.mem.trim(u8, raw, " \t\r");
    if (value.len >= 2 and value[0] == value[value.len - 1] and (value[0] == '"' or value[0] == '\'')) {
        value = value[1 .. value.len - 1];
    }
    return value;
}

fn externalAgentCommandSourceName(allocator: std.mem.Allocator, source_commands: []const u8, source_file: []const u8) ![]const u8 {
    var relative = source_file;
    if (std.mem.startsWith(u8, source_file, source_commands)) {
        relative = source_file[source_commands.len..];
        while (relative.len > 0 and (relative[0] == '/' or relative[0] == std.fs.path.sep)) {
            relative = relative[1..];
        }
    }
    const extension = std.fs.path.extension(relative);
    const without_extension = if (extension.len > 0) relative[0 .. relative.len - extension.len] else relative;
    var result = std.ArrayList(u8).empty;
    errdefer result.deinit(allocator);
    var parts = std.mem.splitScalar(u8, without_extension, std.fs.path.sep);
    while (parts.next()) |part| {
        if (part.len == 0) continue;
        if (result.items.len != 0) try result.append(allocator, '-');
        try result.appendSlice(allocator, part);
    }
    return result.toOwnedSlice(allocator);
}

fn externalAgentCommandSkillName(allocator: std.mem.Allocator, source_name: []const u8) ![]const u8 {
    const raw = try std.fmt.allocPrint(allocator, "source-command-{s}", .{source_name});
    defer allocator.free(raw);
    return slugifyExternalAgentName(allocator, raw);
}

fn slugifyExternalAgentName(allocator: std.mem.Allocator, value: []const u8) ![]const u8 {
    var slug = std.ArrayList(u8).empty;
    defer slug.deinit(allocator);
    var last_was_dash = false;
    for (value) |byte| {
        if (std.ascii.isAlphanumeric(byte)) {
            try slug.append(allocator, std.ascii.toLower(byte));
            last_was_dash = false;
        } else if (!last_was_dash) {
            try slug.append(allocator, '-');
            last_was_dash = true;
        }
    }
    const trimmed = std.mem.trim(u8, slug.items, "-");
    if (trimmed.len == 0) return allocator.dupe(u8, "migrated");
    return allocator.dupe(u8, trimmed);
}

fn hasUnsupportedExternalAgentCommandTemplateFeatures(template: []const u8) bool {
    if (std.mem.indexOf(u8, template, "$ARGUMENTS") != null) return true;
    if (std.mem.indexOf(u8, template, "{{") != null and std.mem.indexOf(u8, template, "}}") != null) return true;
    if (std.mem.indexOf(u8, template, "!`") != null) return true;
    if (std.mem.indexOf(u8, template, "! `") != null) return true;
    if (containsExternalAgentNumberedArgumentPlaceholder(template)) return true;

    var tokens = std.mem.tokenizeAny(u8, template, " \t\r\n");
    while (tokens.next()) |token| {
        if (token.len > 1 and token[0] == '@') return true;
    }
    return false;
}

fn containsExternalAgentNumberedArgumentPlaceholder(template: []const u8) bool {
    if (template.len < 2) return false;
    var index: usize = 0;
    while (index + 1 < template.len) : (index += 1) {
        if (template[index] == '$' and std.ascii.isDigit(template[index + 1])) return true;
    }
    return false;
}

fn renderExternalAgentCommandSkill(
    allocator: std.mem.Allocator,
    body: []const u8,
    name: []const u8,
    description: []const u8,
    source_name: []const u8,
) ![]const u8 {
    const rewritten_description = try rewriteExternalAgentTerms(allocator, description);
    defer allocator.free(rewritten_description);
    const body_trimmed = std.mem.trim(u8, body, " \t\r\n");
    const body_source = if (body_trimmed.len == 0) "No command template body was found." else body_trimmed;
    const rewritten_body = try rewriteExternalAgentTerms(allocator, body_source);
    defer allocator.free(rewritten_body);
    const name_yaml = try externalAgentYamlString(allocator, name);
    defer allocator.free(name_yaml);
    const description_yaml = try externalAgentYamlString(allocator, rewritten_description);
    defer allocator.free(description_yaml);

    return std.fmt.allocPrint(
        allocator,
        "---\nname: {s}\ndescription: {s}\n---\n\n# {s}\n\nUse this skill when the user asks to run the migrated source command `{s}`.\n\n## Command Template\n\n{s}\n",
        .{ name_yaml, description_yaml, name, source_name, rewritten_body },
    );
}

fn externalAgentYamlString(allocator: std.mem.Allocator, value: []const u8) ![]const u8 {
    var output = std.ArrayList(u8).empty;
    errdefer output.deinit(allocator);
    try output.append(allocator, '"');
    for (value) |byte| {
        switch (byte) {
            '"' => try output.appendSlice(allocator, "\\\""),
            '\\' => try output.appendSlice(allocator, "\\\\"),
            '\n' => try output.appendSlice(allocator, "\\n"),
            '\r' => try output.appendSlice(allocator, "\\r"),
            '\t' => try output.appendSlice(allocator, "\\t"),
            else => try output.append(allocator, byte),
        }
    }
    try output.append(allocator, '"');
    return output.toOwnedSlice(allocator);
}

fn missingExternalAgentSubagentNames(allocator: std.mem.Allocator, source_agents: []const u8, target_agents: []const u8) !std.ArrayList([]const u8) {
    var files = std.ArrayList([]const u8).empty;
    defer deinitExternalAgentNamedItems(allocator, &files);
    try collectExternalAgentSubagentMarkdownFiles(allocator, source_agents, &files);

    var names = std.ArrayList([]const u8).empty;
    errdefer deinitExternalAgentNamedItems(allocator, &names);
    for (files.items) |file| {
        const target = try externalAgentSubagentTargetPath(allocator, file, target_agents);
        defer allocator.free(target);
        if (try externalAgentPathExists(allocator, target)) continue;

        const bytes = try readTextFile(allocator, file);
        defer allocator.free(bytes);
        const document = parseExternalAgentSubagentDocument(bytes) orelse continue;
        try names.append(allocator, try allocator.dupe(u8, document.name));
    }
    return names;
}

fn importExternalAgentSubagentsAt(allocator: std.mem.Allocator, source_agents: []const u8, target_agents: []const u8) !void {
    var files = std.ArrayList([]const u8).empty;
    defer deinitExternalAgentNamedItems(allocator, &files);
    try collectExternalAgentSubagentMarkdownFiles(allocator, source_agents, &files);
    if (files.items.len == 0) return;

    const io = std.Io.Threaded.global_single_threaded.io();
    try std.Io.Dir.cwd().createDirPath(io, target_agents);
    for (files.items) |file| {
        const target = try externalAgentSubagentTargetPath(allocator, file, target_agents);
        defer allocator.free(target);
        if (try externalAgentPathExists(allocator, target)) continue;

        const bytes = try readTextFile(allocator, file);
        defer allocator.free(bytes);
        const document = parseExternalAgentSubagentDocument(bytes) orelse continue;
        const rendered = try renderExternalAgentSubagentToml(allocator, document);
        defer allocator.free(rendered);
        try writeTextFile(target, rendered);
    }
}

fn collectExternalAgentSubagentMarkdownFiles(allocator: std.mem.Allocator, source_agents: []const u8, files: *std.ArrayList([]const u8)) !void {
    const io = std.Io.Threaded.global_single_threaded.io();
    var dir = std.Io.Dir.openDirAbsolute(io, source_agents, .{ .iterate = true }) catch |err| switch (err) {
        error.FileNotFound => return,
        error.NotDir => return,
        else => return err,
    };
    defer dir.close(io);

    var iter = dir.iterate();
    while (try iter.next(io)) |entry| {
        if (entry.kind != .file) continue;
        if (!std.mem.eql(u8, std.fs.path.extension(entry.name), ".md")) continue;
        if (std.mem.eql(u8, std.fs.path.stem(entry.name), "README")) continue;
        const path = try std.fs.path.join(allocator, &.{ source_agents, entry.name });
        errdefer allocator.free(path);
        try files.append(allocator, path);
    }
    std.mem.sort([]const u8, files.items, {}, stringLessThan);
}

fn externalAgentSubagentTargetPath(allocator: std.mem.Allocator, source_file: []const u8, target_agents: []const u8) ![]const u8 {
    const file_name = std.fs.path.basename(source_file);
    const stem = std.fs.path.stem(file_name);
    if (stem.len == 0) return error.InvalidExternalAgentSubagentPath;
    const target_name = try std.fmt.allocPrint(allocator, "{s}.toml", .{stem});
    defer allocator.free(target_name);
    return std.fs.path.join(allocator, &.{ target_agents, target_name });
}

const ExternalAgentSubagentDocument = struct {
    name: []const u8,
    description: []const u8,
    permission_mode: ?[]const u8,
    effort: ?[]const u8,
    body: []const u8,
};

fn parseExternalAgentSubagentDocument(bytes: []const u8) ?ExternalAgentSubagentDocument {
    var name: ?[]const u8 = null;
    var description: ?[]const u8 = null;
    var permission_mode: ?[]const u8 = null;
    var effort: ?[]const u8 = null;
    var body = bytes;
    var found_end = false;
    var lines = std.mem.splitScalar(u8, bytes, '\n');
    const first = lines.next() orelse return null;
    if (!std.mem.eql(u8, std.mem.trim(u8, first, " \t\r"), "---")) return null;

    var cursor: usize = first.len;
    if (cursor < bytes.len and bytes[cursor] == '\n') cursor += 1;
    while (lines.next()) |raw_line| {
        cursor += raw_line.len;
        if (cursor < bytes.len and bytes[cursor] == '\n') cursor += 1;
        const line = std.mem.trim(u8, raw_line, " \t\r");
        if (std.mem.eql(u8, line, "---")) {
            body = bytes[cursor..];
            found_end = true;
            break;
        }
        const colon = std.mem.indexOfScalar(u8, line, ':') orelse continue;
        const key = std.mem.trim(u8, line[0..colon], " \t");
        const value = trimExternalAgentFrontmatterValue(line[colon + 1 ..]);
        if (std.mem.eql(u8, key, "name")) {
            name = value;
        } else if (std.mem.eql(u8, key, "description")) {
            description = value;
        } else if (std.mem.eql(u8, key, "permissionMode")) {
            permission_mode = value;
        } else if (std.mem.eql(u8, key, "effort")) {
            effort = value;
        }
    }
    if (!found_end) return null;
    const trimmed_body = std.mem.trim(u8, body, " \t\r\n");
    if (trimmed_body.len == 0) return null;
    const parsed_name = name orelse return null;
    if (std.mem.trim(u8, parsed_name, " \t\r\n").len == 0) return null;
    const parsed_description = description orelse return null;
    if (std.mem.trim(u8, parsed_description, " \t\r\n").len == 0) return null;
    return .{
        .name = parsed_name,
        .description = parsed_description,
        .permission_mode = permission_mode,
        .effort = effort,
        .body = body,
    };
}

fn renderExternalAgentSubagentToml(allocator: std.mem.Allocator, document: ExternalAgentSubagentDocument) ![]const u8 {
    var output = std.ArrayList(u8).empty;
    errdefer output.deinit(allocator);

    try output.appendSlice(allocator, "name = ");
    const name_toml = try externalAgentYamlString(allocator, document.name);
    defer allocator.free(name_toml);
    try output.appendSlice(allocator, name_toml);
    try output.appendSlice(allocator, "\n");

    const rewritten_description = try rewriteExternalAgentTerms(allocator, document.description);
    defer allocator.free(rewritten_description);
    const description_toml = try externalAgentYamlString(allocator, rewritten_description);
    defer allocator.free(description_toml);
    try output.appendSlice(allocator, "description = ");
    try output.appendSlice(allocator, description_toml);
    try output.appendSlice(allocator, "\n");

    if (document.effort) |effort| {
        if (mapExternalAgentSubagentReasoningEffort(effort)) |mapped| {
            const effort_toml = try externalAgentYamlString(allocator, mapped);
            defer allocator.free(effort_toml);
            try output.appendSlice(allocator, "model_reasoning_effort = ");
            try output.appendSlice(allocator, effort_toml);
            try output.appendSlice(allocator, "\n");
        }
    }
    if (document.permission_mode) |permission_mode| {
        if (mapExternalAgentSubagentPermissionMode(permission_mode)) |sandbox_mode| {
            const sandbox_toml = try externalAgentYamlString(allocator, sandbox_mode);
            defer allocator.free(sandbox_toml);
            try output.appendSlice(allocator, "sandbox_mode = ");
            try output.appendSlice(allocator, sandbox_toml);
            try output.appendSlice(allocator, "\n");
        }
    }

    const body_trimmed = std.mem.trim(u8, document.body, " \t\r\n");
    const rewritten_body = try rewriteExternalAgentTerms(allocator, body_trimmed);
    defer allocator.free(rewritten_body);
    try output.appendSlice(allocator, "developer_instructions = \"\"\"\n");
    try appendExternalAgentMultilineTomlStringContent(allocator, &output, rewritten_body);
    try output.appendSlice(allocator, "\"\"\"\n");
    return output.toOwnedSlice(allocator);
}

fn mapExternalAgentSubagentReasoningEffort(effort: []const u8) ?[]const u8 {
    const mapped = if (std.mem.eql(u8, effort, "max")) "xhigh" else effort;
    if (std.mem.eql(u8, mapped, "none") or
        std.mem.eql(u8, mapped, "minimal") or
        std.mem.eql(u8, mapped, "low") or
        std.mem.eql(u8, mapped, "medium") or
        std.mem.eql(u8, mapped, "high") or
        std.mem.eql(u8, mapped, "xhigh"))
    {
        return mapped;
    }
    return null;
}

fn mapExternalAgentSubagentPermissionMode(permission_mode: []const u8) ?[]const u8 {
    if (std.mem.eql(u8, permission_mode, "acceptEdits")) return "workspace-write";
    if (std.mem.eql(u8, permission_mode, "readOnly")) return "read-only";
    return null;
}

fn appendExternalAgentMultilineTomlStringContent(allocator: std.mem.Allocator, output: *std.ArrayList(u8), value: []const u8) !void {
    var index: usize = 0;
    while (index < value.len) : (index += 1) {
        const byte = value[index];
        if (byte == '\\') {
            try output.appendSlice(allocator, "\\\\");
        } else if (byte == '"' and index + 2 < value.len and value[index + 1] == '"' and value[index + 2] == '"') {
            try output.appendSlice(allocator, "\\\"\\\"\\\"");
            index += 2;
        } else {
            try output.append(allocator, byte);
        }
    }
}

fn copyExternalAgentSkillDirRecursive(allocator: std.mem.Allocator, source_root: []const u8, target_root: []const u8) !void {
    const io = std.Io.Threaded.global_single_threaded.io();
    try std.Io.Dir.cwd().createDirPath(io, target_root);

    var source_dir = try std.Io.Dir.openDirAbsolute(io, source_root, .{ .iterate = true });
    defer source_dir.close(io);

    var iter = source_dir.iterate();
    while (try iter.next(io)) |entry| {
        const source_path = try std.fs.path.join(allocator, &.{ source_root, entry.name });
        defer allocator.free(source_path);
        const target_path = try std.fs.path.join(allocator, &.{ target_root, entry.name });
        defer allocator.free(target_path);

        if (entry.kind == .directory) {
            try copyExternalAgentSkillDirRecursive(allocator, source_path, target_path);
        } else if (entry.kind == .file) {
            if (asciiRegionEqlIgnoreCase(entry.name, "SKILL.md")) {
                const source_contents = try readTextFile(allocator, source_path);
                defer allocator.free(source_contents);
                const rewritten = try rewriteExternalAgentTerms(allocator, source_contents);
                defer allocator.free(rewritten);
                try writeTextFile(target_path, rewritten);
            } else {
                try ensureParentDir(io, target_path);
                try std.Io.Dir.copyFileAbsolute(source_path, target_path, io, .{});
            }
        }
    }
}

fn externalAgentConfigPlanHasMissingValues(bytes: []const u8, plan: ExternalAgentHomeConfigPlan) bool {
    if (plan.sandbox_workspace_write and !tomlKeyPathHasAssignment(bytes, "sandbox_mode")) return true;
    if (plan.env.items.len > 0 and !tomlKeyPathHasAssignment(bytes, "shell_environment_policy.inherit")) return true;
    for (plan.env.items) |entry| {
        var key_path_buffer: [256]u8 = undefined;
        const key_path = std.fmt.bufPrint(&key_path_buffer, "shell_environment_policy.set.{s}", .{entry.key}) catch return true;
        if (!tomlKeyPathHasAssignment(bytes, key_path)) return true;
    }
    return false;
}

const ExternalAgentEnvEntry = struct {
    key: []const u8,
    value: []const u8,

    fn deinit(self: ExternalAgentEnvEntry, allocator: std.mem.Allocator) void {
        allocator.free(self.key);
        allocator.free(self.value);
    }
};

const ExternalAgentHomeConfigPlan = struct {
    sandbox_workspace_write: bool = false,
    env: std.ArrayList(ExternalAgentEnvEntry) = .empty,

    fn deinit(self: *ExternalAgentHomeConfigPlan, allocator: std.mem.Allocator) void {
        for (self.env.items) |entry| entry.deinit(allocator);
        self.env.deinit(allocator);
    }

    fn isEmpty(self: ExternalAgentHomeConfigPlan) bool {
        return !self.sandbox_workspace_write and self.env.items.len == 0;
    }
};

fn loadExternalAgentConfigPlan(allocator: std.mem.Allocator, settings_path: []const u8) !ExternalAgentHomeConfigPlan {
    const settings_dir = std.fs.path.dirname(settings_path) orelse return ExternalAgentHomeConfigPlan{};
    const local_settings_path = try std.fs.path.join(allocator, &.{ settings_dir, "settings.local.json" });
    defer allocator.free(local_settings_path);

    var settings = try readExternalAgentSettings(allocator, settings_path, false);
    defer if (settings) |*parsed| parsed.deinit();
    var local_settings = try readExternalAgentSettings(allocator, local_settings_path, true);
    defer if (local_settings) |*parsed| parsed.deinit();

    var plan = ExternalAgentHomeConfigPlan{};
    errdefer plan.deinit(allocator);
    try addExternalAgentSettingsToPlan(allocator, &plan, if (settings) |parsed| parsed.value else null);
    try addExternalAgentSettingsToPlan(allocator, &plan, if (local_settings) |parsed| parsed.value else null);
    std.mem.sort(ExternalAgentEnvEntry, plan.env.items, {}, externalAgentEnvEntryLessThan);
    return plan;
}

fn addExternalAgentSettingsToPlan(
    allocator: std.mem.Allocator,
    plan: *ExternalAgentHomeConfigPlan,
    settings_value: ?std.json.Value,
) !void {
    const settings = settings_value orelse return;
    if (settings != .object) return error.InvalidExternalAgentSettings;

    if (settings.object.get("sandbox")) |sandbox| {
        if (sandbox == .object) {
            if (sandbox.object.get("enabled")) |enabled| {
                if (enabled == .bool) plan.sandbox_workspace_write = enabled.bool;
            }
        }
    }

    if (settings.object.get("env")) |env_value| {
        if (env_value == .object) {
            var iterator = env_value.object.iterator();
            while (iterator.next()) |entry| {
                if (!isBareTomlKeySegment(entry.key_ptr.*)) continue;
                const env_string = try externalAgentEnvValueToString(allocator, entry.value_ptr.*) orelse {
                    removeExternalAgentEnvEntry(allocator, plan, entry.key_ptr.*);
                    continue;
                };
                errdefer allocator.free(env_string);
                try putExternalAgentEnvEntry(allocator, plan, entry.key_ptr.*, env_string);
            }
        }
    }
}

fn putExternalAgentEnvEntry(
    allocator: std.mem.Allocator,
    plan: *ExternalAgentHomeConfigPlan,
    key: []const u8,
    value: []const u8,
) !void {
    for (plan.env.items) |*entry| {
        if (std.mem.eql(u8, entry.key, key)) {
            allocator.free(entry.value);
            entry.value = value;
            return;
        }
    }
    const owned_key = try allocator.dupe(u8, key);
    errdefer allocator.free(owned_key);
    try plan.env.append(allocator, .{ .key = owned_key, .value = value });
}

fn removeExternalAgentEnvEntry(allocator: std.mem.Allocator, plan: *ExternalAgentHomeConfigPlan, key: []const u8) void {
    for (plan.env.items, 0..) |entry, index| {
        if (!std.mem.eql(u8, entry.key, key)) continue;
        entry.deinit(allocator);
        _ = plan.env.swapRemove(index);
        return;
    }
}

fn externalAgentEnvValueToString(allocator: std.mem.Allocator, value: std.json.Value) !?[]const u8 {
    return switch (value) {
        .string => |string| try allocator.dupe(u8, string),
        .bool => |boolean| try allocator.dupe(u8, if (boolean) "true" else "false"),
        .integer => |integer| try std.fmt.allocPrint(allocator, "{}", .{integer}),
        .float => |float| try std.fmt.allocPrint(allocator, "{d}", .{float}),
        .number_string => |number| try allocator.dupe(u8, number),
        .null, .array, .object => null,
    };
}

fn externalAgentEnvEntryLessThan(_: void, lhs: ExternalAgentEnvEntry, rhs: ExternalAgentEnvEntry) bool {
    return std.mem.lessThan(u8, lhs.key, rhs.key);
}

fn readExternalAgentSettings(
    allocator: std.mem.Allocator,
    path: []const u8,
    ignore_invalid: bool,
) !?std.json.Parsed(std.json.Value) {
    const bytes = std.Io.Dir.cwd().readFileAlloc(std.Io.Threaded.global_single_threaded.io(), path, allocator, .limited(1024 * 1024)) catch |err| switch (err) {
        error.FileNotFound => return null,
        else => return err,
    };
    defer allocator.free(bytes);
    return std.json.parseFromSlice(std.json.Value, allocator, bytes, .{}) catch |err| {
        if (ignore_invalid) return null;
        return err;
    };
}

