    const key = try std.fmt.allocPrint(allocator, "apps.{s}.tools.{s}.{s}", .{ app_name, tool_name, field });
    defer allocator.free(key);
    try appendConfigReadManagedOrigin(allocator, result, first, layer, key);
}

