    first: *bool,
    layer: ConfigReadManagedLayer,
) !void {
    try appendConfigReadLayerStart(allocator, result, first);
    try appendConfigReadManagedSource(allocator, result, layer.file_path);
    try result.appendSlice(allocator, ",\"version\":");
